-- Poems batch 309
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c688702a-1cc1-4b9c-b7a4-485fd6e65f2a','寄漳川隠士  其一','寇準','宋','宋诗','song-poetry','','[]','志高長說耻鳬趨，歲晏園林戀隠居。',64,'全唐诗/poet.song.4000.json','["志高長說耻鳬趨，歲晏園林戀隠居。", "陋巷自甘棲短褐，侯門終不曳長裾。", "夜吟雪屋冥搜句，春結煙蓑老釣漁。", "爲我紅塵偶爲吏，近來還寄絕交書。"]'),
('5e3a28c7-d63e-4945-8224-6761fa96eed8','寄漳川隠士  其二','寇準','宋','宋诗','song-poetry','','[]','慵趨大厦戀山薇，立志由來與世違。',64,'全唐诗/poet.song.4000.json','["慵趨大厦戀山薇，立志由來與世違。", "溪上有時逢靜釣，雪中長日掩閑扉。", "自知天爵高人爵，不愛朝衣換布衣。", "我逐浮名任飄泊，清泉難得共忘機。"]'),
('859249e6-5192-4e56-aef1-3f211858707c','題巴東寺','寇準','宋','宋诗','song-poetry','','[]','寺在啼猿外，門開古澗涯。',48,'全唐诗/poet.song.4000.json','["寺在啼猿外，門開古澗涯。", "山深微有徑，樹老半無枝。", "望遠雲長暝，談空日漸移。", "恐朝金馬去，還失白蓮期。"]'),
('6f36e746-7b98-4f0c-a5b6-42c40e0ecd7d','贈隠士','寇準','宋','宋诗','song-poetry','','[]','夫子住東野，經年不到城。',48,'全唐诗/poet.song.4000.json','["夫子住東野，經年不到城。", "愛吟無俗趣，貪靜得閑名。", "荒徑侵山影，虛堂出燕聲。", "我慚爲俗吏，泉石負幽情。"]'),
('1e062ed1-57f4-4619-9c98-ad2784d5fec6','南亭晨望寄唐知印','寇準','宋','宋诗','song-poetry','','[]','夢覺偶晨起，南軒還獨過。',48,'全唐诗/poet.song.4000.json','["夢覺偶晨起，南軒還獨過。", "曉光生遠樹，露氣冷疏荷。", "窗白遊塵少，風清靜興多。", "遥知江郡守，幽趣在煙波。"]'),
('e6c56e67-5886-4698-b312-801c7162bd46','殘月  其一','寇準','宋','宋诗','song-poetry','','[]','半夜沉清影，宵殘猶伴吟。',48,'全唐诗/poet.song.4000.json','["半夜沉清影，宵殘猶伴吟。", "已甘垂樹杪，由得掛天心。", "淡色迷蓬戶，餘光映宿禽。", "誰家傷早別，凝思共沉沉。"]'),
('632b2ee7-08e2-4d2d-95e7-72945f76f02e','殘月  其二','寇準','宋','宋诗','song-poetry','','[]','光隨春漏細，影共夕煙流。',24,'全唐诗/poet.song.4000.json','["光隨春漏細，影共夕煙流。", "若近明河沒，還疑墜玉鈎。"]'),
('8d4e86ad-636b-4d9f-bfd6-da29c8d4aac3','巴東有感','寇準','宋','宋诗','song-poetry','','[]','長歲天涯悲斷梗，逢君無處不傷情。',32,'全唐诗/poet.song.4000.json','["長歲天涯悲斷梗，逢君無處不傷情。", "那堪日落紅樓伴，更聽蕭蕭杜宇聲。"]'),
('7695dd3a-e351-4025-9abb-a63edd307e89','省夏書事','寇準','宋','宋诗','song-poetry','','[]','窗戶經初雨，風清野景饒。',48,'全唐诗/poet.song.4000.json','["窗戶經初雨，風清野景饒。", "閑庭猶戲蝶，高樹已鳴蜩。", "世態貧中覺，鄉思醉裏銷。", "縱吟還獨步，時復過溪橋。"]'),
('58f31534-ac9b-4209-ad4f-8199058e5ff8','和李逢同年水閣閑望','寇準','宋','宋诗','song-poetry','','[]','務簡凭危檻，凝然感物華。',48,'全唐诗/poet.song.4000.json','["務簡凭危檻，凝然感物華。", "孤村經野燒，極浦見漁家。", "灘急舟難渡，山高日易斜。", "明時如道在，焉復痛懷沙。"]'),
('e4667c44-c213-4219-b88a-94e3ada79b0c','塞上秋懷','寇準','宋','宋诗','song-poetry','','[]','未識窮邊苦，今遊信有之。',48,'全唐诗/poet.song.4000.json','["未識窮邊苦，今遊信有之。", "秋林殘照後，關路獨行時。", "磧迥風長急，天寒雁度遲。", "離心已無頼，更聽戍樓鼙。"]'),
('efe81f00-3155-4b46-b1ac-c3bee606d8d6','送人歸吳','寇準','宋','宋诗','song-poetry','','[]','忽憶湖山景，沿流興不窮。',48,'全唐诗/poet.song.4000.json','["忽憶湖山景，沿流興不窮。", "孤舟將去夜，絕塞已來鴻。", "白髮前期近，滄川舊業空。", "明時方道在，莫更學漁翁。"]'),
('bc23097e-66f8-4fb7-9e00-0b37a64be3c0','秋日','寇準','宋','宋诗','song-poetry','','[]','江天物候潛衰變，氣爽初疑夏景餘。',64,'全唐诗/poet.song.4000.json','["江天物候潛衰變，氣爽初疑夏景餘。", "雨漬亂苔侵古壁，風飄紅葉滿荒渠。", "晚雲連嶽幽藏寺，秋水澄江靜見魚。", "昔歲一鳴無所恨，綠槐金蕊任蕭疏。"]'),
('927d6501-3a6e-4e59-ba66-cbab87e9fd15','寄贈笠澤處士','寇準','宋','宋诗','song-poetry','','[]','笠澤漁人高節奇，白頭猶自著蓑衣。',64,'全唐诗/poet.song.4000.json','["笠澤漁人高節奇，白頭猶自著蓑衣。", "吟過竹院僧留宿，釣罷煙江鶴伴歸。", "花落砌邊春雨歇，酒醒林際夕陽微。", "中朝名士皆知己，多說東來信亦稀。"]'),
('afd7420c-737a-47d7-a8e6-bd620c2a6476','柳','寇準','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u67f3\u6811"]','曉带輕煙間杏花，晚凝深翠拂平沙。',32,'全唐诗/poet.song.4000.json','["曉带輕煙間杏花，晚凝深翠拂平沙。", "長條別有風流處，密映錢塘蘇小家。"]'),
('a3c46dc5-c0ba-4909-b6c1-bd0d59758214','喜吉上人至','寇準','宋','宋诗','song-poetry','','[]','鄴北至夔城，三千里外程。',48,'全唐诗/poet.song.4000.json','["鄴北至夔城，三千里外程。", "勞尋苦吟伴，獨入亂山行。", "楚水秋無際，巴猿夜有聲。", "逢師不能寐，因話故鄉情。"]'),
('d6135da0-3c0a-4962-8b87-2d961b00e891','早秋二絕  其一','寇準','宋','宋诗','song-poetry','','[]','年光苒苒暗推移，坐惜流年感舊期。',32,'全唐诗/poet.song.4000.json','["年光苒苒暗推移，坐惜流年感舊期。", "獨聽早蟬秋色裏，潘安初見二毛時。"]'),
('6f6e1eb1-0484-4514-9781-b39b1278597f','早秋二絕  其二','寇準','宋','宋诗','song-poetry','','[]','一聽早蟬響，坐悲芳歲闌。',24,'全唐诗/poet.song.4000.json','["一聽早蟬響，坐悲芳歲闌。", "新秋空索寞，前事但心酸。"]'),
('1f5e6083-784c-416f-878f-f06ddbe4e77e','秋日武關道中','寇準','宋','宋诗','song-poetry','','[]','行塵漠漠起西風，來往征軒似轉蓬。',32,'全唐诗/poet.song.4000.json','["行塵漠漠起西風，來往征軒似轉蓬。", "駐馬幾多愁思苦，亂蟬衰柳武關中。"]'),
('4c73e508-fa6e-438d-8649-330af77c9d4d','早春','寇準','宋','宋诗','song-poetry','','[]','日暖經冰泮，潛回律管春。',48,'全唐诗/poet.song.4000.json','["日暖經冰泮，潛回律管春。", "初驚柳色重，漸見草芽新。", "罇酒留歡少，雲溪入夢頻。", "惟應五侯地，行樂及芳辰。"]'),
('0414931e-9c27-4a95-b7ab-62d3a7ac601c','書山館壁','寇準','宋','宋诗','song-poetry','','[]','秋作西南使，千林覆去程。',48,'全唐诗/poet.song.4000.json','["秋作西南使，千林覆去程。", "四時無日影，終夜有猿聲。", "路入溪雲過，人穿鳥道行。", "不堪孤驛望，風雨動鄉情。"]'),
('6dd7c5c1-0cba-4d58-a484-24a19f0b993e','送趙主簿之任惠安','寇準','宋','宋诗','song-poetry','','[]','蕭蕭征騎立長亭，遥指天涯萬里程。',32,'全唐诗/poet.song.4000.json','["蕭蕭征騎立長亭，遥指天涯萬里程。", "尊酒欲闌人欲別，夕陽絲管盡離聲。"]'),
('6ae32b64-5881-4461-96df-1c181577b952','秋氣凜然庭木將墜道謙上人有南征之役賦詩祖行','寇準','宋','宋诗','song-poetry','','[]','洪府多佳致，師今欲此行。',48,'全唐诗/poet.song.4000.json','["洪府多佳致，師今欲此行。", "寒山連楚遠，白浪浸吳平。", "煙雨經秋迥，霜鴻入夜鳴。", "到時春未暮，閑聽鷓鴣聲。"]'),
('26d590ec-1cd1-47f5-89cf-9600184ed3c8','酒醒','寇準','宋','宋诗','song-poetry','','[]','勝遊歡宴是良圖，何必凄凄獨向隅。',32,'全唐诗/poet.song.4000.json','["勝遊歡宴是良圖，何必凄凄獨向隅。", "深院酒醒春日晚，只聞芳樹語提壺。"]'),
('0ebdc5e0-855d-425d-bcf5-b565a673faf5','南陽春日','寇準','宋','宋诗','song-poetry','','[]','水滿池塘花遶城，日斜南陌暖風輕。',32,'全唐诗/poet.song.4000.json','["水滿池塘花遶城，日斜南陌暖風輕。", "千門柳色春煙淡，獨倚高樓聞暮鶑。"]'),
('f1c1f664-433e-4c8a-921b-34e9a4bd1349','春日長安故苑有懷','寇準','宋','宋诗','song-poetry','','[]','唐室空城有舊基，荒凉長使後人悲。',64,'全唐诗/poet.song.4000.json','["唐室空城有舊基，荒凉長使後人悲。", "遥村日暖花空發，廢苑春深柳自垂。", "事著簡編猶可念，景隨陵谷更何疑。", "入梁朝士無多在，誰向秋風詠黍離。"]'),
('c2f69472-115e-4e0e-a650-63d50323c554','送人遊邊','寇準','宋','宋诗','song-poetry','','[]','遠行當歲暮，冰雪路難分。',24,'全唐诗/poet.song.4000.json','["遠行當歲暮，冰雪路難分。", "疋馬陽關外，邊聲落日聞。"]'),
('d2b72230-bc6a-413f-8389-81678f589e5f','惜花','寇準','宋','宋诗','song-poetry','','[]','深謝暖風傳馥郁，長憂夜雨暗摧殘。',32,'全唐诗/poet.song.4000.json','["深謝暖風傳馥郁，長憂夜雨暗摧殘。", "黄昏欲放笙歌散，更遶朱欄子細看。"]'),
('d7cb2c8e-8d5e-4ecd-9d8a-76f5c71ac713','微凉','寇準','宋','宋诗','song-poetry','','[]','高桐深密間幽篁，乳燕聲稀夏日長。',32,'全唐诗/poet.song.4000.json','["高桐深密間幽篁，乳燕聲稀夏日長。", "獨坐水亭風滿袖，世間清景是微凉。"]'),
('017d8054-3156-4628-88fc-eadf51ce1c92','帝城秋望','寇準','宋','宋诗','song-poetry','','[]','登臨秋向盡，千里見王畿。',48,'全唐诗/poet.song.4000.json','["登臨秋向盡，千里見王畿。", "過雨山逾翠，經霜菊漸稀。", "平原夕靄起，高樹宿禽歸。", "一望關河道，空令詠式微。"]'),
('330d02a5-6bc2-4e76-b5b5-f3ab322e2d74','禁中偶書所懷呈內翰同年同院二學士','寇準','宋','宋诗','song-poetry','','[]','朝回內省中，默坐對西風。',48,'全唐诗/poet.song.4000.json','["朝回內省中，默坐對西風。", "秋色澄寒沼，朝陽上古桐。", "龍墀慚近侍，魚浦憶疏篷。", "會待酬恩了，煙蓑伴釣翁。"]'),
('a8e689ba-5a3a-4871-9bfd-0106ae19c37d','新秋','寇準','宋','宋诗','song-poetry','','[]','孤吟遶桐砌，時節又西風。',48,'全唐诗/poet.song.4000.json','["孤吟遶桐砌，時節又西風。", "悵望新秋在，歡娛往事空。", "柳條微減翠，蓼穗已飄紅。", "正是多傷感，仍將別恨中。"]'),
('44b3f5cc-fe0c-4c44-aabc-ac92b48f8c1c','春晝','寇準','宋','宋诗','song-poetry','','[]','年長追遊興漸凋，況兼巴峽景蕭蕭。',32,'全唐诗/poet.song.4000.json','["年長追遊興漸凋，況兼巴峽景蕭蕭。", "閑齋爲謝楊花到，時拂殘書慰寂寥。"]'),
('c1cb8b1c-6c7e-46c2-a715-9c1f41c1ec9b','秋日晚晴池上作','寇準','宋','宋诗','song-poetry','','[]','雨歇南山積翠明，淡雲消盡遠天晴。',32,'全唐诗/poet.song.4000.json','["雨歇南山積翠明，淡雲消盡遠天晴。", "漪漣不動秋塘靜，獨拄寒筇遶岸行。"]'),
('31f4aa4c-6463-42e4-8569-6875c3e66c16','夏日','寇準','宋','宋诗','song-poetry','','[]','離心杳杳思遲遲，深院無人柳自垂。',32,'全唐诗/poet.song.4000.json','["離心杳杳思遲遲，深院無人柳自垂。", "日暮長廊聞燕語，輕寒微雨麥秋時。"]'),
('ff4ac766-080c-48eb-8a6a-9bd18fe40fc0','留題郡樓','寇準','宋','宋诗','song-poetry','','[]','千里關河一望間，登臨長到夕陽還。',32,'全唐诗/poet.song.4000.json','["千里關河一望間，登臨長到夕陽還。", "欲驅征旆歸朝去，更倚高樓看暮山。"]'),
('6869c1c9-bc0e-4d88-bf51-7f74f2eb8936','青州西樓雨中閑望','寇準','宋','宋诗','song-poetry','','[]','海上秋添寂寞情，萬家煙樹暝重城。',32,'全唐诗/poet.song.4000.json','["海上秋添寂寞情，萬家煙樹暝重城。", "蕭蕭細雨遥天暮，獨向空樓聞笛聲。"]'),
('a901f94b-1ffb-448c-90ef-35d37c93b02a','中書秋日有懷青社舊遊因書一首','寇準','宋','宋诗','song-poetry','','[]','掖垣秋色生鷄樹，忽憶青丘感舊情。',32,'全唐诗/poet.song.4000.json','["掖垣秋色生鷄樹，忽憶青丘感舊情。", "曾倚西樓吟暮雨，數峰寒碧遶高城。"]'),
('8a8340a1-6ffb-41e6-99ea-203a267fc93d','贈寶上人','寇準','宋','宋诗','song-poetry','','[]','重城蕭寺雖留滯，野鶴由來性本閑。',64,'全唐诗/poet.song.4000.json','["重城蕭寺雖留滯，野鶴由來性本閑。", "寒磬終宵鳴竹院，虛窗盡日對秋山。", "旋移怪石資吟賞，應有孤雲共往還。", "自笑紅塵成底事，幽期長是負松間。"]'),
('057a1cf7-eb85-4047-9bbd-b3217b1598d9','雨夜許氏第會宿各賦四韻','寇準','宋','宋诗','song-poetry','','[]','雨夜銷煩暑，林塘向夕幽。',48,'全唐诗/poet.song.4000.json','["雨夜銷煩暑，林塘向夕幽。", "庭虛惟欠月，樹冷欲生秋。", "河北嗟新別，罇前念舊遊。", "若非逢勝會，何以解離憂。"]'),
('8c8cd5f0-6681-4b53-be2d-b313441b69c5','水閣夜望書懷','寇準','宋','宋诗','song-poetry','','[]','水閣中宵動，寥寥起遠思。',48,'全唐诗/poet.song.4000.json','["水閣中宵動，寥寥起遠思。", "秋風生折葦，星彩動寒池。", "白社孤前約，青雲少舊知。", "苦吟空自歎，風雅道由衰。"]'),
('ab3a6781-70c5-4a1b-91cc-36a75d0e15a3','離京作','寇準','宋','宋诗','song-poetry','','[]','致君才業本無能，戀闕情懷老不勝。',32,'全唐诗/poet.song.4000.json','["致君才業本無能，戀闕情懷老不勝。", "欲過龍津重回首，朣朧初日上觚稜。"]'),
('31832ac9-5842-4926-9181-68fb063c8bf5','洛陽道中感懷','寇準','宋','宋诗','song-poetry','','[]','文陛初辭咫尺顔，恩深猶綴輔臣班。',32,'全唐诗/poet.song.4000.json','["文陛初辭咫尺顔，恩深猶綴輔臣班。", "漢庭舊友彫零盡，獨擁雙旌入武關。"]'),
('9e999003-6df1-47dd-b5f8-bed15de97e97','初到長安書懷','寇準','宋','宋诗','song-poetry','','[]','薦承丹詔撫彫殘，適值年豐萬井安。',64,'全唐诗/poet.song.4000.json','["薦承丹詔撫彫殘，適值年豐萬井安。", "舊職尚兼黄閣貴，前驅新擁碧油寒。", "靜憐風竹經宵聽，老愛山雲盡日看。", "魂夢不知關塞外，有時猶得到金鑾。"]'),
('7e2a56f2-c03f-46db-8124-8159e8d30421','遊花巖寺','寇準','宋','宋诗','song-poetry','','[]','寺對南山積翠濃，水村鷗鷺下遥空。',32,'全唐诗/poet.song.4000.json','["寺對南山積翠濃，水村鷗鷺下遥空。", "層樓望盡樊川景，恨不凭欄煙雨中。"]'),
('9f66d439-8178-4fad-8a92-c6f98164d6ba','和向相公見寄','寇準','宋','宋诗','song-poetry','','[]','玉殿登科四十年，當時交友盡英賢。',32,'全唐诗/poet.song.4000.json','["玉殿登科四十年，當時交友盡英賢。", "歲寒唯有君兼我，頭白猶持將相權。"]'),
('1a0f6de0-e517-44cd-8368-ca32b208b690','送轉運梅學士巡邊郡四首  其一','寇準','宋','宋诗','song-poetry','','[]','悵飲惜離羣，窮邊去路分。',24,'全唐诗/poet.song.4000.json','["悵飲惜離羣，窮邊去路分。", "雪深山館夜，孤雁背燈聞。"]'),
('ee99427c-a393-4f05-81cf-740a1a3a402a','送轉運梅學士巡邊郡四首  其二','寇準','宋','宋诗','song-poetry','','[]','絕塞程方遠，窮陰歲欲殘。',24,'全唐诗/poet.song.4000.json','["絕塞程方遠，窮陰歲欲殘。", "石城歸夢斷，隴月照人寒。"]'),
('6e8a695b-c98d-45d9-bc98-76bad7e5e348','送轉運梅學士巡邊郡四首  其三','寇準','宋','宋诗','song-poetry','','[]','水遠沉來信，山長疊去愁。',24,'全唐诗/poet.song.4000.json','["水遠沉來信，山長疊去愁。", "夜深關月白，休凭驛邊樓。"]'),
('fe017067-8b9b-4ffc-ac0f-67d4f1d07dd0','送轉運梅學士巡邊郡四首  其四','寇準','宋','宋诗','song-poetry','','[]','夙駕巡邊徼，歸程隔亂山。',24,'全唐诗/poet.song.4000.json','["夙駕巡邊徼，歸程隔亂山。", "長安花木麗，春苑待君還。"]'),
('9a8f7a3c-0c2e-4d4a-aec9-2579aa0867d1','春晝偶書','寇準','宋','宋诗','song-poetry','','[]','白晝偶成芳草夢，起來幽興有誰知。',32,'全唐诗/poet.song.4000.json','["白晝偶成芳草夢，起來幽興有誰知。", "風簾不動黄鸝語，坐見庭花日影移。"]'),
('097a518c-1772-4d82-b8fd-9f52b2d3e03c','秋夜懷歸','寇準','宋','宋诗','song-poetry','','[]','渭水苔磯阻舊遊，夢回空館却凝愁。',64,'全唐诗/poet.song.4000.json','["渭水苔磯阻舊遊，夢回空館却凝愁。", "一聲江笛巴雲暝，半夜山風楚樹秋。", "星落古池孤影動，燈摇疏壁冷光幽。", "遲明不寐空搔首，蹤跡何由得狎鷗。"]'),
('85bc80fe-8d72-4a06-afdf-b42d3f7efea3','憶洛陽','寇準','宋','宋诗','song-poetry','','[]','金谷春來柳自黄，曉煙晴日映宮牆。',32,'全唐诗/poet.song.4000.json','["金谷春來柳自黄，曉煙晴日映宮牆。", "不堪花下聽歌處，却向長安憶洛陽。"]'),
('d3b78396-84a9-457f-a72d-81ffd4a1468e','長安春望感懷','寇準','宋','宋诗','song-poetry','','[]','灞岸春波遠，秦川暮雨微。',24,'全唐诗/poet.song.4000.json','["灞岸春波遠，秦川暮雨微。", "凭高正愁絕，煙樹更斜暉。"]'),
('bea14122-fd2c-4797-8ba1-3355aeb2a5f6','春晝','寇準','宋','宋诗','song-poetry','','[]','午晝花陰靜，春風數蝶飛。',24,'全唐诗/poet.song.4000.json','["午晝花陰靜，春風數蝶飛。", "坐來生遠思，深院燕初歸。"]'),
('5f5d8de0-17ea-41ed-9fa2-ea49b95f0573','岐下秋書','寇準','宋','宋诗','song-poetry','','[]','碧樹微凉露氣清，感愁懷舊獨含情。',32,'全唐诗/poet.song.4000.json','["碧樹微凉露氣清，感愁懷舊獨含情。", "西樓月夜明如水，只欠桓伊一笛聲。"]'),
('09f34035-4028-4091-9b39-ef85ff96d594','憶岐下小池','寇準','宋','宋诗','song-poetry','','[]','長憶西園清夜景，酒闌無不獨臨池。',32,'全唐诗/poet.song.4000.json','["長憶西園清夜景，酒闌無不獨臨池。", "可憐隴月三更白，誰見紅蕖露滴時。"]'),
('645fa604-698e-455f-a587-e0283827550f','岐下西園秋日書事','寇準','宋','宋诗','song-poetry','','[]','務簡羣吏散，披襟幽興長。',48,'全唐诗/poet.song.4000.json','["務簡羣吏散，披襟幽興長。", "松篁經晚節，蘭菊有清香。", "水凈澄秋色，山高見夕陽。", "身閑心自泰，何必濯滄浪。"]'),
('d24292e3-643e-442c-adb0-1613b6ea9e09','秋懷','寇準','宋','宋诗','song-poetry','','[]','輕雲不動日微陰，高樹無風秋色深。',32,'全唐诗/poet.song.4000.json','["輕雲不動日微陰，高樹無風秋色深。", "獨聽暮蟬臨水坐，十年林壑阻歸心。"]'),
('69d7cf81-abe4-42fd-ae0b-432c41358c45','秋','寇準','宋','宋诗','song-poetry','','[]','自古名高衆毀歸，又應身退是知機。',32,'全唐诗/poet.song.4000.json','["自古名高衆毀歸，又應身退是知機。", "林風驚斷西窗夢，一夜愁聲憶翠微。"]'),
('39a32c5c-6e42-464c-a6e5-55f9e804e0ab','冬日北齋','寇準','宋','宋诗','song-poetry','','[]','寒風颯颯響庭槐，愛日明窗坐北齋。',32,'全唐诗/poet.song.4000.json','["寒風颯颯響庭槐，愛日明窗坐北齋。", "閑憶故山歸未得，舊遊時展認雲崖。"]'),
('96a26e81-bb9a-43c4-abc6-3d5f83e5ceae','秋齋','寇準','宋','宋诗','song-poetry','','[]','霽景有誰同遠望，秋懷無奈只悲歌。',32,'全唐诗/poet.song.4000.json','["霽景有誰同遠望，秋懷無奈只悲歌。", "雲收遠嶠凝嵐翠，雨歇空庭敗葉多。"]'),
('a439b506-a77c-4fba-813e-9c8fb0407fb8','洛陽有懷岐山舊遊','寇準','宋','宋诗','song-poetry','','[]','綠鬢年來已漸彫，舊遊芳草路迢迢。',64,'全唐诗/poet.song.4000.json','["綠鬢年來已漸彫，舊遊芳草路迢迢。", "山橫遠翠疑歌黛，柳拂輕梢認舞腰。", "秦甸夢回空有恨，洛城吟斷獨無憀。", "斜陽更上高樓望，始覺離情一倍饒。"]'),
('1f642879-8513-4545-9820-2080d600d903','憶岐下舊遊','寇準','宋','宋诗','song-poetry','','[]','二年岐下假諸侯，事簡民安選勝遊。',64,'全唐诗/poet.song.4000.json','["二年岐下假諸侯，事簡民安選勝遊。", "花寺水村時駐馬，暮天秋雪獨登樓。", "靜眠鈴閤聞羌笛，閑酌松醪引越甌。", "別後幾回空有恨，葉飛蟬噪動離愁。"]'),
('81be97fc-3f1c-4ec8-a8df-2ab35ae337cc','無題','寇準','宋','宋诗','song-poetry','','[]','金甲珠襦鎖繡扃，杜城殘月葬娥英。',32,'全唐诗/poet.song.4000.json','["金甲珠襦鎖繡扃，杜城殘月葬娥英。", "春風候館花如雪，空有鶑傳度曲聲。"]'),
('37112bc1-daf6-4182-8ec2-fc9a712adfaf','秋日登後樓','寇準','宋','宋诗','song-poetry','','[]','遠山重疊故關遥，公退乘閑上麗譙。',32,'全唐诗/poet.song.4000.json','["遠山重疊故關遥，公退乘閑上麗譙。", "今日登臨秋思苦，雨荷風葉共蕭蕭。"]'),
('13deeb10-a8b7-42be-9fbb-e467ce697d86','早春','寇準','宋','宋诗','song-poetry','','[]','星紀周天運，微陽氣候新。',48,'全唐诗/poet.song.4000.json','["星紀周天運，微陽氣候新。", "郊原初度臘，梅柳暗驚春。", "故國無書久，孤峰入夢頻。", "年加自多感，況復送歸人。"]'),
('0a01f19c-a008-45ed-a037-9cbddbbcf2bf','南陽夏日','寇準','宋','宋诗','song-poetry','','[]','綠楊陰密覆回廊，深院簾垂晝景長。',64,'全唐诗/poet.song.4000.json','["綠楊陰密覆回廊，深院簾垂晝景長。", "人靜獨聞幽鳥語，風來時有異花香。", "世間寵辱皆嘗遍，身外聲名豈足量。", "閑讀南華真味理，片心惟只許蒙莊。"]'),
('c0024905-61aa-47c7-8217-32a927efafd2','夏日有懷','寇準','宋','宋诗','song-poetry','','[]','庭樹陰陰夏景遲，閑房愁對暮簾垂。',32,'全唐诗/poet.song.4000.json','["庭樹陰陰夏景遲，閑房愁對暮簾垂。", "因思往歲陪天仗，正是瑶池賜宴時。"]'),
('0c0076a0-9d67-427d-8f7c-dbd4e3ea4e9e','途中作','寇準','宋','宋诗','song-poetry','','[]','秋末楚雲端，行侵苔蘚斑。',48,'全唐诗/poet.song.4000.json','["秋末楚雲端，行侵苔蘚斑。", "愁腸不厭酒，病眼豈逢山。", "遠路有時到，宦遊無處閑。", "却思清渭北，煙柳掩柴關。"]'),
('af33af86-b6e7-41a0-9816-d3956e84012f','喜吉上人至','寇準','宋','宋诗','song-poetry','','[]','喜師來訪我，幽會興何長。',48,'全唐诗/poet.song.4000.json','["喜師來訪我，幽會興何長。", "清論都無倦，鄉愁頓欲忘。", "疏林秋色暮，虛閣水風凉。", "久坐慵言別，微陽下短牆。"]'),
('bccea43e-d294-4975-aae1-692e8d171057','書黄山館壁','寇準','宋','宋诗','song-poetry','','[]','殘日住孤館，遲遲行古臺。',48,'全唐诗/poet.song.4000.json','["殘日住孤館，遲遲行古臺。", "大河連野去，白鳥背城來。", "離恨渾如結，鄉心漸欲灰。", "山花半寥落，猶在社前開。"]'),
('685b061a-5c87-4d01-a338-7053594581d3','巴東驛秋日晚望','寇準','宋','宋诗','song-poetry','','[]','楚驛獨閑望，山村秋暮天。',48,'全唐诗/poet.song.4000.json','["楚驛獨閑望，山村秋暮天。", "數峰橫夕照，一笛起江船。", "遣恨須言命，冥心漸學禪。", "遲遲未回首，深谷暗寒煙。"]'),
('3bd94eae-4f44-4b5c-9cbf-8626cf1dc2f4','掩卷','寇準','宋','宋诗','song-poetry','','[]','掩卷頻秋望，無人共展眉。',48,'全唐诗/poet.song.4000.json','["掩卷頻秋望，無人共展眉。", "殘陽留古樹，白鳥下寒池。", "簪組心還倦，風騷志未衰。", "登臨一長嘆，還失渭川期。"]'),
('2becb794-875b-43a5-a2d1-73e4ec951985','巴東書事','寇準','宋','宋诗','song-poetry','','[]','鄉思終日有，孤淡厭琴樽。',48,'全唐诗/poet.song.4000.json','["鄉思終日有，孤淡厭琴樽。", "衆木侵山徑，寒江逼縣門。", "浪沉灘見脊，雨過壁生痕。", "憔悴悲蘭蕙，因思楚屈原。"]'),
('7e6cdd63-fcd5-486c-bb17-557ab1f42083','池上秋書','寇準','宋','宋诗','song-poetry','','[]','虛齋獨語復書空，閑對林塘思少同。',64,'全唐诗/poet.song.4000.json','["虛齋獨語復書空，閑對林塘思少同。", "霜葉聲乾飄夕照，露荷香冷泣秋風。", "時平偶作青衫吏，心老渾如白髮翁。", "昨夜渭川歸好夢，一船煙雨打孤篷。"]'),
('2ea8272e-19ff-498a-b2ae-9a0bb105b7a7','書懷寄郝監軍','寇準','宋','宋诗','song-poetry','','[]','索居終日學忘機，深歎高堂養獨遲。',64,'全唐诗/poet.song.4000.json','["索居終日學忘機，深歎高堂養獨遲。", "自問江村紆墨綬，何當煙浦坐魚磯。", "夢迴渭水秦雲斷，望盡巴山蜀魄飛。", "好怪多才郝夫子，道孤俱未及輕肥。"]'),
('0785a1f1-8128-419a-9fac-b99faf9a2e7d','南平驛','寇準','宋','宋诗','song-poetry','','[]','心隨流水還鄉國，身向青山上屈盤。',32,'全唐诗/poet.song.4000.json','["心隨流水還鄉國，身向青山上屈盤。", "秋夢不成秋雨細，西風一夜客亭寒。"]'),
('7f0fe96a-b1a3-444c-a8cc-704b6ebf730f','悶書','寇準','宋','宋诗','song-poetry','','[]','秋憶故鄉魂欲斷，晚臨寒浦思如流。',32,'全唐诗/poet.song.4000.json','["秋憶故鄉魂欲斷，晚臨寒浦思如流。", "歸來古屋寒燈暗，能較騷人幾處愁。"]'),
('fa7000b7-3198-4701-b345-69f83f416269','秋寄江上吟僧','寇準','宋','宋诗','song-poetry','','[]','掛錫在荆楚，杜門無往還。',48,'全唐诗/poet.song.4000.json','["掛錫在荆楚，杜門無往還。", "潮聲到孤寺，月色遍前山。", "一雁驚幽思，西風慘病顔。", "何當重携手，高步白雲間。"]'),
('0d84c7fd-d4fd-4b21-8b9f-46fc8d03a0ab','江上晚望','寇準','宋','宋诗','song-poetry','','[]','寒鐘來極浦，古寺隔重巖。',24,'全唐诗/poet.song.4000.json','["寒鐘來極浦，古寺隔重巖。", "斜日搘頤坐，天涯落月帆。"]'),
('816e7cf1-2681-45f9-9e43-bf528139d4ad','金陵懷古','寇準','宋','宋诗','song-poetry','','[]','極目望吳甸，野煙凝亂流。',48,'全唐诗/poet.song.4000.json','["極目望吳甸，野煙凝亂流。", "夜來榆塞雁，叫斷石城秋。", "舊苑荒餘草，平川半古丘。", "遲遲獨迴首，落日一蟬幽。"]'),
('624ac6fa-5e2b-48d0-a6d9-af0c45c7720e','暮春感事','寇準','宋','宋诗','song-poetry','','[]','春至又春暮，閑心成古心。',48,'全唐诗/poet.song.4000.json','["春至又春暮，閑心成古心。", "花光隨雨薄，草色共煙深。", "粉蝶稀狂影，黄鸝送好音。", "餘芳留不得，還共夕陽沉。"]'),
('a954fbc7-efbc-494f-9474-1c5e1a702529','秋興','寇準','宋','宋诗','song-poetry','','[]','窮秋九月西風高，疏林木落聲蕭騷。',32,'全唐诗/poet.song.4000.json','["窮秋九月西風高，疏林木落聲蕭騷。", "出門長望無所適，唯見空江生暮濤。"]'),
('5aadaf0b-8896-46e7-8ef0-fc65b7e87a99','春日閑望有感','寇準','宋','宋诗','song-poetry','','[]','水鄉春氣變新正，風物光榮異帝城。',64,'全唐诗/poet.song.4000.json','["水鄉春氣變新正，風物光榮異帝城。", "閑步偶尋芳草色，空林獨聽野鶑聲。", "煙霞未得從幽興，吟賞潛悲減舊情。", "燕麥楊花自摇蕩，不知離客困南征。"]'),
('d217db73-7365-45f6-9d59-24329383aaf4','江上聞鷓鴣','寇準','宋','宋诗','song-poetry','','[]','水村煙樹與雲平，閑倚孤舟念遠行。',32,'全唐诗/poet.song.4000.json','["水村煙樹與雲平，閑倚孤舟念遠行。", "無奈鄉心倍寥落，殘陽中有鷓鴣聲。"]'),
('b1629626-794e-418e-b84c-62ec9821c20f','醉題','寇準','宋','宋诗','song-poetry','','[]','榴花滿甕撥寒醅，痛飲能令百恨開。',32,'全唐诗/poet.song.4000.json','["榴花滿甕撥寒醅，痛飲能令百恨開。", "大抵天真有高趣，騰騰須入醉鄉來。"]'),
('d740f75c-e5cd-4ad2-b7d6-17f458de3771','和趙監丞春江送別','寇準','宋','宋诗','song-poetry','','[]','孤舟東去水煙微，久客那堪更送歸。',32,'全唐诗/poet.song.4000.json','["孤舟東去水煙微，久客那堪更送歸。", "三月江頭春盡日，片帆輕絮共紛飛。"]'),
('2dfb38aa-aebd-4813-8655-33078ebd00f6','送李生二絕句  其一','寇準','宋','宋诗','song-poetry','','[]','愛君白髮無覊束，命駕常爲千里遊。',32,'全唐诗/poet.song.4000.json','["愛君白髮無覊束，命駕常爲千里遊。", "一夜春江又迴棹，當時風雨滿汀洲。"]'),
('b311b294-63f5-4a3b-9048-92c708fd2930','送李生二絕句  其二','寇準','宋','宋诗','song-poetry','','[]','晴色半和行色遠，江頭別來欲何之。',32,'全唐诗/poet.song.4000.json','["晴色半和行色遠，江頭別來欲何之。", "數盃酒盡又南去，正是落花春暮時。"]'),
('52052ab3-2c8d-46ca-8065-250f5e5b5ce2','與詩友會宿','寇準','宋','宋诗','song-poetry','','[]','此夕南軒宿，論詩萬慮忘。',48,'全唐诗/poet.song.4000.json','["此夕南軒宿，論詩萬慮忘。", "苦吟秋信近，寂坐漏聲長。", "室靜燈光暗，桐疏露氣凉。", "幽懷聊自遣，山色漸蒼蒼。"]'),
('e09e1001-5a5e-44dd-a8fe-7389d5375408','南冠亭秋晚閑望','寇準','宋','宋诗','song-poetry','','[]','南冠亭外淡江天，久客登臨更浩然。',64,'全唐诗/poet.song.4000.json','["南冠亭外淡江天，久客登臨更浩然。", "遠浦秋深翻白浪，孤山日暮起蒼煙。", "已嗟異國逢衰節，況復西風聽亂蟬。", "倦鳥知還雖有意，故林無奈隔秦川。"]'),
('dfbfcabc-b883-4fb5-937c-e0ed9db53200','峽中春感','寇準','宋','宋诗','song-poetry','','[]','二年窮峽外，不見帝城春。',48,'全唐诗/poet.song.4000.json','["二年窮峽外，不見帝城春。", "覽照知年老，逢花感恨頻。", "浮榮何足貴，幽別轉難伸。", "終憶歸清渭，林泉卜舊鄰。"]'),
('6cc3a894-bb6a-4686-90a9-03f2dda71fc8','東歸再經峽口','寇準','宋','宋诗','song-poetry','','[]','復命經三峽，波瀾極目愁。',48,'全唐诗/poet.song.4000.json','["復命經三峽，波瀾極目愁。", "片雲生斷壁，孤石礙中流。", "道路連巴塞，風煙接楚丘。", "重來登望處，因念昔年遊。"]'),
('c5186bc1-5dac-434b-9dcb-4f60b2852016','江上晚行','寇準','宋','宋诗','song-poetry','','[]','秦川不得却歸耕，奉詔年來在楚城。',64,'全唐诗/poet.song.4000.json','["秦川不得却歸耕，奉詔年來在楚城。", "孤寺殘鐘催夕照，汀洲疏葦送秋聲。", "西風獨起湖山思，久客應知寂寞情。", "野鶴漸無驚弋意，對人孤立水煙平。"]'),
('f732b4f5-b6f8-476a-99b3-5c44429125c1','初秋即事','寇準','宋','宋诗','song-poetry','','[]','古邑端居夏景移，炎飆經雨自收威。',64,'全唐诗/poet.song.4000.json','["古邑端居夏景移，炎飆經雨自收威。", "蓮衰小渚秋光淡，蟬噪平林夕照微。", "冷句每招江客和，深心終約嶽雲歸。", "晚凉却近南亭立，獨看沙鷗向浦飛。"]'),
('d8ebc754-2c31-4b21-9ca9-9fe45fe0eaa9','蓮','寇準','宋','宋诗','song-poetry','','[]','數柄疏荷出小池，幽香深謝好風吹。',32,'全唐诗/poet.song.4000.json','["數柄疏荷出小池，幽香深謝好風吹。", "曉來秋氣凝清露，似學湘妃怨九嶷。"]'),
('4536ad0e-26bb-4f89-84f5-ac4e318dc91f','望都雨夜','寇準','宋','宋诗','song-poetry','','[]','孤驛蕭條風雨夜，夜深窗竹動秋聲。',32,'全唐诗/poet.song.4000.json','["孤驛蕭條風雨夜，夜深窗竹動秋聲。", "離魂無睡難成夢，却遶長廊獨自行。"]'),
('187caa89-48aa-4c36-ba47-26e48877f2a4','成安秋望','寇準','宋','宋诗','song-poetry','','[]','八月西風蟬噪時，蕭蕭疏葉已辭枝。',32,'全唐诗/poet.song.4000.json','["八月西風蟬噪時，蕭蕭疏葉已辭枝。", "煙村物景都無頼，況是登臨有所思。"]'),
('8739c248-0f5a-4f54-ac1b-73b6dfc2115f','夏日晚凉','寇準','宋','宋诗','song-poetry','','[]','微凉天氣似秋期，風觸疏簾影自移。',64,'全唐诗/poet.song.4000.json','["微凉天氣似秋期，風觸疏簾影自移。", "遠夢有時尋水寺，孤吟終日對莎池。", "笋梢成翠堆輕籜，梅實翻黄壓嫩枝。", "兀兀騰騰聊自遣，此懷深謝野僧知。"]'),
('a6bf382d-fbb8-4d9c-94b0-146320224566','輦下書懷','寇準','宋','宋诗','song-poetry','','[]','身名長似夢，家計盡蕭然。',48,'全唐诗/poet.song.4000.json','["身名長似夢，家計盡蕭然。", "旅宦遊梁苑，歸心滿渭川。", "郊原秋變色，桑柘晚生煙。", "願得長閑去，何妨老一廛。"]'),
('cceb1a7c-ffb0-420e-8af4-800e4e436bff','冬日偶書','寇準','宋','宋诗','song-poetry','','[]','戶庭初過雪，鳥雀亦聲稀。',48,'全唐诗/poet.song.4000.json','["戶庭初過雪，鳥雀亦聲稀。", "天淡雲容結，林寒日影微。", "虛名何足道，前是旋成非。", "簪紱全忘念，終須掃澗扉。"]'),
('d903a772-431a-4bef-88b2-ca5001ce19dc','巴東縣齋秋書','寇準','宋','宋诗','song-poetry','','[]','訟庭終日靜，琴鶴亦長閑。',48,'全唐诗/poet.song.4000.json','["訟庭終日靜，琴鶴亦長閑。", "晚樹生凉吹，秋思在遠山。", "水穿吟閣過，苔遶印床斑。", "幸有江雲看，何須卜往還。"]'),
('9a4dcc08-3362-4f6b-831f-f181eb5d1d58','江行書事','寇準','宋','宋诗','song-poetry','','[]','孤棹沿流岸，凝懷似舊遊。',48,'全唐诗/poet.song.4000.json','["孤棹沿流岸，凝懷似舊遊。", "朝雲生嶽頂，斜月動江流。", "賤節難干世，離心易感秋。", "因思六朝事，千古有遺愁。"]'),
('d834dbb0-b0ac-4afe-a15f-44cacf1b5c4d','題楊氏別墅','寇準','宋','宋诗','song-poetry','','[]','門巷枕江濆，疑將俗境分。',48,'全唐诗/poet.song.4000.json','["門巷枕江濆，疑將俗境分。", "湖山晴後見，天籟靜中聞。", "徑僻苔空老，林寒日漸曛。", "高懷無一事，長歲似孤雲。"]'),
('4c0c4ed4-5279-4860-a6e3-e95742356778','再到鄴下有感','寇準','宋','宋诗','song-poetry','','[]','漳濱勝地皆牢落，晚歲重來恨莫收。',64,'全唐诗/poet.song.4000.json','["漳濱勝地皆牢落，晚歲重來恨莫收。", "極浦寺藏雲樹老，故人門鎖雨苔秋。", "煙霄得路輸時彥，泉石忘機阻舊遊。", "今日重思昔年事，放懷惟上夕陽樓。"]'),
('5401e547-dcb2-4e62-906a-5d5facabc565','成安秋望有懷','寇準','宋','宋诗','song-poetry','','[]','年加心地轉如灰，書篋經旬亦懶開。',64,'全唐诗/poet.song.4000.json','["年加心地轉如灰，書篋經旬亦懶開。", "詩句偶吟皆感事，文章無用獨傷才。", "秋蟬殘韻摇疏樹，夕照寒光下古臺。", "閑遶岸莎看野水，暗流紅葉不重回。"]'),
('ae39cdaf-fcd2-433e-9338-a87e9770550f','書懷寄唐工部','寇準','宋','宋诗','song-poetry','','[]','不才曾忝吾君選，紫殿科名志已酬。',64,'全唐诗/poet.song.4000.json','["不才曾忝吾君選，紫殿科名志已酬。", "孤立敢言逾素分，高吟深愧預清流。", "西風獨見江蘺暮，紅葉還思苑樹秋。", "多謝明公知賤節，每貽清句緩牢愁。"]'),
('45712e00-6e2b-4074-b834-65ea04114d23','鄴中和崔邁著作  其一','寇準','宋','宋诗','song-poetry','','[]','虛室凝愁厭夜眠，長吟靜對欲凉天。',64,'全唐诗/poet.song.4000.json','["虛室凝愁厭夜眠，長吟靜對欲凉天。", "夢迴故國人空遠，望斷重城月自圓。", "時泰未能拋組綬，性孤終是憶林泉。", "明朝奉詔遐方去，何處煙江寄客船。"]'),
('f210d156-2dd1-4317-85af-39f4a2a85bbd','鄴中和崔邁著作  其二','寇準','宋','宋诗','song-poetry','','[]','獨倚空樓畏景殘，凝眸魂斷楚雲端。',64,'全唐诗/poet.song.4000.json','["獨倚空樓畏景殘，凝眸魂斷楚雲端。", "猿清好雜江聲聽，山遠宜和霽色看。", "鳥掠平蕪堪入畫，風來危檻欲生寒。", "蕭蕭前浦歸帆靜，落日長吟且凭欄。"]'),
('0c0c1a06-06c2-4710-9e5c-900a62721f1f','漢上偶書','寇準','宋','宋诗','song-poetry','','[]','謫仙唐室遊茲郡，花下聽歌醉眼迷。',32,'全唐诗/poet.song.4000.json','["謫仙唐室遊茲郡，花下聽歌醉眼迷。", "今日漢江煙樹靜，更無人唱白銅鞮。"]'),
('1262e650-5aff-4789-8c0f-21ee546f61d6','舂陵聞雁  其一','寇準','宋','宋诗','song-poetry','','[]','蕭蕭疏葉下長亭，雲淡秋空一雁經。',32,'全唐诗/poet.song.4000.json','["蕭蕭疏葉下長亭，雲淡秋空一雁經。", "惟有北人偏悵望，孤城獨上倚樓聽。"]'),
('92205b55-df0d-48f4-92d4-625e0879f601','舂陵聞雁  其二','寇準','宋','宋诗','song-poetry','','[]','危欄秋盡偶來凭，霜落秋山爽氣澄。',32,'全唐诗/poet.song.4000.json','["危欄秋盡偶來凭，霜落秋山爽氣澄。", "誰道衡陽無雁過，數聲殘日下舂陵。"]'),
('eb0d943a-33c5-40b9-b2dc-e255126048d5','贈魏野處士','寇準','宋','宋诗','song-poetry','','[]','人間名利走塵埃，惟子高閑晦盛才。',64,'全唐诗/poet.song.4000.json','["人間名利走塵埃，惟子高閑晦盛才。", "欹枕夜風喧薜荔，閉門春雨長莓苔。", "詩題遠岫經年得，僧戀幽軒繼日來。", "却恐明君徵隠逸，溪雲誰得共徘徊。"]'),
('056abefe-6d7c-4ed1-91c5-a1526baeae52','荆南秋望','寇準','宋','宋诗','song-poetry','','[]','西風吹戶牖，猶自客荆蠻。',48,'全唐诗/poet.song.4000.json','["西風吹戶牖，猶自客荆蠻。", "積水浮秋漢，微陽淡遠山。", "蟬稀疏葉盡，雨歇片雲閑。", "何日忘簪紱，深居石室間。"]'),
('33a6f7a5-9181-4b91-9364-06354a0f7c03','江上送別','寇準','宋','宋诗','song-poetry','','[]','浪疊春江遠樹微，落花風雨共淒淒。',32,'全唐诗/poet.song.4000.json','["浪疊春江遠樹微，落花風雨共淒淒。", "愁人此際腸須斷，況是登臨更送歸。"]'),
('458069dc-f33e-4ca0-be6c-325bc1b6638b','送人往嶺表','寇準','宋','宋诗','song-poetry','','[]','炎光君此去，旅恨杳何窮。',24,'全唐诗/poet.song.4000.json','["炎光君此去，旅恨杳何窮。", "海樹瘴煙黑，蠻村山路中。"]'),
('ee046f8f-2ca0-4a75-95ae-14c172b32b11','秋日','寇準','宋','宋诗','song-poetry','','[]','柳衰蟬噪寒煙淡，地迥山遥暮雨收。',32,'全唐诗/poet.song.4000.json','["柳衰蟬噪寒煙淡，地迥山遥暮雨收。", "宛是昔年秋氣味，只添多病與離愁。"]'),
('2655fa68-e98d-40fb-aee1-4041093b6e61','留題洛北羅漢閣','寇準','宋','宋诗','song-poetry','','[]','地高閣迥宜閑望，望盡雲山首懶迴。',32,'全唐诗/poet.song.4000.json','["地高閣迥宜閑望，望盡雲山首懶迴。", "林下野僧應笑我，半年旌旆四曾來。"]'),
('e1188eef-aaab-46eb-877c-85db4d2f6920','判都省感懷','寇準','宋','宋诗','song-poetry','','[]','昔爲學士掌三銓，屈指年光三十年。',32,'全唐诗/poet.song.4000.json','["昔爲學士掌三銓，屈指年光三十年。", "秋雨滴階桐已老，白頭重到倍依然。"]'),
('7ea514aa-abc7-4fcf-a45d-20907029db92','輦下春日','寇準','宋','宋诗','song-poetry','','[]','雨餘宮闕麗春陰，三月花光照上林。',32,'全唐诗/poet.song.4000.json','["雨餘宮闕麗春陰，三月花光照上林。", "誰倚青樓望歸騎，日斜南陌柳煙深。"]'),
('47f27b28-5cfd-4bd5-991a-728d10a985e7','南宮宿齋靜思陝城東閣竹','寇準','宋','宋诗','song-poetry','','[]','南宮向夕景彌清，風竹蕭然動遠情。',32,'全唐诗/poet.song.4000.json','["南宮向夕景彌清，風竹蕭然動遠情。", "憶到陝城東閣伴，拂窗敲砌送寒聲。"]'),
('e78bb81d-f606-4e20-a10f-81d89486d553','途次方城','寇準','宋','宋诗','song-poetry','','[]','方城舊路四曾過，此度偏饒悵望多。',32,'全唐诗/poet.song.4000.json','["方城舊路四曾過，此度偏饒悵望多。", "獨倚客亭思往事，南陽何異夢南柯。"]'),
('e7acf96b-446f-4607-b903-6e7759567bed','經郴州永興驛','寇準','宋','宋诗','song-poetry','','[]','昔擁雙旌在斗城，今朝孤館語同名。',32,'全唐诗/poet.song.4000.json','["昔擁雙旌在斗城，今朝孤館語同名。", "天遥秦樹無因見，極目空饒悵望情。"]'),
('d968b507-fb6b-4eba-a34e-8d0238d6781d','臨海驛夏日','寇準','宋','宋诗','song-poetry','','[]','嶺外突蒸當盛暑，雨餘新館覺微凉。',32,'全唐诗/poet.song.4000.json','["嶺外突蒸當盛暑，雨餘新館覺微凉。", "最憐夏木青陰合，時有鶑聲似故鄉。"]'),
('9f14d896-6c00-4f07-abac-831bfbb93aec','海康西館有懷','寇準','宋','宋诗','song-poetry','','[]','風露凄清西館靜，悄然懷舊一長歎。',32,'全唐诗/poet.song.4000.json','["風露凄清西館靜，悄然懷舊一長歎。", "海雲銷盡金波冷，半夜無人獨凭欄。"]'),
('926cb0ef-74a8-40ca-a0c2-710b592ae58f','長安春日','寇準','宋','宋诗','song-poetry','','[]','淡淡秦雲薄似羅，灞橋楊柳拂煙波。',32,'全唐诗/poet.song.4000.json','["淡淡秦雲薄似羅，灞橋楊柳拂煙波。", "夕陽樓上山重疊，未抵愁春一倍多。"]'),
('34edad05-297c-47e6-9aed-a3c1a6393d56','病中書','寇準','宋','宋诗','song-poetry','','[]','多病將經歲，逢迎故不能。',48,'全唐诗/poet.song.4000.json','["多病將經歲，逢迎故不能。", "書惟看藥錄，客只待醫僧。", "壯志銷如雪，幽懷冷似冰。", "郡齋風雨後，無睡對寒燈。"]'),
('35bf2018-e620-43ed-8a31-5863d573c9fc','長安春書','寇準','宋','宋诗','song-poetry','','[]','務閑公府都無事，騎吏前驅引馬行。',64,'全唐诗/poet.song.4000.json','["務閑公府都無事，騎吏前驅引馬行。", "雨霽晚街官柳色，日長春寺講鐘聲。", "雲山已有終南秀，泉石猶思洛下清。", "聞道曲江新水滿，欲携歌管出重城。"]'),
('01de845b-40c3-42f1-a113-e2bbe8e733be','宮詞','寇準','宋','宋诗','song-poetry','','[]','長門秋夜雨，窗外滴寒聲。',24,'全唐诗/poet.song.4000.json','["長門秋夜雨，窗外滴寒聲。", "悔不先辭輦，應無別恨生。"]'),
('11a426bf-671e-4e45-8987-2aa0694c5a74','柳','寇準','宋','宋诗','song-poetry','','[]','絲翠最宜經宿雨，絮飛爭忍逐香塵。',32,'全唐诗/poet.song.4000.json','["絲翠最宜經宿雨，絮飛爭忍逐香塵。", "簾垂獨院無人處，一樹風摇日午春。"]'),
('5e589b1b-0ba9-4bb1-a976-8ca46587a664','杜陵','寇準','宋','宋诗','song-poetry','','[]','燕有情還至，花無主亂開。',24,'全唐诗/poet.song.4000.json','["燕有情還至，花無主亂開。", "杜陵人不見，夜月自徘徊。"]'),
('29d7e1d7-1413-4ea4-8e6d-41e7fb829602','左馮寺樓閑望','寇準','宋','宋诗','song-poetry','','[]','閑思至道年中事，獨倚左馮城外樓。',32,'全唐诗/poet.song.4000.json','["閑思至道年中事，獨倚左馮城外樓。", "目斷平皋人不見，暮天無際水悠悠。"]'),
('605f2ea1-2e48-4c39-b4d5-60cb2cb5c7a2','偶書','寇準','宋','宋诗','song-poetry','','[]','往事都如夢，流年只斷魂。',24,'全唐诗/poet.song.4000.json','["往事都如夢，流年只斷魂。", "不堪春盡日，細雨欲黄昏。"]'),
('71c74602-c65b-454c-a51e-04784a5b51a1','途次鄧州','寇準','宋','宋诗','song-poetry','','[]','南陽西去見遺基，駐馬平郊遠樹微。',32,'全唐诗/poet.song.4000.json','["南陽西去見遺基，駐馬平郊遠樹微。", "自笑平生無所著，不如山鳥解思歸。"]'),
('6067b8a0-3cd9-48eb-aeaa-80ad1ff2d4a1','春雨','寇準','宋','宋诗','song-poetry','','[]','漠漠霏霏著柳條，輕寒爭信杏花嬌。',32,'全唐诗/poet.song.4000.json','["漠漠霏霏著柳條，輕寒爭信杏花嬌。", "江南二月如煙細，誰正春愁在麗譙。"]'),
('89102545-f631-48c8-a8c5-a5005003e6c1','感舊','寇準','宋','宋诗','song-poetry','','[]','長思密勿侍甘泉，丹地翱翔獨少年。',32,'全唐诗/poet.song.4000.json','["長思密勿侍甘泉，丹地翱翔獨少年。", "重到文昌倍惆悵，秋風霜鬢共蕭然。"]'),
('7e54858f-c5bc-477a-a9dd-785335d0788f','途次三絕  其一','寇準','宋','宋诗','song-poetry','','[]','秋風故關路，蟬噪日斜時。',24,'全唐诗/poet.song.4000.json','["秋風故關路，蟬噪日斜時。", "有客驅征馬，茫茫天一涯。"]'),
('d343c0b6-98f5-4fae-83e4-df7f044f8dc8','途次三絕  其二','寇準','宋','宋诗','song-poetry','','[]','大澤荒草闊，行人心慘悽。',24,'全唐诗/poet.song.4000.json','["大澤荒草闊，行人心慘悽。", "邊雲時斷續，流水自東西。"]'),
('df55836d-3f2e-4296-844b-b62d083d5589','途次三絕  其三','寇準','宋','宋诗','song-poetry','','[]','沙闊戍樓迥，風高邊日清。',24,'全唐诗/poet.song.4000.json','["沙闊戍樓迥，風高邊日清。", "遲遲驅疋馬，何處問歸程。"]'),
('fdc05b89-f21f-4f31-8383-a534e38c79cd','冬日偶成','寇準','宋','宋诗','song-poetry','','[]','正是旅愁悲遠宦，況逢邊塞向殘年。',64,'全唐诗/poet.song.4000.json','["正是旅愁悲遠宦，況逢邊塞向殘年。", "輪蹄影絕冬深路，鳥雀聲稀雪後天。", "探騎經旬無使客，戍樓終日有烽煙。", "病來無復拈罇酒，獨向虛窗盡日眠。"]'),
('e5ea0aae-c628-44b0-b55b-b74620858c8e','九日羣公出遊郊外余方卧郡齋聽水因寄一絕呈諸官','寇準','宋','宋诗','song-poetry','','[]','菊老東籬人病酒，西風黄葉滿荒田。',32,'全唐诗/poet.song.4000.json','["菊老東籬人病酒，西風黄葉滿荒田。", "不知今日登高興，何似虛堂聽水眠。"]'),
('c58f5b86-2adc-407e-b361-23060b209a6d','春日偶書','寇準','宋','宋诗','song-poetry','','[]','柳岸花塘慵獨賞，閑門春盡阻閑遊。',32,'全唐诗/poet.song.4000.json','["柳岸花塘慵獨賞，閑門春盡阻閑遊。", "少年多故心先老，却被人疑似白頭。"]'),
('71403e2f-7a58-4fc5-9a8f-ff422245f913','送溫尚書入洛','寇準','宋','宋诗','song-poetry','','[]','蕭蕭紅葉馬前飛，又送王孫晝錦歸。',32,'全唐诗/poet.song.4000.json','["蕭蕭紅葉馬前飛，又送王孫晝錦歸。", "却到舊遊應悵望，故溪秋蘚滿魚磯。"]'),
('d694574b-fa8f-4287-867d-4bbf657ea197','小韓店','寇準','宋','宋诗','song-poetry','','[]','昔從鄴下遊梁苑，孤店曾經十數迴。',32,'全唐诗/poet.song.4000.json','["昔從鄴下遊梁苑，孤店曾經十數迴。", "歲月暗移人事改，白頭重到小韓來。"]'),
('1c68fa9a-ad3f-48fb-baec-1dbe9a3e5154','虛堂','寇準','宋','宋诗','song-poetry','','[]','虛堂寂寂草蟲鳴，欹枕難忘是舊情。',32,'全唐诗/poet.song.4000.json','["虛堂寂寂草蟲鳴，欹枕難忘是舊情。", "斜月半軒疏樹影，夜深風露更凄清。"]'),
('6bab7629-38eb-4327-953b-03b8741083e2','憶樊川','寇準','宋','宋诗','song-poetry','','[]','閑想舊遊都似夢，別來秦樹又西東。',32,'全唐诗/poet.song.4000.json','["閑想舊遊都似夢，別來秦樹又西東。", "高秋最憶樊川景，稻穗初黄柿葉紅。"]'),
('c50b6f19-2e54-459b-8259-7ffd528d027a','東窗','寇準','宋','宋诗','song-poetry','','[]','徙倚東窗夜未明，悄然幽館獨凝情。',64,'全唐诗/poet.song.4000.json','["徙倚東窗夜未明，悄然幽館獨凝情。", "燈摇古壁秋蟲怨，露下疏林宿鶴驚。", "道在任從時態薄，年加潛覺睡魂輕。", "待酬北闕君恩了，歸聽冰泉落石聲。"]'),
('f3ee3a7d-b4ea-40f6-aa55-cc1865ae1d1c','九日不飲','寇準','宋','宋诗','song-poetry','','[]','雲淡長空日欲斜，水邊衰柳噪寒鴉。',32,'全唐诗/poet.song.4000.json','["雲淡長空日欲斜，水邊衰柳噪寒鴉。", "病來不飲空凄感，獨遶東籬詠菊花。"]'),
('628c3434-5566-4394-acca-d3d0c654d9dc','和人春暮  其一','寇準','宋','宋诗','song-poetry','','[]','流年賦分長多感，盡日長思立短亭。',32,'全唐诗/poet.song.4000.json','["流年賦分長多感，盡日長思立短亭。", "猶謝海棠花始發，似留春色向凋零。"]'),
('77fd131c-8255-4d9f-98dd-dcc385bc5021','和人春暮  其二','寇準','宋','宋诗','song-poetry','','[]','昔曾過洛浦，遺恨寫蒼苔。',24,'全唐诗/poet.song.4000.json','["昔曾過洛浦，遺恨寫蒼苔。", "往事詩空在，春深我獨來。"]'),
('7b57467d-187a-4f6b-a28b-28a5f2002662','早行','寇準','宋','宋诗','song-poetry','','[]','嚴鐘將報曙，遊子已登途。',24,'全唐诗/poet.song.4000.json','["嚴鐘將報曙，遊子已登途。", "野火時明滅，殘星似有無。"]'),
('25ece38b-31ab-4aa2-a74a-119fa17f2819','月夜懷杜陵友生','寇準','宋','宋诗','song-poetry','','[]','一忝軺車命，三逢水國春。',48,'全唐诗/poet.song.4000.json','["一忝軺車命，三逢水國春。", "重看漢浦月，獨憶杜陵人。", "旅宦違前計，歸田失舊鄰。", "年來更多緒，清淚滿衣巾。"]'),
('9ec213d3-1aa6-4dd3-818b-86fc4376a967','贈僧','寇準','宋','宋诗','song-poetry','','[]','重城須久住，塵事日全無。',48,'全唐诗/poet.song.4000.json','["重城須久住，塵事日全無。", "落葉驚秋信，思山展舊圖。", "貌同仙鶴瘦，心似片雲孤。", "念我浮名在，還將靜者殊。"]'),
('9dcd78c5-6797-402f-a93a-eccd199462a8','楚江有弔','寇準','宋','宋诗','song-poetry','','[]','悲風颯颯起長洲，獨弔靈均恨莫收。',64,'全唐诗/poet.song.4000.json','["悲風颯颯起長洲，獨弔靈均恨莫收。", "深岸自隨浮世變，遺魂不逐大江流。", "霜凄極浦幽蘭暮，波動寒沙宿雁愁。", "月落烟沈無處泊，數聲猿叫楚山秋。"]'),
('a928720c-951f-4868-9a4a-6f338c744a2b','秋雨懷友生','寇準','宋','宋诗','song-poetry','','[]','江城秋雨歇，孤坐役吟身。',48,'全唐诗/poet.song.4000.json','["江城秋雨歇，孤坐役吟身。", "草色荒三逕，蟲聲滿四鄰。", "邊鴻來已近，庭葉落還頻。", "對此空搔首，無由面故人。"]'),
('294083b6-eddb-44be-b6d8-5e92fe04e51c','南亭','寇準','宋','宋诗','song-poetry','','[]','初夜南亭望，清吟露濕衣。',48,'全唐诗/poet.song.4000.json','["初夜南亭望，清吟露濕衣。", "雨餘羣籟發，天淡數星稀。", "秋氣又還至，故園猶未歸。", "虛堂愁重入，燭白冷光微。"]'),
('50ebb79f-38e9-4153-8730-45b2192dc888','贈惠政上人','寇準','宋','宋诗','song-poetry','','[]','寥寥長日掩松關，白首忘機古寺間。',64,'全唐诗/poet.song.4000.json','["寥寥長日掩松關，白首忘機古寺間。", "香燼石房終曉講，葉堆莎徑憶秋山。", "澄泉心地清無染，野鶴精神老更閑。", "孤坐有誰同此意，白雲空見渚禽還。"]'),
('a3ed9e37-4d95-4591-b791-3d08a6634194','輦下春望','寇準','宋','宋诗','song-poetry','','[]','獨向東門凝目望，園林無處不啼鶑。',64,'全唐诗/poet.song.4000.json','["獨向東門凝目望，園林無處不啼鶑。", "鄉心已似楊花亂，歸路那堪野草生。", "紫陌盡應趨勝地，紅塵誰肯受閑名。", "年來却羨滄江叟，長在湖山聽浪聲。"]'),
('42bbcef9-30a4-46ea-a90a-80133bf7c825','和蒨桃','寇準','宋','宋诗','song-poetry','','[]','將相功名終若何，不堪急景似奔梭。',32,'全唐诗/poet.song.4000.json','["將相功名終若何，不堪急景似奔梭。", "人間萬事何須問，且向樽前聽艷歌。"]'),
('94dbc276-8be1-4a69-91f4-f41f7640c34f','過襄州留題驛亭','寇準','宋','宋诗','song-poetry','','[]','沙堤築處迎丞相，驛吏催時送逐臣。',32,'全唐诗/poet.song.4000.json','["沙堤築處迎丞相，驛吏催時送逐臣。", "到了輸他林下客，無榮無辱自由身。"]'),
('2b4ee06b-4683-405e-9970-fec8af5ced91','春睡','寇準','宋','宋诗','song-poetry','','[]','春力著人春睡重，葉底黄鸝鳴自送。',32,'全唐诗/poet.song.4000.json','["春力著人春睡重，葉底黄鸝鳴自送。", "綠幕朱欄日觀明，回廊側戶風簾動。"]'),
('2da7ac20-04c2-45fd-9443-e1042b8ff5fe','華山','寇準','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u63cf\u5199\u5c71", "\u548f\u7269", "\u5199\u5c71"]','祇有天在上，更無山與齊。',24,'全唐诗/poet.song.4000.json','["祇有天在上，更無山與齊。", "舉頭紅日近，回首白雲低。"]'),
('374847b6-279b-4de8-bb58-4a1cca3fa75a','過新井慈光院留題海棠','寇準','宋','宋诗','song-poetry','','[]','暄風花雜滿欄香，盡日幽吟歎異常。',32,'全唐诗/poet.song.4000.json','["暄風花雜滿欄香，盡日幽吟歎異常。", "翻笑牡丹虛得地，玉階開落對君王。"]'),
('e2f20c40-ae9c-4930-a271-4ae4738b759b','廬山','寇準','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江南到處佳山水，廬阜丹霞是勝遊。',32,'全唐诗/poet.song.4000.json','["江南到處佳山水，廬阜丹霞是勝遊。", "獨抱古琴携竹杖，若逢絕境莫歸休。"]'),
('860f1562-45b2-4abd-b3f2-fb40775a7ad1','題廬山太平興國宮','寇準','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','飛泉噴薄走虹蜺，遠岫崢嶸植玉圭。',32,'全唐诗/poet.song.4000.json','["飛泉噴薄走虹蜺，遠岫崢嶸植玉圭。", "若有桃花鎮開落，遊人應認武陵溪。"]'),
('ab9e7fc6-293b-49d4-b338-e65383e2453a','頂山','寇準','宋','宋诗','song-poetry','','[]','雨歇黄梅後，秋生麥熟前。',48,'全唐诗/poet.song.4000.json','["雨歇黄梅後，秋生麥熟前。", "偶同金馬客，來訪玉龍泉。", "竹葉一尊酒，榴花五月天。", "不妨扶拄杖，行到白雲邊。"]'),
('86440521-6db2-4193-957e-9607612256bd','句  其一','寇準','宋','宋诗','song-poetry','','[]','冬葉扶疏碧繖團，溪山環郭莫窮端。',16,'全唐诗/poet.song.4000.json','["冬葉扶疏碧繖團，溪山環郭莫窮端。"]'),
