('cd11fbde-1308-4587-b192-1cbea67a6c90','春恨','寇準','宋','宋诗','song-poetry','','[]','侵階草色連朝雨，滿地梨花昨夜風。',32,'全唐诗/poet.song.4000.json','["侵階草色連朝雨，滿地梨花昨夜風。", "蜀魄不來春寂寞，楚魂吟夜月朦朧。"]'),
('fe54f76b-dbdf-4d2e-99d8-1767d8dda455','夢中作','謝濤','宋','宋诗','song-poetry','','[]','百年奇特幾張紙，千古英雄一窖塵。',32,'全唐诗/poet.song.4000.json','["百年奇特幾張紙，千古英雄一窖塵。", "惟有炳然周孔教，至今仁義浸生民。"]'),
('de695aea-0bea-4658-8ba4-e2040530fdca','題澄照寺主師壁','謝濤','宋','宋诗','song-poetry','','[]','疊巘收雲拂眼明，久依香社豁高情。',32,'全唐诗/poet.song.4000.json','["疊巘收雲拂眼明，久依香社豁高情。", "主人心似秋池水，一日看來一日清。"]'),
('4c38d703-734f-4406-8e28-f46f857942b4','呈寇公二首  其一','蒨桃','宋','宋诗','song-poetry','','[]','一曲清歌一束綾，美人猶自意嫌輕。',32,'全唐诗/poet.song.4000.json','["一曲清歌一束綾，美人猶自意嫌輕。", "不知織女螢窗下，幾度拋梭織得成。"]'),
('30579323-f091-418b-93a2-251980439cb6','呈寇公二首  其二','蒨桃','宋','宋诗','song-poetry','','[]','風勁衣單手屢呵，幽窗軋軋度寒梭。',32,'全唐诗/poet.song.4000.json','["風勁衣單手屢呵，幽窗軋軋度寒梭。", "臘天日短不盈尺，何似燕姬一曲歌。"]'),
('1bc319c8-736c-41eb-9767-85aaae875d50','送張無夢歸天台山','王欽若','宋','宋诗','song-poetry','','[]','天台瓊臺標奇狀，赤城瀑布懸千丈。',192,'全唐诗/poet.song.4000.json','["天台瓊臺標奇狀，赤城瀑布懸千丈。", "中有高人混姓名，不向迷塗隨得喪。", "閑尋棋侶過清溪，靜撥雲根種紫芝。", "八卦爐中調姹女，三田宮裏守嬰兒。", "太平天子秉乾籙，內寧外肅均百福。", "直符受事紫微宮，三捧靈文降黄屋。", "沖漠玄臺集九真，清浄洪基化兆民。", "祥風拂袂來幽谷，志士乘蹻朝玉宸。", "相見開懷忘歲月，因論微言鑒毫髮。", "萬壑流泉岸不枯，四時春煦花常發。", "却避紅塵思舊麓，空羨冥鴻歸勢速。", "囊中御製寵行歌，好與黄庭同誦讀。"]'),
('1e7601f8-4cd0-45dc-8a53-53dd6c590386','送天柱馮先生','王欽若','宋','宋诗','song-poetry','','[]','鬰蕭空殿倚雲霓，玉氣珠輝冠紫微。',64,'全唐诗/poet.song.4000.json','["鬰蕭空殿倚雲霓，玉氣珠輝冠紫微。", "暫到帝城朝斗會，却思巖竇負琴歸。", "日奔內景乾坤靜，泉漱清音杞菊肥。", "却到水鄉深邃住，晴嵐掩映簇春暉。"]'),
('39ad43a9-4e28-43b6-b518-0b9c82112ac9','覺林寺','王欽若','宋','宋诗','song-poetry','','[]','暫拂塵襟思倍清，竹風山色亂泉聲。',32,'全唐诗/poet.song.4000.json','["暫拂塵襟思倍清，竹風山色亂泉聲。", "安民功淺君恩重，又策羸蹄向古城。"]'),
('9a9f7c41-d9e8-4598-b222-fa93b868904a','詠華林書院','王欽若','宋','宋诗','song-poetry','','[]','文明尊北極，孝友播南昌。',96,'全唐诗/poet.song.4000.json','["文明尊北極，孝友播南昌。", "禮法兒孫睦，雍和道路揚。", "地靈浮喜氣，山近接嵐光。", "投轄添賓榻，鳴鼙啟食堂。", "紙窗蒭酒響，竹徑焙茶香。", "克己甘藜藿，矜貧濟稻粱。", "時平安九族，家計慶千箱。", "每聽游僧說，神清鬢未霜。"]'),
('e6eddefb-c28e-4394-890c-b9ef13e70a71','句  其一','王欽若','宋','宋诗','song-poetry','','[]','憶念西山玉隆友。',8,'全唐诗/poet.song.4000.json','["憶念西山玉隆友。"]'),
('d6d9dd60-57f2-49d7-816f-dfbb91ad6d75','句  其二','王欽若','宋','宋诗','song-poetry','','[]','春漬苔紋沿石塔，月含松韻雜琴聲。',16,'全唐诗/poet.song.4000.json','["春漬苔紋沿石塔，月含松韻雜琴聲。"]'),
('5006c8a8-6d69-41cc-b15d-6503e768d35c','句  其三','王欽若','宋','宋诗','song-poetry','','[]','石城松柏鎖烟霞。',8,'全唐诗/poet.song.4000.json','["石城松柏鎖烟霞。"]'),
('c9458e45-b71b-4113-a994-1891960bda89','句  其四','王欽若','宋','宋诗','song-poetry','','[]','九重天闕夢掉臂，黄雞白酒鄰舍恩。',16,'全唐诗/poet.song.4000.json','["九重天闕夢掉臂，黄雞白酒鄰舍恩。"]'),
('389504e4-a8d2-492d-a6ee-d41b88dfa4e6','句  其五','王欽若','宋','宋诗','song-poetry','','[]','須知堯曆初釐正，玉燭初從獻歲來。',16,'全唐诗/poet.song.4000.json','["須知堯曆初釐正，玉燭初從獻歲來。"]'),
('95c1b9c1-1836-4921-8ad1-26f5a4d144bd','句  其六','王欽若','宋','宋诗','song-poetry','','[]','龍带晚烟歸洞府，雁拖秋色入衡陽。',16,'全唐诗/poet.song.4000.json','["龍带晚烟歸洞府，雁拖秋色入衡陽。"]'),
('f9d921c1-a951-42ab-acc0-d5cd2f0a436e','余自天禧元祀解宥密之職首治是邦越期月而移蒞他郡于今八載復領藩政再踐殊館仰廟貌□如昔感威靈而長在强抽鄙思以紀歲華','張耆','宋','宋诗','song-poetry','','[]','雄屏口分寄，珍祠倏再臨。',72,'全唐诗/poet.song.4000.json','["雄屏口分寄，珍祠倏再臨。", "翬飛叢宇峻，龍濩洑淵深。", "蘋藻羅清薦，金匏合雅音。", "風旌翻鳳蜺，晨炷燎榆沉。", "麝墨披新刻，塵籤認舊吟。", "樂遊情未足，殘照下西岑。"]'),
('e7bba368-245a-4463-b7d1-a557d2ca6cdb','詩一首','杭州老尉','宋','宋诗','song-poetry','','[]','當年同試大明宮，文字雖同命不同。',32,'全唐诗/poet.song.4000.json','["當年同試大明宮，文字雖同命不同。", "我作尉時君作相，東皇元沒兩般風。"]'),
('cf09e1ed-6c6d-47f5-9818-583c0cf48bd2','送張無夢歸天台','曹谷','宋','宋诗','song-poetry','','[]','幾載仙山下，無機世莫分。',72,'全唐诗/poet.song.4000.json','["幾載仙山下，無機世莫分。", "因爲天市客，方識帝鄉雲。", "鍊氣壺中見，還元海內聞。", "名高赤城洞，歌賜紫皇君。", "步逐飈輪健，香隨斗極焚。", "何當挹蓬閬，鸞鶴自成羣。"]'),
('b0aa3ac2-6759-4158-8dbc-ff6dd92df8a1','爲王欽若作命書  其一','曹谷','宋','宋诗','song-poetry','','[]','七十年中一一加，弄珠灘上事堪誇。',32,'全唐诗/poet.song.4000.json','["七十年中一一加，弄珠灘上事堪誇。", "碧油幢下聞啼鳥，千日招還上漢槎。"]'),
('d5c89688-b0b3-4944-990c-f56016c35da3','爲王欽若作命書  其二','曹谷','宋','宋诗','song-poetry','','[]','周匝將臨壬戌歲，定鼎門前春色異。',32,'全唐诗/poet.song.4000.json','["周匝將臨壬戌歲，定鼎門前春色異。", "一千日上少三鐶，再入和羹宜盡瘁。"]'),
('51609d17-469b-4725-9fbc-ccb1cdd2fe7b','句','曹谷','宋','宋诗','song-poetry','','[]','臨去尚猶聞禁漏，異姓嘉名在史書。',16,'全唐诗/poet.song.4000.json','["臨去尚猶聞禁漏，異姓嘉名在史書。"]'),
('a02b21c7-c528-4a9d-9e52-31b194233799','別雲臺觀同宿饒益寺與魏野聯句','薛田','宋','宋诗','song-poetry','','[]','自古人人足歎嗟，閒遊得侶復堪誇。',34,'全唐诗/poet.song.4000.json','["自古人人足歎嗟，閒遊得侶復堪誇。", "可憐十宿無喧雜，不在僧家即道家。", "田。"]'),
('18e4dedd-94e4-4314-b256-b317c3e82dd9','成都書事百韻','薛田','宋','宋诗','song-poetry','','[]','混茫丕變造西阡，物象熙熙被一川。',384,'全唐诗/poet.song.4000.json','["混茫丕變造西阡，物象熙熙被一川。", "易覺錦城銷白日，難歌蜀道上青天。", "雲敷牧野耕桑雨，柳拂旗亭市井煙。", "院鎖玉溪留好景，坊題金馬促繁絃。", "風流鋪席堆紅豆，瀟灑門庭映碧鮮。", "表狀屢言同穎穗，敕書頻奬竝生蓮。", "旋科杞樹炊香稻，剩種豌巢沃晚田。", "仁宅不隳由政立，議闈無取任情遷。", "民知禮遜蠶叢後，俗尚奢華邃古先。", "繞郭波濤來浩浩，歸朝岐路去緜緜。", "乍回黑水將成道，潛到青羊恐遇仙。", "靚女各攻翻樣繡，袪商兼制砑綾牋。", "壚邊泛蟻張裙幄，江上鳴鼉簇淚船。", "石筍崚嶒衙對峙，琴臺恢闊寺相連。", "羣葩艷裏珍禽語，百草香中瑞獸眠。", "喜處必臻尤佇望，勝遊爭倦更遷延。", "早荷葉底蹲鴟伏，椶樹梢頭亂蝶穿。", "鹺發牢盆渾棄鹵，鐵資圜法免鉟鉛。", "豐饒物態甯殊越，美麗姝姬酷類燕。", "西海號雄彰傳紀，南康辭健積銘鎸。", "良工手技高容學，妙隠丹方祕不傳。", "倚劍靈關凌絕頂，夢刀孤壘削危巔。", "金華巷陌遺三品，石鏡伽藍露一拳。", "信落荆州隨鼓枻，檢頒芝闕聽摇鞭。"]'),
('cf9cad7e-7d08-4616-9302-8b93bac36116','景德四年爲中江令後爲益州轉運賦詩','薛田','宋','宋诗','song-poetry','','[]','一同舊治居芸閣，八使新銜忝柏臺。',32,'全唐诗/poet.song.4000.json','["一同舊治居芸閣，八使新銜忝柏臺。", "父老出郊迎馬首，人情似到故鄉來。"]'),
('ed380e4a-1858-4eaf-bd5a-698f0da2482a','喜友人過隠居','曹汝弼','宋','宋诗','song-poetry','','[]','忽向新春裏，閑過隠士家。',48,'全唐诗/poet.song.4000.json','["忽向新春裏，閑過隠士家。", "旋收松上雪，來煮雨前茶。", "禽換新歌曲，梅妝隔歲花。", "應慚非遁者，難久在煙霞。"]'),
('d3248338-8f5d-4646-b3b1-f2245bbaa32a','懷寄披雲峰誠上人','曹汝弼','宋','宋诗','song-poetry','','[]','院高窮木盛，野極靜無言。',48,'全唐诗/poet.song.4000.json','["院高窮木盛，野極靜無言。", "險路通巖頂，香泉出石根。", "微風飄磬韻，幽鳥啄苔痕。", "常記相留夜，秋堂共聽猿。"]'),
('90fab847-b998-464b-94d0-1f8d8b64f56b','再寄','曹汝弼','宋','宋诗','song-poetry','','[]','江城從別後，聞說在松間。',48,'全唐诗/poet.song.4000.json','["江城從別後，聞說在松間。", "度日長扃戶，終年不下山。", "靜爲詩所役，閑免事相關。", "應喜雲邊客，冥搜鬢未斑。"]'),
('5df7a740-0c96-46db-81c3-81a03d32574f','贈披雲峰岳長老','曹汝弼','宋','宋诗','song-poetry','','[]','禪外掩松扃，閑眠度歲陰。',48,'全唐诗/poet.song.4000.json','["禪外掩松扃，閑眠度歲陰。", "雨侵香篆溼，苔長屐痕深。", "水在銅瓶冷，雲歸玉磬沈。", "前山有靈藥，時策杖藜尋。"]'),
('22894aaf-6a1d-41de-bda1-b5f3c716e897','贈僧','曹汝弼','宋','宋诗','song-poetry','','[]','一從叨命服，乘興入天台。',48,'全唐诗/poet.song.4000.json','["一從叨命服，乘興入天台。", "院接石橋住，門臨瀑布開。", "松閒應獨坐，雪裏更誰來。", "時復携藜杖，看雲上古台。"]'),
('fcbd4ee1-689b-4033-b810-a68202500039','國朝自建隆至大中祥符七年垂五十載謝頤素始奏名甫官太守','陳逸賞','宋','宋诗','song-poetry','','[]','死却王褒五百春，資中不見有詞臣。',32,'全唐诗/poet.song.4000.json','["死却王褒五百春，資中不見有詞臣。", "今朝忽遇登龍客，喜殺西郊謝逸人。"]'),
('6fa747ad-04ed-4dc5-a27e-b99d041488f1','送張無夢歸天台','孫奭','宋','宋诗','song-poetry','','[]','笑背芙蓉闕，東南望海涯。',48,'全唐诗/poet.song.4000.json','["笑背芙蓉闕，東南望海涯。", "雲章藏綠藴，鶴馭拂青霞。", "台嶺攀新桂，桃源訪舊花。", "鳴騶須再去，莫泛客星槎。"]'),
('53b9fdc2-9da5-4699-b4ca-53a15228d8bb','南朝','錢惟演','宋','宋诗','song-poetry','','[]','結綺臨春映夕霏，景陽鐘動曙星稀。',64,'全唐诗/poet.song.4000.json','["結綺臨春映夕霏，景陽鐘動曙星稀。", "潘妃寶釧光如晝，江令花牋落似飛。", "舴艋凌波朱火度，觚稜拂漢紫烟微。", "自從飲馬秦淮水，蜀柳無因對殿幃。"]'),
('1cc0b9c6-0dc1-4b84-85c4-16c3c47142c1','禁中庭樹','錢惟演','宋','宋诗','song-poetry','','[]','紫闥分陰地，丹條擢秀時。',48,'全唐诗/poet.song.4000.json','["紫闥分陰地，丹條擢秀時。", "高枝接溫樹，密葉覆辛夷。", "夜影瑶光接，晨英玉露滋。", "乘春好封殖，爲賦角弓詩。"]'),
('904b23c3-db25-4832-90ba-bd82c123d046','休沐端居有懷希聖少卿學士','錢惟演','宋','宋诗','song-poetry','','[]','雕盤瓊蕊冰寒凘，密樹蟬嘶下直時。',64,'全唐诗/poet.song.4000.json','["雕盤瓊蕊冰寒凘，密樹蟬嘶下直時。", "更賦新詩答靈運，不將團扇隔元規。", "經梅綠草沿階上，盡日流風轉蕙遲。", "祇待觚稜照初旭，橫經還集絳紗韓。"]'),
('46fa3f0d-75d5-4f48-910e-280bceed5e04','再次首唱韻和','錢惟演','宋','宋诗','song-poetry','','[]','雲變危峰萬里橫，簟鋪湘水一牀平。',64,'全唐诗/poet.song.4000.json','["雲變危峰萬里橫，簟鋪湘水一牀平。", "紅蘭受露消晨渴，綠蕙翻風析夜酲。", "逸少偶書葵扇貴，羊欣閒卧練裙輕。", "無妨天上芝泥熟，獨看瑶光近太清。"]'),
('6669b69c-a295-4a7a-b613-d92f9be5d903','槿花','錢惟演','宋','宋诗','song-poetry','','[]','綺霞初結處，珠露未晞時。',48,'全唐诗/poet.song.4000.json','["綺霞初結處，珠露未晞時。", "寶樹寧三尺，華燈更九枝。", "亭亭方自喜，黯黯却成悲。", "欲作飛烟散，猶憐反照遲。"]'),
('597c9251-8d3b-4dd8-9112-16dc11b563ab','漢武','錢惟演','宋','宋诗','song-poetry','','[]','一曲橫汾鼓吹迴，侍臣高會柏梁臺。',64,'全唐诗/poet.song.4000.json','["一曲橫汾鼓吹迴，侍臣高會柏梁臺。", "金芝燁煜凌晨見，青雀軒翔白晝來。", "立候東溟邀鶴駕，窮兵西極待龍媒。", "甘泉祭罷神光滅，更遣人間識玉杯。"]'),
('b7f60724-cc34-4d3c-90a2-244c0e99fcbb','館中新蟬','錢惟演','宋','宋诗','song-poetry','','[]','冉冉光風泛紫蘭，新聲含怨日將殘。',64,'全唐诗/poet.song.4000.json','["冉冉光風泛紫蘭，新聲含怨日將殘。", "自憐伴雀成團扇，誰許迎秋集武冠。", "委蛻亭皋隨木葉，飛緌雲表拂仙盤。", "青葱玉樹連金爵，不覺醯雞競羽翰。"]'),
('7e5a7c37-14f7-405a-97ab-19a56ca1836a','夜讌','錢惟演','宋','宋诗','song-poetry','','[]','昨夜讌南堂，華燈燭九光。',72,'全唐诗/poet.song.4000.json','["昨夜讌南堂，華燈燭九光。", "削青爭落筆，舉白鬭飛觴。", "祇覺輝裴玉，寧思夢謝塘。", "解煩多蜜勺，藉俎半蘭芳。", "促席風弦怨，開簾月露凉。", "酡顔君莫訴，西北轉銀潢。"]'),
('0441134e-cef3-47cb-b4e1-128bd66f6301','鶴','錢惟演','宋','宋诗','song-poetry','','[]','碧樹陰濃接玉墀，幾年飛舞伴長離。',64,'全唐诗/poet.song.4000.json','["碧樹陰濃接玉墀，幾年飛舞伴長離。", "天淵風雨多秋意，遼海烟波失舊期。", "自許一鳴聞逈漢，可隨三匝繞空枝。", "從來腐鼠何曾顧，不似鵷雛枉見疑。"]'),
('3082a7d2-1891-49df-94e3-12a5c206c1b1','公子','錢惟演','宋','宋诗','song-poetry','','[]','蓮勺交衢接荻園，來時十里一開筵。',64,'全唐诗/poet.song.4000.json','["蓮勺交衢接荻園，來時十里一開筵。", "歌翻南國桃根曲，馬過章臺杏葉韉。", "別殿對迴雙綬貴，後門歸夜九枝然。", "閒隨翠幰欹烏帽，紫陌三條入柳烟。"]'),
('cea20237-9dd8-4ffd-a5a8-555107fff5f0','宣曲二十二韻','錢惟演','宋','宋诗','song-poetry','','[]','絳縷初分後，銀鐶未解時。',264,'全唐诗/poet.song.4000.json','["絳縷初分後，銀鐶未解時。", "已障紈扇笑，猶捧玉壺悲。", "乞巧長生殿，迎風太液池。", "雕屏涵火齊，寶帳隔琉璃。", "欲買詞人賦，空傳狎客詩。", "蔗漿銷內熱，瓊蕊療朝饑。", "綺蒂桃初熟，紅心草欲披。", "凌波渡羅襪，向日翳華芝。", "素臉分丹柰，香津滴紫梨。", "龍梭隨振素，獺髓補凝脂。", "蓬餌重陽節，金針七夕期。", "玉膏嘗滵溢，翠蓋逐葳蕤。", "弦急哀隨指，歌長恨入眉。", "青鸞惟有舞，赤鳳可能疑。", "下蔡迷還易，平陽破未知。", "髻高釵自墜，腰細佩長垂。", "出恐嚴鍾晚，歸嫌鈿幰遲。", "轆轤驚曉夢，鸚鵡漏春思。", "魂怨惟愁斷，腸柔已自危。", "璧璫螢影度，瓊戶蘚花滋。", "掩鼻讒難訴，披圖悔豈追。", "祇應金带枕，聊爲達微辭。"]'),
('28807e1c-468d-4e7a-b97f-78c8c8e12fc9','夜意','錢惟演','宋','宋诗','song-poetry','','[]','漏淺風微夜未勝，雨雲無跡火雲凝。',64,'全唐诗/poet.song.4000.json','["漏淺風微夜未勝，雨雲無跡火雲凝。", "簟鋪寒水頻移枕，帳卷輕烟更背燈。", "沃頂幾思金掌露，滌煩誰借玉壺冰。", "蘭臺知有披襟處，宋玉多才獨自登。"]'),
('f2ddbeca-b97f-4b77-add0-0eccc4701757','明皇','錢惟演','宋','宋诗','song-poetry','','[]','山上湯泉架玉梁，雲中複道拂瑶光。',64,'全唐诗/poet.song.4000.json','["山上湯泉架玉梁，雲中複道拂瑶光。", "絲囊暗結三危露，翠幰時遺百和香。", "枉是金雞親便坐，更拋珠被掩方牀。", "匆匆一曲凉州罷，萬里橋邊見夕陽。"]'),
('6a9809e4-88a9-4146-912d-4a77d05dd6fe','別墅','錢惟演','宋','宋诗','song-poetry','','[]','別館斗城傍，斜軒映曲房。',96,'全唐诗/poet.song.4000.json','["別館斗城傍，斜軒映曲房。", "蒼頭冠綠幘，中婦織流黄。", "複道登平樂，期門集未央。", "意錢梁冀宅，挾瑟莫愁堂。", "走馬章臺柳，停車陌上桑。", "彀弓隨寶障，投轄付銀牀。", "出戴繁星急，歸衝細雨忙。", "曾過阿君宿，醉舞起跳梁。"]'),
('3713957e-8f77-4c78-824c-1848f49eac2f','無題三首  其一','錢惟演','宋','宋诗','song-poetry','','[]','誤語成疑意已傷，春山低歛翠眉長。',64,'全唐诗/poet.song.4000.json','["誤語成疑意已傷，春山低歛翠眉長。", "鄂君繡被朝猶掩，荀令薰爐冷自香。", "有恨豈因燕鳳去，無言寧爲息侯亡。", "合歡不驗丁香結，祇得凄凉對燭房。"]'),
('cba8de5f-6a40-494d-8e0b-cd72782ef898','無題三首  其二','錢惟演','宋','宋诗','song-poetry','','[]','耿耿寒燈照醉羅，看朱成碧意如何。',64,'全唐诗/poet.song.4000.json','["耿耿寒燈照醉羅，看朱成碧意如何。", "虎頭辟惡無妨枕，犀角凉心更待磨。", "惟有幽蘭啼月露，可將尺素託雲波。", "山屏六曲歸來夜，祇恐重投折齒梭。"]'),
('3bfaef76-9083-4b9e-b772-3cdc3cbcaa31','無題三首  其三','錢惟演','宋','宋诗','song-poetry','','[]','香歇環沉無限猜，春陰濃淡畫簾開。',64,'全唐诗/poet.song.4000.json','["香歇環沉無限猜，春陰濃淡畫簾開。", "有時盤馬看猶懶，盡日投壺笑未迴。", "蝶怨豈能重傅粉，雉嬌疑待更求媒。", "啼粧不治金翹闇，腸斷溫郎玉照臺。"]'),
('e6dd76ef-cb4d-4f1c-a256-0ed28aa1a5fa','荷花','錢惟演','宋','宋诗','song-poetry','','[]','水闊雨蕭蕭，風微影自摇。',72,'全唐诗/poet.song.4000.json','["水闊雨蕭蕭，風微影自摇。", "徐娘羞半面，楚女妬纖腰。", "別恨拋深浦，遺香逐畫橈。", "華燈連霧夕，鈿合映霞朝。", "淚有鮫人見，魂須宋玉招。", "凌波終未渡，疑待鵲爲橋。"]'),
('01e4cb8b-422d-497e-9bf6-d4d717edea80','再賦','錢惟演','宋','宋诗','song-poetry','','[]','玉甃引清泉，風高露白天。',72,'全唐诗/poet.song.4000.json','["玉甃引清泉，風高露白天。", "盈盈臨一水，羃羃隔長烟。", "已分蘭芝溺，仍憂趙后仙。", "鮫絲衣更密，珠蚌淚長圓。", "瑟怨來湘浦，鴻驚近洛川。", "金塘正斜照，誰倚木蘭船。"]'),
('f6685fe2-a00d-4059-82b0-34234d6b9a28','再賦七言','錢惟演','宋','宋诗','song-poetry','','[]','欲網珊瑚碧浪深，橫塘斜日带秋陰。',64,'全唐诗/poet.song.4000.json','["欲網珊瑚碧浪深，橫塘斜日带秋陰。", "漢宮此地留金餠，洛浦何人遺錦衾。", "舞學西城迴雅態，歌傳南國有餘音。", "韓憑恨魄如長在，青骨香銷亦見尋。"]'),
('89e57369-e712-49ed-a113-fa685e2ae703','又贈一絕','錢惟演','宋','宋诗','song-poetry','','[]','唾露金銷月似霜，雲屏玉簟剩清光。',32,'全唐诗/poet.song.4000.json','["唾露金銷月似霜，雲屏玉簟剩清光。", "不如誰有高唐夢，翠被華燈徹曙香。"]'),
('36af74c6-5b48-45ed-bbac-1f8e5484a9fb','梨','錢惟演','宋','宋诗','song-poetry','','[]','紫花青蒂壓枝繁，秋實離離出上蘭。',64,'全唐诗/poet.song.4000.json','["紫花青蒂壓枝繁，秋實離離出上蘭。", "東海圓珪無柰碧，嵰州甜雪不勝寒。", "已憂仙佩懸珠重，更恐金刀切玉難。", "自與相如解痟渴，何須瓊蕊作朝餐。"]'),
('6dcde01c-0c09-4b64-865c-a42030f7c44e','淚二首  其一','錢惟演','宋','宋诗','song-poetry','','[]','鮫盤千點怨吞聲，蠟炬風高翠箔輕。',64,'全唐诗/poet.song.4000.json','["鮫盤千點怨吞聲，蠟炬風高翠箔輕。", "夜半商陵聞別鶴，酒闌安石對哀箏。", "銀屏欲去連珠迸，金屋初來玉筯橫。", "馬上悲歌寄黄鵠，紫臺迴首暮雲平。"]'),
('952c3537-89f9-4dd1-b824-c93a687ff434','淚二首  其二','錢惟演','宋','宋诗','song-poetry','','[]','家在河陽路入秦，樓頭相望祇酸辛。',64,'全唐诗/poet.song.4000.json','["家在河陽路入秦，樓頭相望祇酸辛。", "江南滿目新亭宴，旗鼓傷心故國春。", "仙掌倚天頻滴露，方諸待月自涵津。", "荆王未辨連城價，腸斷南州抱璧人。"]'),
('e447d455-4dc4-4dbb-8b48-4286cd5d31d9','七夕','錢惟演','宋','宋诗','song-poetry','','[]','紫天銀水渡辛夷，藻帳雕屏解佩時。',64,'全唐诗/poet.song.4000.json','["紫天銀水渡辛夷，藻帳雕屏解佩時。", "金朔窗中窺阿母，小姑堂上憶蘭芝。", "初宵已有穿針樂，欲曙還成弄杼悲。", "若比人間更腸斷，萬重雲浪寄微辭。"]'),
('fac80414-7e25-4cfe-9e82-0a9a1bb880d7','成都','錢惟演','宋','宋诗','song-poetry','','[]','武侯千載有遺靈，盤石刀痕尚未平。',64,'全唐诗/poet.song.4000.json','["武侯千載有遺靈，盤石刀痕尚未平。", "巴婦自饒丹穴富，漢庭還責碧砮征。", "雨經蜀市應和酒，琴到臨邛別寄情。", "知有忠臣能叱馭，不論雲棧更崢嶸。"]'),
('b59dc59c-11ec-4f12-aa17-d5d3179d58c4','秋夜對月','錢惟演','宋','宋诗','song-poetry','','[]','顥氣中秋正，明河左界長。',96,'全唐诗/poet.song.4000.json','["顥氣中秋正，明河左界長。", "桂孤香易散，蚌冷淚先汪。", "飛蓋傾蘭坂，鳴琴厭燭房。", "玉盤浮浩露，素綆冰寒漿。", "浪白江連楚，風凄笛怨羌。", "庾樓聊顧慕，潘省更悲凉。", "雪漫誇圓璧，珠休號夜光。", "嫦娥悔孀獨，空見海生桑。"]'),
('9e054c77-e507-444f-a45d-c0153891e9e2','小園秋夕','錢惟演','宋','宋诗','song-poetry','','[]','潘鬢秋來已自傷，庾園時物更荒凉。',64,'全唐诗/poet.song.4000.json','["潘鬢秋來已自傷，庾園時物更荒凉。", "紫梨半熟連紅樹，碧蘚初圓亂縹牆。", "月露暗從孤桂滴，水風猶獵敗荷香。", "滑稽還喜鴟夷在，欲取臨邛美酒嘗。"]'),
('f8601bb8-2cfa-4ade-9c04-c661a34cdc10','始皇','錢惟演','宋','宋诗','song-poetry','','[]','天極周環百二都，六王鍾鐻接劉蘇。',64,'全唐诗/poet.song.4000.json','["天極周環百二都，六王鍾鐻接劉蘇。", "金椎漫築甘泉道，匕首還隨督亢圖。", "已覺副車驚博浪，更携連弩望蓬壺。", "不將寸土封諸子，劉項由來是匹夫。"]'),
('dbc2a2fb-0ba7-44d4-bf84-4d8422032eec','初秋屬疾','錢惟演','宋','宋诗','song-poetry','','[]','蜜房初滿石榴紅，秋意先侵玉井桐。',64,'全唐诗/poet.song.4000.json','["蜜房初滿石榴紅，秋意先侵玉井桐。", "薤簟自憑南郭几，縠巾猶卧北窗風。", "雲迷候雁辭遥塞，露濕飛螢起暗叢。", "病已不須傳七發，粉牋香墨寄詩筒。"]'),
('260ea776-9db6-48dc-8023-87ff23ff0ab7','寄靈仙觀舒職方學士','錢惟演','宋','宋诗','song-poetry','','[]','方瞳玄鬢粉闈郎，絳闕齋心奉紫皇。',64,'全唐诗/poet.song.4000.json','["方瞳玄鬢粉闈郎，絳闕齋心奉紫皇。", "徵士高懷雲在嶺，騷人秋思水周堂。", "閑園露草開三逕，靈宇華燈燭九光。", "知有美田堪種玉，幾時春渚逐歸艎。"]'),
('28947b94-0bd2-49c0-b098-cd5a915243a0','宋玉','錢惟演','宋','宋诗','song-poetry','','[]','章華清宴重遊陪，已有微詞更有才。',64,'全唐诗/poet.song.4000.json','["章華清宴重遊陪，已有微詞更有才。", "神女夢靈因賦感，屈平魂怨待招迴。", "悲秋終古情難盡，障袂何時望可來。", "祇有大言君自許，景差無計上蘭臺。"]'),
('db606f6d-5997-49ec-b49f-e3519bf21792','送客不及','錢惟演','宋','宋诗','song-poetry','','[]','橋闊川長恨已多，斑騅嘶斷隔雲蘿。',64,'全唐诗/poet.song.4000.json','["橋闊川長恨已多，斑騅嘶斷隔雲蘿。", "遥山幾疊迷朱旆，芳草經時駐玉珂。", "高鳥可能追夕照，綠楊空自拂微波。", "短轅白鼻何由得，目送層樓一雁過。"]'),
('f5e657f2-0e21-4f9b-9078-5a8f61d73a6f','夕陽','錢惟演','宋','宋诗','song-poetry','','[]','遠色連高樹，迴光射逈樓。',48,'全唐诗/poet.song.4000.json','["遠色連高樹，迴光射逈樓。", "自翻歸雁影，更急思蟲愁。", "烟暝長先隔，霞烘久未收。", "華燈知可繼，惟照洞房幽。"]'),
('0817c757-6974-4a9e-9a14-d1e8b86d5271','樞密王左丞宅新菊','錢惟演','宋','宋诗','song-poetry','','[]','賀燕翻飛地，靈芳茂遂時。',96,'全唐诗/poet.song.4000.json','["賀燕翻飛地，靈芳茂遂時。", "陰連桃李徑，潤接鳳凰池。", "夕照揮金葆，輕風拂翠蕤。", "露珠清自沍，烟素引還披。", "西顥霜雖勁，南榮暖更滋。", "擷芳多楚澤，得地勝陶籬。", "味可登蘭籍，香應奪桂旗。", "願公長却老，宴寢奉瓊巵。"]'),
('fd110604-a51b-4eff-8b6e-e3207c3ca9e7','直夜','錢惟演','宋','宋诗','song-poetry','','[]','千廬徼道發傳呼，帝宇沉沉璧月孤。',64,'全唐诗/poet.song.4000.json','["千廬徼道發傳呼，帝宇沉沉璧月孤。", "重橑祇聞喧鬭鼠，危枝誰見繞驚烏。", "石螭霜重連鈎盾，玉虎冰消下轆轤。", "素髮自憐同騎省，一竿何日釣秋鱸。"]'),
('6aa04549-6734-4534-a9d6-f60ab1c2227f','柳絮','錢惟演','宋','宋诗','song-poetry','','[]','三月江南花漸稀，春陰漠漠雪霏霏。',64,'全唐诗/poet.song.4000.json','["三月江南花漸稀，春陰漠漠雪霏霏。", "章臺街裏翩輕吹，灞水橋邊送落暉。", "陸凱傳精梅暗落，韓憑遺恨蝶爭飛。", "詔書漫道吹綸薄，誰見紛紛上客衣。"]'),
('2ba4d308-250d-497d-ac61-fd5b55a4b600','與客啟明','錢惟演','宋','宋诗','song-poetry','','[]','越溪微霰灑寒梅，家近嚴陵古釣臺。',64,'全唐诗/poet.song.4000.json','["越溪微霰灑寒梅，家近嚴陵古釣臺。", "夢欲成魚通夕去，書曾憑犬隔秋迴。", "干時不爲侏儒米，樂聖猶銜叔夜杯。", "帝右豈無楊得意，漢宮須薦長卿才。"]'),
('1aca6426-73ea-4a72-8d8a-7d2fb949b8d6','無題','錢惟演','宋','宋诗','song-poetry','','[]','絳縷初分麝氣濃，絃聲不動意潛通。',64,'全唐诗/poet.song.4000.json','["絳縷初分麝氣濃，絃聲不動意潛通。", "圓蟾可見還歸海，媚蝶多驚欲御風。", "紈扇寄情雖自潔，玉壺盛淚祇凝紅。", "春窗亦有心知夢，未到鳴鐘已旋空。"]'),
('3d7697e6-7420-405e-bdbc-4ea3607b5028','霜月','錢惟演','宋','宋诗','song-poetry','','[]','霜月正如鈎，臨池更上樓。',48,'全唐诗/poet.song.4000.json','["霜月正如鈎，臨池更上樓。", "沈侯新覺瘦，宋玉舊多愁。", "獺髓分膏密，鵝毛寫恨稠。", "長懷寄歸雁，歸雁自悠悠。"]'),
('959b3670-16fe-43a9-9e06-62c642a529e5','此夕','錢惟演','宋','宋诗','song-poetry','','[]','曲瓊斜掛影沉沉，火齊屏風六曲深。',64,'全唐诗/poet.song.4000.json','["曲瓊斜掛影沉沉，火齊屏風六曲深。", "春瘦已寬連理带，夜長誰有辟寒金。", "珠拋月浦空涵淚，琴怨蘭堂漫寄心。", "碧玉可能攀貴德，阮郎追騎更駸駸。"]'),
('a7c3e1b0-7767-4c23-b0e3-5c881b91180e','燈夕寄獻內翰虢略公','錢惟演','宋','宋诗','song-poetry','','[]','嶢闕翬飛河漢傍，鈎陳遥認赭袍光。',64,'全唐诗/poet.song.4000.json','["嶢闕翬飛河漢傍，鈎陳遥認赭袍光。", "九枝火樹連金狄，萬里霜輪上碧璫。", "匝地行車珠網細，照天晨燎紫沉香。", "祇聞鼇嶺神仙客，再拜雲邊捧壽觴。"]'),
('167ab41b-3aff-4366-9562-a2c7b6853f48','懷舊居','錢惟演','宋','宋诗','song-poetry','','[]','武夷仙壇接里閭，琴堂水閣半凌虛。',64,'全唐诗/poet.song.4000.json','["武夷仙壇接里閭，琴堂水閣半凌虛。", "竹林舊享銅盤食，門巷今容駟馬車。", "楚國大言登宋玉，漢家答詔用相如。", "未知笳鼓歸何日，空鎖鱣庭春草疏。"]'),
('b88cc6b2-1fe7-47d3-82ff-b0b21ea9f2ca','許洞歸吳中','錢惟演','宋','宋诗','song-poetry','','[]','草薰風暖接長亭，一曲驪歌倒醁醽。',64,'全唐诗/poet.song.4000.json','["草薰風暖接長亭，一曲驪歌倒醁醽。", "懷古更投玄石賦，艤舟閑採紫莖萍。", "醉拋隋岸楊花白，吟過淮山桂樹青。", "可使長離終鎩羽，淵雲辭藻掞天庭。"]'),
('305f1919-2ef8-4ca8-8999-38b6d2891d33','上巳玉津園賜宴','錢惟演','宋','宋诗','song-poetry','','[]','漢家傳洛飲，楚俗泛蘭泉。',72,'全唐诗/poet.song.4000.json','["漢家傳洛飲，楚俗泛蘭泉。", "玉液初頒酒，金盤屢擊鮮。", "珥彤尋竹籞，傾蓋集芝廛。", "錦羽翻晴旭，霞英落暖烟。", "雅音和舜樂，睿澤洽堯天。", "更聽承雲曲，同歌在鎬年。"]'),
('9d0e0983-35fb-4479-8e49-dc1c736707f2','致齋太一宮','錢惟演','宋','宋诗','song-poetry','','[]','齋潔奉惟馨，瑶臺獨自升。',96,'全唐诗/poet.song.4000.json','["齋潔奉惟馨，瑶臺獨自升。", "樓迷五里霧，壇燭九枝燈。", "珠館來青雀，琁題射玉繩。", "疏鐘平野闊，古柏夕霏凝。", "鶴扇真規月，仙衣可鏤冰。", "春茶泛雲液，曉飯薦蘭蒸。", "棄藥疑洪井，藏書類羽陵。", "回瞻太帝室，飛檻更長憑。"]'),
('dbfed568-d536-419e-a0e9-9fac298095af','苦熱','錢惟演','宋','宋诗','song-poetry','','[]','赫日烘霞鬭曉光，雙文桃簟碧牙牀。',64,'全唐诗/poet.song.4000.json','["赫日烘霞鬭曉光，雙文桃簟碧牙牀。", "頻傾蜜勺寧蠲渴，久捧冰壺未覺凉。", "雪嶺却思隨博望，風窗猶欲傲羲皇。", "更憐乳燕翻飛處，深入盧家白玉堂。"]'),
('ad0d1201-bf6e-4ed7-b5a1-7da4b410084f','清風十韻','錢惟演','宋','宋诗','song-poetry','','[]','溽暑迎秋盡，凉颸逗曉迴。',120,'全唐诗/poet.song.4000.json','["溽暑迎秋盡，凉颸逗曉迴。", "起蘋初淅瀝，獵桂更徘徊。", "欲引長烟素，微飄畫燭煤。", "墜桐侵玉井，拂柳度章臺。", "已覺雲翹動，還驚月幌開。", "鮫簾移亂影，瑶瑟泛餘哀。", "扇掩藏鸞羽，荷傾側露杯。", "正當河左界，不待雨東來。", "自好摶垂翼，寧勞起死灰。", "楚宮誰第賦，宋玉最多才。"]'),
('9ec9ac6c-2718-42ab-ae25-a77ace925d4a','戊申年七夕五絕  其一','錢惟演','宋','宋诗','song-poetry','','[]','烏鵲飛來接斷雲，祇貪清淺渡星津。',32,'全唐诗/poet.song.4000.json','["烏鵲飛來接斷雲，祇貪清淺渡星津。", "不知一夜支機石，却屬乘槎上漢人。"]'),
('69097d91-24a5-4e07-bb9f-df919980d2ff','戊申年七夕五絕  其二','錢惟演','宋','宋诗','song-poetry','','[]','玉露金河顥氣凉，辛夷車轉桂旗香。',32,'全唐诗/poet.song.4000.json','["玉露金河顥氣凉，辛夷車轉桂旗香。", "嫦娥可是多猜忌，不駐瓊輪放夜長。"]'),
('a4f62ebc-8e7a-4a04-816c-95d323e704d1','戊申年七夕五絕  其三','錢惟演','宋','宋诗','song-poetry','','[]','一歲佳期一夕過，羽旗雲蓋涉微波。',32,'全唐诗/poet.song.4000.json','["一歲佳期一夕過，羽旗雲蓋涉微波。", "明朝若寄相思淚，玉枕金莖得最多。"]'),
('edc73e36-aba1-482b-abe6-5903dc23b71e','戊申年七夕五絕  其四','錢惟演','宋','宋诗','song-poetry','','[]','青鳥當時下紫雲，綺囊書祕露桃新。',32,'全唐诗/poet.song.4000.json','["青鳥當時下紫雲，綺囊書祕露桃新。", "莫嫌夜半移牀遠，朱雀窗中別有人。"]'),
('2a95c93e-820d-4172-8701-04b85151f3f2','戊申年七夕五絕  其五','錢惟演','宋','宋诗','song-poetry','','[]','驪阜凌雲對玉鈎，千門高切絳河秋。',32,'全唐诗/poet.song.4000.json','["驪阜凌雲對玉鈎，千門高切絳河秋。", "欲聞天語猶嫌遠，更結三層乞巧樓。"]'),
('99890128-86ff-43c4-ad7d-8dbc80fbff60','秋夕池上','錢惟演','宋','宋诗','song-poetry','','[]','珪月上金塘，烟容带水光。',48,'全唐诗/poet.song.4000.json','["珪月上金塘，烟容带水光。", "朱華接蘭坂，綠荇溢魚防。", "叢暗禽棲密，林疏露下凉。", "秋懷已潘鬢，無柰更啼螿。"]'),
('80d81af9-210a-4e8d-87aa-9259bb1c4583','謫居漢東撰曲','錢惟演','宋','宋诗','song-poetry','','["\u5b8b\u8bcd\u7cbe\u9009", "\u6625\u5929", "\u9063\u6000", "\u5931\u610f", "\u5a49\u7ea6"]','城上風光鶑語亂，城下煙波春拍岸。',64,'全唐诗/poet.song.4000.json','["城上風光鶑語亂，城下煙波春拍岸。", "綠楊芳草幾時休，淚眼愁腸先已斷。", "情懷漸變成衰晚，鸞鑑朱顔驚暗換。", "昔年多病厭芳樽，今日芳樽惟恐淺。"]'),
('564a04f0-ac93-471a-b128-e48177e72753','賦竹寄李和文公','錢惟演','宋','宋诗','song-poetry','','["\u5199\u7af9", "\u79cb\u5929", "\u5199\u666f"]','瘦玉蕭蕭伊水頭，風宜清夜露宜秋。',32,'全唐诗/poet.song.4000.json','["瘦玉蕭蕭伊水頭，風宜清夜露宜秋。", "更教仙驥傍邊立，盡是人間第一流。"]'),
('e6cee8e5-d203-42a5-a808-02dd0cc38497','珊湖筆格','錢惟演','宋','宋诗','song-poetry','','[]','藴粹滄波遠，搜奇鐵網勞。',72,'全唐诗/poet.song.4000.json','["藴粹滄波遠，搜奇鐵網勞。", "柔條鑽火樹，麗景奪星旄。", "叢倚棲油几，枝疏薦兔毫。", "寶跗光互映，翠匣價相高。", "鉤謾標祥諜，人須詠楚騷。", "休將鐵如意，碎擊爲爭豪。"]'),
('8925ed6e-000d-4f2f-a86a-b87f92ee40ab','以蜀紙端硯寄仙芝','錢惟演','宋','宋诗','song-poetry','','[]','膩繭裁邛部，蒼崖映越溪。',72,'全唐诗/poet.song.4000.json','["膩繭裁邛部，蒼崖映越溪。", "展時雲冉冉，呵久露凄凄。", "平滑逾鵝素，精鋼類褭蹄。", "輕於漢宮縠，碧似夏王圭。", "鈿軸聊閑卷，銀鉤且醉題。", "即時封密詔，別有武都泥。"]'),
('badd6e4b-a76e-41d1-8e85-93207310c942','留題雲門山雍熙院','錢惟演','宋','宋诗','song-poetry','','[]','精舍依巖巘，香林結薜蘿。',48,'全唐诗/poet.song.4000.json','["精舍依巖巘，香林結薜蘿。", "崇臺涵夕靄，危閣架春波。", "浄饌供蒲塞，真詮譯貝多。", "幾時輝晝錦，松下駐鳴珂。"]'),
('9c28871d-06ad-478a-9ab0-7184520ade6f','送高學士知越','錢惟演','宋','宋诗','song-poetry','','[]','粉署爲郎鬢雪侵，酒酣風駛惜分襟。',64,'全唐诗/poet.song.4000.json','["粉署爲郎鬢雪侵，酒酣風駛惜分襟。", "雲迷水館春旗潤，樹繞山城暝角深。", "下擔挂鈎傳密意，渡江桃葉聽遺音。", "孤鶑啼罷芳心歇，倦翼因君憶故林。"]'),
('65cfc138-5fb2-40bd-b49d-a8a2eb6cf760','送張無夢歸天台山','錢惟演','宋','宋诗','song-poetry','','[]','金庭霞標雲半中，巖扉澗戶凌太空。',160,'全唐诗/poet.song.4000.json','["金庭霞標雲半中，巖扉澗戶凌太空。", "飄飄靈氣際浮景，蟬蛻萬物乘高風。", "吾君當天坐環極，物色異人方側席。", "豈因垂釣識羔裘，不假張羅得鳬舄。", "恩深況遇千齡旦，威顔咫尺隆宸盼。", "問政應同牧馬言，臨軒幾動猶龍嘆。", "方瞳玉骨本無羈，馳烟馭氣思東歸。", "江南芳草正無際，林下羣鶑猶亂飛。", "浮丘挹袂去何處，五芝同曉仙露晞。", "人間祕境不可識，千載宸章煥巖壁。"]'),
('38d0db54-35a2-4863-b8c8-3ae209128b1c','送梵才大師歸天台','錢惟演','宋','宋诗','song-poetry','','[]','漢苑辭千柰，仙丘訪五芝。',48,'全唐诗/poet.song.4000.json','["漢苑辭千柰，仙丘訪五芝。", "汲瓶春溜滿，卷裓曉雲滋。", "望剎青龍起，觀濤白馬馳。", "紅樓曾應制，佳句詠朝緌。"]'),
('02e7b74f-d1cf-4341-a085-ffc6cb886c37','送僧歸護國寺  其一','錢惟演','宋','宋诗','song-poetry','','[]','曹溪有真嗣，是名大知識。',192,'全唐诗/poet.song.4000.json','["曹溪有真嗣，是名大知識。", "得法三十年，堂堂坐巖石。", "忽徇雲璽招，暫屈冥鴻翼。", "褰裳度王城，夙駕來軍壁。", "陸泉正持戒，到溉方蔬食。", "晨爐薝蔔霏，夜榻氍毹積。", "金鉢稻脂香，瓊甌茗花碧。", "高談入幽固，默對探虛寂。", "學精西竺言，詩妙南朝格。", "與游欣霧潤，鄙吝猶泉滌。", "遽憶五芝春，悠然理歸策。", "伊予病且老，末景如駒隙。", "慙爲中軍帥，更玷台臣席。", "無功翊熙明，何力當優績。", "蓮社久棲心，華簪聊寄迹。", "願辭食地封，永事彌天釋。"]'),
('e4b8a34b-d8a9-4a5b-9a60-5ac0e4ceff5b','送僧歸護國寺  其二','錢惟演','宋','宋诗','song-poetry','','[]','白道縈回徹上方，薰然風信滿歸航。',64,'全唐诗/poet.song.4000.json','["白道縈回徹上方，薰然風信滿歸航。", "五芝巖秀經行熟，千柰園深宴坐凉。", "吟久半軒移海日，定回諸壑散天香。", "忘年寶契由來厚，終謝繁纓捧鉢囊。"]'),
('f6f45bf9-cec0-46e0-a64b-9cb5da013378','送僧歸天寧萬年禪院','錢惟演','宋','宋诗','song-poetry','','[]','絕巘依滄海，疑君際紫氛。',48,'全唐诗/poet.song.4000.json','["絕巘依滄海，疑君際紫氛。", "巖扉晴落雪，寶地晝生雲。", "浄饌芝房秀，深爐桂葉熏。", "宰官遊未得，空愧北山文。"]'),
('f1379eeb-8965-4c66-85c1-7842fb33f471','護國寺','錢惟演','宋','宋诗','song-poetry','','[]','峻極壓滄溟，清居聚百靈。',48,'全唐诗/poet.song.4000.json','["峻極壓滄溟，清居聚百靈。", "重門深閟邃，絕澗遠湛冥。", "客問無生法，人遊不死庭。", "何當謝簪組，鳥道駕飛軨。"]'),
('a7ba6b18-77b7-44fc-9542-6cd018023c53','懷天台進禪師','錢惟演','宋','宋诗','song-poetry','','[]','默坐理情條，虛齋息衆囂。',48,'全唐诗/poet.song.4000.json','["默坐理情條，虛齋息衆囂。", "寰區指稊米，身世諭芭蕉。", "雨任階生蘚，風嫌樹有瓢。", "惟思白蓮社，他日許相招。"]'),
('f9358ff3-d2e4-45a7-b086-5cafcb9daf72','登師欲東歸因成五言','錢惟演','宋','宋诗','song-poetry','','[]','誰謂元戎幕，今同長者家。',48,'全唐诗/poet.song.4000.json','["誰謂元戎幕，今同長者家。", "一音聞說法，五葉見開花。", "久住生車耳，因閑長道牙。", "方期注金策，休夢赤城霞。"]'),
('85b637d4-8f2d-4781-a391-027b67408a0b','送禪照大師歸越','錢惟演','宋','宋诗','song-poetry','','[]','金剎杳霞扃，南風漾彩舲。',48,'全唐诗/poet.song.4000.json','["金剎杳霞扃，南風漾彩舲。", "吳天六幕遠，越岫萬螺青。", "龍篆霏雕像，鯨濤注浄瓶。", "上方堪逈望，支策見春溟。"]'),
('880a656e-44f9-421b-a832-99368b95657b','雪夕奉陪天台明照禪師擁鑪閑話','錢惟演','宋','宋诗','song-poetry','','[]','藜燭薝香夜幄清，朔風窗際激飛英。',32,'全唐诗/poet.song.4000.json','["藜燭薝香夜幄清，朔風窗際激飛英。", "鳳梨鴟芋煨將熟，坐擁豐貂話赤城。"]'),
('8b4a7e75-5b18-42db-979e-1af6bcc5d298','和司空相公假山','錢惟演','宋','宋诗','song-poetry','','[]','劚得古雲根，蒼蒼蘚痕布。',96,'全唐诗/poet.song.4000.json','["劚得古雲根，蒼蒼蘚痕布。", "叢倚狀峰嵐，霏微起烟素。", "參差衡霍列，巉崒虬龍聚。", "揮扇動林風，飛香暗巖戶。", "誰言盈尺內，自有青霄路。", "相君機務閒，玩此懷真趣。", "興似東山歸，境對曹溪悟。", "美矣仁智心，良哉聖明輔。"]'),
('5fcb14c4-8da3-491f-a9a1-fdfa66d0486e','句  其一','錢惟演','宋','宋诗','song-poetry','','[]','日上故陵烟漠漠，春歸空苑水潺潺。',16,'全唐诗/poet.song.4000.json','["日上故陵烟漠漠，春歸空苑水潺潺。"]'),
('b1ce3963-205b-4ef6-90f4-dc0cc174255a','句  其二','錢惟演','宋','宋诗','song-poetry','','[]','正好睡時行十里，不交談處飲三杯。',16,'全唐诗/poet.song.4000.json','["正好睡時行十里，不交談處飲三杯。"]'),
('9d4ed173-86d2-49ec-b337-9482cce9ccea','句  其三','錢惟演','宋','宋诗','song-poetry','','[]','廳前捉到須依法，合內盛來定付厨。',16,'全唐诗/poet.song.4000.json','["廳前捉到須依法，合內盛來定付厨。"]'),
('e925b251-6c3f-4775-8ec0-817b1d9b43e9','句  其四','錢惟演','宋','宋诗','song-poetry','','[]','雪意未成雲著地，秋聲不斷雁連天。',16,'全唐诗/poet.song.4000.json','["雪意未成雲著地，秋聲不斷雁連天。"]'),
