('cc1895d7-617d-4361-a7f9-074f864a1fe8','石鐘山','李景和','宋','宋诗','song-poetry','','[]','楚地有石鼓，吾地有石鐘。',48,'全唐诗/poet.song.4000.json','["楚地有石鼓，吾地有石鐘。", "鼓不假制作，鐘不費陶鎔。", "朕兆不可測，良由造化工。", "安得置太廟，同聲叶時雍。"]'),
('ffef58d2-77e0-49e6-b3ee-b6b887d6cc74','縱魚','胡從義','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','放汝入長江，養教鱗角出。',24,'全唐诗/poet.song.4000.json','["放汝入長江，養教鱗角出。", "風雲際會時，莫道不相識。"]'),
('3ecc0026-08fd-428d-8f8c-48ffec478364','寄九日山僧','呂言','宋','宋诗','song-poetry','','[]','目極閩南道，雲山隔幾層。',48,'全唐诗/poet.song.4000.json','["目極閩南道，雲山隔幾層。", "深秋城外寺，白日定中僧。", "野蔓穿松甲，幽泉漱石稜。", "遥思茶話夕，敲碎玉池冰。"]'),
('00bbae05-559a-440f-950e-103759e7159e','留題霍山應聖公廟','陳綱','宋','宋诗','song-poetry','','[]','峻極巍峨勢望雄，層巒疊嶂翠重重。',128,'全唐诗/poet.song.4000.json','["峻極巍峨勢望雄，層巒疊嶂翠重重。", "爲神有感興唐祚，作鎮無疆福晉封。", "材産十州資構厦，泉分數邑潤耕農。", "幽巖舊榻高人隠，絕頂遺墳古帝蹤。", "欲雨片雲生峭壁，未明先日照危峰。", "斷崖當午晴雷震，深壑經秋積靄濃。", "樵去每逢游洞鹿，僧禪時見戲潭龍。", "名光祀典傳千載，仰祝牲牢致享恭。"]'),
('99e6c877-4925-4c1d-b974-1aca583ec89f','送鈐轄館使王公','李畋','宋','宋诗','song-poetry','','[]','郄縠詩書奕世傳，西人歌德別戎旃。',64,'全唐诗/poet.song.4000.json','["郄縠詩書奕世傳，西人歌德別戎旃。", "三朝功業標勳府，四稔恩綏播蜀川。", "耦射隔花聞破帖，分題臨沼間中筵。", "歸朝聖旨俞僉望，畿內封侯養重權。"]'),
('29529d2c-ed73-49a8-9353-417bb8729d19','句  其一','李畋','宋','宋诗','song-poetry','','[]','紅沽村落酒，肥鱠海鄉魚。',12,'全唐诗/poet.song.4000.json','["紅沽村落酒，肥鱠海鄉魚。"]'),
('acfbb797-da08-4db2-9f7a-02815028cb71','句  其二','李畋','宋','宋诗','song-poetry','','[]','沃心甘蔗冷，燒眼刺桐繁。',12,'全唐诗/poet.song.4000.json','["沃心甘蔗冷，燒眼刺桐繁。"]'),
('bed3af17-4add-44df-a85d-ed4b28e69039','句  其三','李畋','宋','宋诗','song-poetry','','[]','銀山雲出海，練水澗分岡。',12,'全唐诗/poet.song.4000.json','["銀山雲出海，練水澗分岡。"]'),
('23f32a1f-30a4-4289-9386-e5be2013105d','漢武','任隨','宋','宋诗','song-poetry','','[]','殊庭深恨隔仙曹，桂館蜚廉事轉勞。',64,'全唐诗/poet.song.4000.json','["殊庭深恨隔仙曹，桂館蜚廉事轉勞。", "銀闕尚沈滄海闊，井幹空拂絳河高。", "萯陽弋獵侵多稼，朔塞旌旗照不毛。", "苦信凴虛王母說，東方三度竊蟠桃。"]'),
('45d38c27-25e2-4240-972f-60e1949e3214','鶴','任隨','宋','宋诗','song-poetry','','[]','何年玉羽別崑丘，飛舞長親十二樓。',64,'全唐诗/poet.song.4000.json','["何年玉羽別崑丘，飛舞長親十二樓。", "警露夜窺瑶圃月，翔雲高憶海天秋。", "肯教渠略知遐壽，會向神區更遠遊。", "正是溶溪煙水碧，好陪青鳳飲澄流。"]'),
('fd48c5fb-417c-4ce9-81d6-160ffb5bfdbf','舊將','任隨','宋','宋诗','song-poetry','','[]','幾年塵虜復征蠻，分閫功成兩鬢斑。',64,'全唐诗/poet.song.4000.json','["幾年塵虜復征蠻，分閫功成兩鬢斑。", "新畫儀形當漢閣，舊銘勳業在燕山。", "龍泉照步文犀澁，馬埒堆金駿足閒。", "時泰無因問充國，曉窗風雪夢陽關。"]'),
('de53f7be-e9bd-4e04-9ae9-6f0bdc93953b','句','張孝和','宋','宋诗','song-poetry','','[]','我是夢中傳彩筆，欲書花葉寄朝雲。',16,'全唐诗/poet.song.4000.json','["我是夢中傳彩筆，欲書花葉寄朝雲。"]'),
('d7f2b910-c197-4a0d-bcf7-1fcbd82c8b85','送新知永州陳祕丞瞻赴任','洪湛','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','零陵古郡枕湘川，太守南歸得意年。',64,'全唐诗/poet.song.4000.json','["零陵古郡枕湘川，太守南歸得意年。", "茶味欲過衡嶽寺，橘香先上洞庭船。", "錦衣照耀維桑地，石燕翻飛欲雨天。", "若到浯溪須艤棹，次山遺頌想依然。"]'),
('51f97579-54b0-46b1-a024-ed978f980fcc','寄陳希夷','洪湛','宋','宋诗','song-poetry','','[]','華山高萬丈，蓮峰映初日。',60,'全唐诗/poet.song.4000.json','["華山高萬丈，蓮峰映初日。", "中有希夷子，默坐養神謐。", "芝朮無外求，巢由乃共匹。", "形跡任化遷，元樞守貞一。", "望岫羣息心，清談詎能悉。"]'),
('fd3ba7ea-d97d-4b64-a5f5-273b30cfb45c','寒食值雨','梁顥','宋','宋诗','song-poetry','','[]','春波微綠草連門，寒食煙光可斷魂。',32,'全唐诗/poet.song.4000.json','["春波微綠草連門，寒食煙光可斷魂。", "細雨隔簾煙火滅，落花風動欲黄昏。"]'),
('c855ab3f-7f1f-4573-b4ed-19d6e590c41d','寒食寓懷','梁顥','宋','宋诗','song-poetry','','[]','明日一百五，春風餘幾何。',48,'全唐诗/poet.song.4000.json','["明日一百五，春風餘幾何。", "愁隨新火出，病憶故人多。", "草色牆陰合，花香宿雨和。", "耿懷殊不寐，終夕扣壺歌。"]'),
('b1f84dde-f1b1-4b4e-9035-b675543accdb','贈淳于公歸養','梁顥','宋','宋诗','song-poetry','','[]','懇辭浮宦振家聲，懸憶高堂指去程。',64,'全唐诗/poet.song.4000.json','["懇辭浮宦振家聲，懸憶高堂指去程。", "選籍便通閨籍美，綵衣兼映錦衣榮。", "推恩半俸供甘旨，守道全家試滿盈。", "我恨無親可歸養，與君言別若爲情。"]'),
('44280ff6-93a3-4e16-966d-636a57b93734','厭氣臺','梁顥','宋','宋诗','song-poetry','','[]','天生王氣何能厭，嬴氏空勞築此臺。',32,'全唐诗/poet.song.4000.json','["天生王氣何能厭，嬴氏空勞築此臺。", "今日我來臺上看，殘春寂寞野花開。"]'),
('0267b38d-a233-4ff5-bb10-7bb50d09a5fe','存目','梁顥','宋','宋诗','song-poetry','','[]','詩題：謝恩詩詩句：天福三年來應舉，熙雍二載始成名。',73,'全唐诗/poet.song.4000.json','["詩題：謝恩詩詩句：天福三年來應舉，熙雍二載始成名。", "饒他白髮巾中滿，且喜青雲足下生。", "觀榜更無朋輩在，歸家惟有子孫迎。", "也知年少登科好，爭奈龍頭屬老成。"]'),
('227da2ac-0d67-42e0-954d-b9615c70ab56','劍門關','姜遵','宋','宋诗','song-poetry','','[]','極目雙峰劍倚天，重門因設據高山。',32,'全唐诗/poet.song.4000.json','["極目雙峰劍倚天，重門因設據高山。", "城隍盡枕溪巖畔，井邑全居水石間。"]'),
('e0422be0-91ec-4f17-982c-12bb44b8fe94','答子','王曙','宋','宋诗','song-poetry','','[]','疏家子歎揮金後，禦寇妻悲遺粟回。',32,'全唐诗/poet.song.4000.json','["疏家子歎揮金後，禦寇妻悲遺粟回。", "爭似吾兒知止足，陶廬容膝早歸來。"]'),
('097c10e3-dc27-4210-beee-5e6eefb067eb','回峰院留題','王曙','宋','宋诗','song-poetry','','[]','山勢欲壓海，禪扃向此開。',48,'全唐诗/poet.song.4000.json','["山勢欲壓海，禪扃向此開。", "魚龍腥不到，日月影先來。", "樹色秋擎出，鐘聲浪答回。", "何期隨吏役，暫得拂塵埃。"]'),
('c9cfa163-b1e0-40cc-899b-8d15eb98f944','詩一首','王曙','宋','宋诗','song-poetry','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u6292\u6000", "\u82b1", "\u5199\u82b1"]','棗花至小能成實，桑葉惟柔解吐絲。',32,'全唐诗/poet.song.4000.json','["棗花至小能成實，桑葉惟柔解吐絲。", "堪笑牡丹如斗大，不成一事只空枝。"]'),
('c7d5ade0-0104-4b3d-a65a-409c85f22fbb','詩一首','王曙','宋','宋诗','song-poetry','','[]','鑿龍蒼翠照□川，白鳥平蕪暮雨閒。',32,'全唐诗/poet.song.4000.json','["鑿龍蒼翠照□川，白鳥平蕪暮雨閒。", "一夕塵襟清似水，潺湲聲裏□□□。"]'),
('04854867-b20c-47ee-ab85-81b112dd2385','偶□','王曙','宋','宋诗','song-poetry','','[]','□倚蒼崖次第開，暫停征傳一徘徊。',32,'全唐诗/poet.song.4000.json','["□倚蒼崖次第開，暫停征傳一徘徊。", "人間萬事皆如此，偶爾□勝特地來。"]'),
('327eae3f-3351-47ca-bbd9-732ab08689d8','句','王曙','宋','宋诗','song-poetry','','[]','千山送客東西路，一樹照人南北枝。',16,'全唐诗/poet.song.4000.json','["千山送客東西路，一樹照人南北枝。"]'),
('66782c4f-72d4-4181-96aa-d549089fef5a','別方巖','胡則','宋','宋诗','song-poetry','','[]','寓居峰頂寺，不覺度炎天。',144,'全唐诗/poet.song.4000.json','["寓居峰頂寺，不覺度炎天。", "山叟頻爲約，林僧每出禪。", "虛懷思往事，宴坐息諸緣。", "照像龕鐙暗，通宵磬韻傳。", "宴心資寂寞，琢句極幽玄。", "拾菌寒雲外，烹茶翠竹前。", "遠陰臨岳樹，清響落巖泉。", "僻道無來客，深秋足亂蟬。", "松風生井浪，溪雨長苔錢。", "自省浮塵世，終難住永年。", "徧遊曾宛轉，欲別重留連。", "明日東西路，依依獨黯然。"]'),
('7fee2d27-e254-4760-b112-eb34dc672690','及第','胡則','宋','宋诗','song-poetry','','[]','金榜名傳四海知，太平時合稱男兒。',64,'全唐诗/poet.song.4000.json','["金榜名傳四海知，太平時合稱男兒。", "五言似劍裁鱗角，七字如刀斫桂枝。", "御苑得題朝帝日，家鄉佩印拜親時。", "小花橋畔人人愛，一带清風雨露隨。"]'),
('4dfe127a-c896-45ae-b09e-9e73701bff38','題紫霄觀','胡則','宋','宋诗','song-poetry','','[]','綺霞重疊武陵溪，溪嶺相逢路不迷。',64,'全唐诗/poet.song.4000.json','["綺霞重疊武陵溪，溪嶺相逢路不迷。", "白石洞天人不到，碧桃花下馬頻嘶。", "深傾玉液琴聲細，旋煮胡麻月色低。", "猶恨此身閒未得，好同劉阮灌芝畦。"]'),
('8b10f738-f991-4d21-b5f0-1da9a3a231cd','酬和二章拜呈慈雲大師伏惟採覽 和桂子','胡則','宋','宋诗','song-poetry','','[]','孤峰聳高桂，千載同一日。',96,'全唐诗/poet.song.4000.json','["孤峰聳高桂，千載同一日。", "秋氣正飛霜，天風落丹實。", "紛紛寶砌傍，顆顆露珠密。", "始自月中來，又從驪頷出。", "香浮古佛剎，光照高僧室。", "吳越饒珍異，金玉非儔匹。", "嘗詠賢人詩，未載史臣筆。", "至矣天竺山，山靈誕奇物。"]'),
('a85c0cc8-588d-44ef-88a4-9f6113570761','酬和二章拜呈慈雲大師伏惟採覽 和種桂','胡則','宋','宋诗','song-poetry','','[]','纍纍丹桂子，秋落古禪關。',48,'全唐诗/poet.song.4000.json','["纍纍丹桂子，秋落古禪關。", "乍到圓蟾窟，潜依靈鷲山。", "始知塵外有，會向月中攀。", "千載孤峰上，清陰與客閒。"]'),
('df2f94d8-9cef-461c-b8db-d11c0544f2f4','奏免衢婺丁錢','胡則','宋','宋诗','song-poetry','','[]','六十年來見弊由，仰蒙龍勅降南州。',64,'全唐诗/poet.song.4000.json','["六十年來見弊由，仰蒙龍勅降南州。", "丁錢永免無拘束，苗米常宜有限收。", "青嶂瀑泉呼萬歲，碧天星月照千秋。", "臣今未恨生身晚，長喜王民紹見休。"]'),
('4ca19974-eac6-43be-a2f1-58a8968fa11c','題嚴子陵祠堂','胡則','宋','宋诗','song-poetry','','[]','占斷烟波七里灘，漁簑輕拂漢衣冠。',64,'全唐诗/poet.song.4000.json','["占斷烟波七里灘，漁簑輕拂漢衣冠。", "高蹤磨出雲涯碧，清節照開秋水寒。", "澤國幾家供廟食，客星千載落雲墩。", "我來亦有沙洲興，願借先生舊釣竿。"]'),
('e9937384-848a-447b-92ee-b139c45c00bc','存目  其一','胡則','宋','宋诗','song-poetry','','[]','詩題：水村首句：畫橈兩兩枕汀沙。',16,'全唐诗/poet.song.4000.json','["詩題：水村首句：畫橈兩兩枕汀沙。"]'),
('fb2c4f1d-07d6-4386-94c0-28457446c9a7','存目  其二','胡則','宋','宋诗','song-poetry','','[]','詩題：夜坐聞竹聲示姪首句：室明窗有燈。',19,'全唐诗/poet.song.4000.json','["詩題：夜坐聞竹聲示姪首句：室明窗有燈。"]'),
('f8fe2cce-e15a-47ca-b2b7-42974eb5d3bc','吳江','陳堯佐','宋','宋诗','song-poetry','','[]','平波渺渺烟蒼蒼，菰蒲纔熟楊柳黄。',32,'全唐诗/poet.song.4000.json','["平波渺渺烟蒼蒼，菰蒲纔熟楊柳黄。", "扁舟繫岸不忍去，秋風斜日鱸魚鄉。"]'),
('dc36b4e9-ae6b-4087-9048-356c943601f8','湖州碧瀾堂','陳堯佐','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','苕溪清淺霅溪斜，碧玉光寒照萬家。',32,'全唐诗/poet.song.4000.json','["苕溪清淺霅溪斜，碧玉光寒照萬家。", "誰向月明終夜聽，洞庭漁笛隔蘆花。"]'),
('72b22d3e-d22a-40c1-81f2-7753d056bfec','題朝元閣','陳堯佐','宋','宋诗','song-poetry','','[]','朝元高閣迥，秋毫無隠情。',24,'全唐诗/poet.song.4000.json','["朝元高閣迥，秋毫無隠情。", "浮雲忽以蔽，不見漁陽城。"]'),
('9f6060cd-7c74-4a04-bae8-7b560baafde9','古寺偈','陳堯佐','宋','宋诗','song-poetry','','[]','殿古寒爐空，流塵暗金碧。',24,'全唐诗/poet.song.4000.json','["殿古寒爐空，流塵暗金碧。", "獨坐偶無人，又得真消息。"]'),
('1383add0-f5d8-4a74-b76a-5a6e5572ca87','答張順之','陳堯佐','宋','宋诗','song-poetry','','[]','有花無酒頭慵舉，有酒無花眼倦開。',32,'全唐诗/poet.song.4000.json','["有花無酒頭慵舉，有酒無花眼倦開。", "正向西窗念蕭索，洛陽花酒一時來。"]'),
('0b2b1a9a-8b70-438f-b1a0-abb8d90c9532','題華清宮','陳堯佐','宋','宋诗','song-poetry','','[]','百首新詩百意精，不尤妃子只尤兵。',32,'全唐诗/poet.song.4000.json','["百首新詩百意精，不尤妃子只尤兵。", "爭如一句傷時事，只爲明皇恃太平。"]'),
('d619562d-99e7-4bb4-aa6a-31d57b656a8f','江潮阻風','陳堯佐','宋','宋诗','song-poetry','','[]','按部谿山接海濤，連天風雨泊輕舠。',32,'全唐诗/poet.song.4000.json','["按部谿山接海濤，連天風雨泊輕舠。", "滄溟未必全勝我，潮落潮生亦自勞。"]'),
('7d10d683-0440-44cd-b24e-4052eb71b8b9','題上虞蘭芎山','陳堯佐','宋','宋诗','song-poetry','','[]','巖巖一峰千萬尋，微茫樓閣寒雲深。',32,'全唐诗/poet.song.4000.json','["巖巖一峰千萬尋，微茫樓閣寒雲深。", "巡州佐吏倚欄久，泠泠天籟清塵心。"]'),
('30845248-9359-483f-a012-c548436a8eaa','憶越州  其一','陳堯佐','宋','宋诗','song-poetry','','[]','越絕谿山第一州，畫圖城郭幾淹留。',32,'全唐诗/poet.song.4000.json','["越絕谿山第一州，畫圖城郭幾淹留。", "閒思禹廟斜迴首，髣髴雲端見郡樓。"]'),
('0151037e-4e7d-49c6-9588-6de3f81f9fb1','憶越州  其二','陳堯佐','宋','宋诗','song-poetry','','[]','稽峰倚雲千仞高，澄湖倒影分秋毫。',32,'全唐诗/poet.song.4000.json','["稽峰倚雲千仞高，澄湖倒影分秋毫。", "當年逸賞有餘意，徘徊不忍移輕舠。"]'),
('5cf5c0c7-d600-4062-b556-f8e3dbc9852f','憶越州  其三','陳堯佐','宋','宋诗','song-poetry','','[]','抽毫欲賦東南奇，雲山好景慙有遺。',32,'全唐诗/poet.song.4000.json','["抽毫欲賦東南奇，雲山好景慙有遺。", "平波蕩漾照湖淥，扁舟憶得遊春時。"]'),
('c005e744-0670-44e9-83c9-1020618ce470','唐施肩吾山居有感','陳堯佐','宋','宋诗','song-poetry','','[]','幽居正想餐霞客，夜久月寒珠露滴。',32,'全唐诗/poet.song.4000.json','["幽居正想餐霞客，夜久月寒珠露滴。", "千年獨鶴兩三聲，飛下巖前一枝柏。"]'),
('d4e1c709-01d3-4f07-b8d9-93f9ca338ecc','虎丘  其一','陳堯佐','宋','宋诗','song-poetry','','[]','雲際樓臺樹杪軒，孤松千尺聳平田。',32,'全唐诗/poet.song.4000.json','["雲際樓臺樹杪軒，孤松千尺聳平田。", "危欄遠思微吟好，隠隠秋帆半入天。"]'),
('a64b4c74-99a8-41d4-9e10-57a36c39a742','虎丘  其二','陳堯佐','宋','宋诗','song-poetry','','[]','人間靈蹟徧曾遊，祇欠吳門訪虎丘。',32,'全唐诗/poet.song.4000.json','["人間靈蹟徧曾遊，祇欠吳門訪虎丘。", "今日偶來無限感，闔閭墳左劍池頭。"]'),
('7259f684-30eb-4137-856e-f6b8d783063c','國清寺','陳堯佐','宋','宋诗','song-poetry','','[]','南越第一寺，偶來心地真。',24,'全唐诗/poet.song.4000.json','["南越第一寺，偶來心地真。", "却嫌橋下水，流去入紅塵。"]'),
('d998baa7-cb83-442e-9ce9-21eb07cdf135','寄洪州楊太博','陳堯佐','宋','宋诗','song-poetry','','[]','南昌爲郡好，樓閣枕江湄。',48,'全唐诗/poet.song.4000.json','["南昌爲郡好，樓閣枕江湄。", "地暖春生早，山寒日下遲。", "訟庭唯鶴立，吟樹獨僧期。", "安得通官政，烟霞共一司。"]'),
('1a536b16-e7fb-4f92-b98e-dd047d987830','送潮陽李孜主簿','陳堯佐','宋','宋诗','song-poetry','','[]','潮陽山水東南奇，魚鹽城郭民熙熙。',32,'全唐诗/poet.song.4000.json','["潮陽山水東南奇，魚鹽城郭民熙熙。", "當時爲撰玄聖碑，而今風俗鄒魯爲。"]'),
('b8bfec09-a7bb-4ba5-a4f1-4764e7e5d4bc','寄題漳浦縣齋','陳堯佐','宋','宋诗','song-poetry','','[]','漳浦從來瘴癘深，潮陽南去更難禁。',32,'全唐诗/poet.song.4000.json','["漳浦從來瘴癘深，潮陽南去更難禁。", "當時三載曾無事，不放閑愁入寸心。"]'),
('e14c5f17-1130-4e01-a2c9-c5b32886fbbe','送王生及第歸潮陽','陳堯佐','宋','宋诗','song-poetry','','[]','休嗟城邑住天荒，已是仙枝耀故鄉。',32,'全唐诗/poet.song.4000.json','["休嗟城邑住天荒，已是仙枝耀故鄉。", "從此方輿載人物，海邊鄒魯是潮陽。"]'),
('30e9a748-f778-44a8-8108-77206c4a9551','題漳浦縣壁','陳堯佐','宋','宋诗','song-poetry','','[]','蠻烟漁火接鯨波，樹樹花枝處處歌。',32,'全唐诗/poet.song.4000.json','["蠻烟漁火接鯨波，樹樹花枝處處歌。", "況是天涯好行樂，莫教憔悴鬢霜多。"]'),
('e57dda17-e2b6-4ca5-aae7-a43ff09d6a62','遊永明寺','陳堯佐','宋','宋诗','song-poetry','','[]','附郭山光峭若烟，倚空樓殿白雲巔。',96,'全唐诗/poet.song.4000.json','["附郭山光峭若烟，倚空樓殿白雲巔。", "孤軒半出青松杪，顥氣疑遊碧漢邊。", "惜別擬留風外燕，傷秋因感雨中蟬。", "人家掩映藏魚浦，島樹扶疏沒水天。", "痛飲豈同蓮社客，狂歌聊許竹林賢。", "忘形且盡尊前樂，休憶樓巖與濟川。"]'),
('3db96b58-677a-4fbf-a7d0-f8515f8782a2','吳王墓','陳堯佐','宋','宋诗','song-poetry','','[]','惜哉吳王墓，秦帝欲開破。',48,'全唐诗/poet.song.4000.json','["惜哉吳王墓，秦帝欲開破。", "應笑埋金玉，千年賈餘禍。", "不特虎跡銷，已聞鮑車過。", "又是驪山頭，炎炎三月火。"]'),
('5374314a-b875-4d16-98ed-47f0e24e32c3','林處士水亭','陳堯佐','宋','宋诗','song-poetry','','[]','城外逋翁宅，開亭野水寒。',96,'全唐诗/poet.song.4000.json','["城外逋翁宅，開亭野水寒。", "冷光浮荇葉，靜影浸魚竿。", "吠犬時迎客，饑禽忽上闌。", "疏籬僧舍近，嘉樹鶴庭寬。", "拂砌烟絲裊，侵窗筍戟攢。", "小橋橫落日，幽徑轉層巒。", "好景吟何極，清歡盡亦難。", "憐君留我意，重疊取琴彈。"]'),
('9117afba-63b8-4769-a661-a4517d5dc176','遊湖上昭慶寺','陳堯佐','宋','宋诗','song-poetry','','[]','湖邊山影裏，靜景與僧分。',48,'全唐诗/poet.song.4000.json','["湖邊山影裏，靜景與僧分。", "一榻坐臨水，片心閑對雲。", "樹寒時落葉，鷗散忽成羣。", "莫問紅塵事，林間肯暫聞。"]'),
('d1e342c7-d8f4-4aa5-a686-abfd38c997af','洞霄宮  其一','陳堯佐','宋','宋诗','song-poetry','','[]','一帆高挂出紅塵，萬仞長歌入紫雲。',32,'全唐诗/poet.song.4000.json','["一帆高挂出紅塵，萬仞長歌入紫雲。", "莫道遊仙別無侶，玉清冠蓋許同羣。"]'),
('85dfc18b-fc88-43b6-ba14-20a2cd580c32','洞霄宮  其二','陳堯佐','宋','宋诗','song-poetry','','[]','谷口停驂上翠微，五雲宮殿闢金扉。',32,'全唐诗/poet.song.4000.json','["谷口停驂上翠微，五雲宮殿闢金扉。", "不知何處朝元會，却見龍鸞隊仗歸。"]'),
('5b5b4b58-b8f7-47f9-be69-11c4544c0b06','洞霄宮  其三','陳堯佐','宋','宋诗','song-poetry','','[]','二天封部稼如雲，流水清寒出洞門。',32,'全唐诗/poet.song.4000.json','["二天封部稼如雲，流水清寒出洞門。", "更愛林間盤石上，松花飄落羽人樽。"]'),
('b0ffff53-6141-44f1-ae0f-b287fa039edb','洞霄宮  其四','陳堯佐','宋','宋诗','song-poetry','','[]','蕭蕭紅樹碧峰前，爲愛桃花入洞天。',32,'全唐诗/poet.song.4000.json','["蕭蕭紅樹碧峰前，爲愛桃花入洞天。", "偶逐霓旌纔百步，却憂人世已經年。"]'),
('019517a1-28b1-4bff-b5d4-3a48d2b48e71','懷杭州西湖','陳堯佐','宋','宋诗','song-poetry','','["\u897f\u6e56"]','橋影飛虹跨碧潭，熙熙亭畔柳毿毿。',32,'全唐诗/poet.song.4000.json','["橋影飛虹跨碧潭，熙熙亭畔柳毿毿。", "扁舟載酒漁翁唱，記得閑過處士庵。"]'),
('60ccd1f5-8d6a-4f09-b89b-dc48886fd13b','赴潮陽倅  其一','陳堯佐','宋','宋诗','song-poetry','','[]','沉醉猶難別帝州，滿城春色重淹留。',32,'全唐诗/poet.song.4000.json','["沉醉猶難別帝州，滿城春色重淹留。", "公閑預想消魂處，望闕頻登海上樓。"]'),
('91290019-259c-4ee3-80b7-f495fb74dda6','赴潮陽倅  其二','陳堯佐','宋','宋诗','song-poetry','','[]','休把空言較短長，算來齊物也無妨。',32,'全唐诗/poet.song.4000.json','["休把空言較短長，算來齊物也無妨。", "蠻民解唱昇平曲，願領閑愁入醉鄉。"]'),
('b9f576e7-6568-4792-bbc1-ffbe4da47150','潮陽作  其一','陳堯佐','宋','宋诗','song-poetry','','[]','景淡花初落，寒生海上潮。',24,'全唐诗/poet.song.4000.json','["景淡花初落，寒生海上潮。", "門前歸北路，微雨柳垂條。"]'),
('31631fe3-71d5-40b7-871d-7194becd4a6f','潮陽作  其二','陳堯佐','宋','宋诗','song-poetry','','[]','靜院鶑啼竹，幽闌蝶在花。',24,'全唐诗/poet.song.4000.json','["靜院鶑啼竹，幽闌蝶在花。", "登臨轉惆悵，斜日兩三家。"]'),
('79493a6d-29b4-479b-b90f-aae248ba0775','遊惠陽西湖','陳堯佐','宋','宋诗','song-poetry','','["\u897f\u6e56"]','附郭水連山，公餘獨往還。',48,'全唐诗/poet.song.4000.json','["附郭水連山，公餘獨往還。", "疏煙魚艇遠，斜日寺樓閑。", "繫馬芭蕉外，移舟菡萏間。", "天涯逢此景，誰信自開顔。"]'),
('cfbad9aa-f9ea-4567-89e4-dd0669ad58fb','遊鳳棲寺','陳堯佐','宋','宋诗','song-poetry','','[]','十里水煙迷，禪居偶杖藜。',48,'全唐诗/poet.song.4000.json','["十里水煙迷，禪居偶杖藜。", "地靈人不老，山好鳳曾棲。", "暑氣消將盡，苔痕長欲齊。", "松間何所得，泉石兩三題。"]'),
('68d6e438-dd2b-4faf-9a51-e36507844890','歸闕感懷','陳堯佐','宋','宋诗','song-poetry','','[]','望闕二年餘，中宵夢玉除。',48,'全唐诗/poet.song.4000.json','["望闕二年餘，中宵夢玉除。", "忽聞天上詔，乍厭海邊居。", "歸路尋芳草，空囊載舊書。", "君恩何以報，零淚落塵裾。"]'),
('d4fe066c-6d53-421d-919a-505ea58e82b3','憶潮陽','陳堯佐','宋','宋诗','song-poetry','','[]','東西樓閣與雲齊，天際孤煙認惡溪。',32,'全唐诗/poet.song.4000.json','["東西樓閣與雲齊，天際孤煙認惡溪。", "記得幽人舊吟處，獨遊亭在野橋西。"]'),
('297fd674-3bf7-4d76-a0f8-27293b78b62c','寄潮州于公九流','陳堯佐','宋','宋诗','song-poetry','','[]','扁舟如葉路東西，一片灘聲下惡溪。',32,'全唐诗/poet.song.4000.json','["扁舟如葉路東西，一片灘聲下惡溪。", "當日亭臺舊時客，相逢莫惜醉如泥。"]'),
('f0a78b66-c31a-4b85-a6d8-96685a23ad5f','寄書上人','陳堯佐','宋','宋诗','song-poetry','','[]','階前春色長苔斑，避俗常聞晝掩關。',64,'全唐诗/poet.song.4000.json','["階前春色長苔斑，避俗常聞晝掩關。", "一榻琴書雙闕寺，片心泉石二林山。", "江樓把酒雲供望，松院支筇鶴對閑。", "誰向風騷爲消息，此身元在寂寥間。"]'),
('6ee6cbaf-8887-4b3a-87b3-294a2fd1d736','閑步過芳菲園','陳堯佐','宋','宋诗','song-poetry','','[]','盡日芳菲園，不見芳菲好。',24,'全唐诗/poet.song.4000.json','["盡日芳菲園，不見芳菲好。", "茂草與斜陽，脈脈情多少。"]'),
('92c5e533-ca14-41ea-aaee-a6a92023e951','三城侍郎寄示留題延慶寺二韻詩二章頃歲予肄業於此遺景盡在幸會之迹首唱之序詳矣謹依命攀和但於首章增爲四韻蓋淺陋之才不覺辭費因遣稚子贊善大夫通判邠州事學古寫於此牌以永嘉賜  其一','陳堯佐','宋','宋诗','song-poetry','','[]','清濟園林接寺隅，水昏煙暝自成圖。',64,'全唐诗/poet.song.4000.json','["清濟園林接寺隅，水昏煙暝自成圖。", "當年棣鄂三冬學，今日鴒原萬里途。", "道契風雲多感激，人非豐沛欠訏謨。", "聞君又枉行春騎，應笑溪邊舊截蒲。"]'),
('286a35d7-cc80-4eb1-9dd6-ae53b39d22a3','三城侍郎寄示留題延慶寺二韻詩二章頃歲予肄業於此遺景盡在幸會之迹首唱之序詳矣謹依命攀和但於首章增爲四韻蓋淺陋之才不覺辭費因遣稚子贊善大夫通判邠州事學古寫於此牌以永嘉賜  其二','陳堯佐','宋','宋诗','song-poetry','','[]','螢窗從此極研覃，墜簡疑文訪濟南。',32,'全唐诗/poet.song.4000.json','["螢窗從此極研覃，墜簡疑文訪濟南。", "擬卜菟裘鄰學所，龍香時爇御書龕。"]'),
('ac97ab37-8e0b-4311-8fd8-97a3f8d11307','望越亭','陳堯佐','宋','宋诗','song-poetry','','[]','颯颯西風葉葉秋，誰家烟火起滄洲。',32,'全唐诗/poet.song.4000.json','["颯颯西風葉葉秋，誰家烟火起滄洲。", "乘閑不耐無機性，擬勸漁翁直釣鈎。"]'),
('de8346b7-a7c2-470c-8656-460f9fa50d02','知果教寺','陳堯佐','宋','宋诗','song-poetry','','[]','蘿巖山下寺，靜境絕過從。',48,'全唐诗/poet.song.4000.json','["蘿巖山下寺，靜境絕過從。", "芳草二三月，碧雲千萬峰。", "窗虛明落日，樓迥響疏鐘。", "恰恐重來晚，庭前記偃松。"]'),
('fe7236af-2ae1-431a-ac7a-c51f203abcc6','張公洞','陳堯佐','宋','宋诗','song-poetry','','[]','空山杳杳鸞鳳飛，神仙門戶開翠微。',32,'全唐诗/poet.song.4000.json','["空山杳杳鸞鳳飛，神仙門戶開翠微。", "主人白髮雲滿衣，松間留我談玄機。"]'),
('c3d9e447-535f-4495-9647-b55e163549a8','野吏亭','陳堯佐','宋','宋诗','song-poetry','','[]','野吏厭公堂，開軒出郡牆。',120,'全唐诗/poet.song.4000.json','["野吏厭公堂，開軒出郡牆。", "殘花炎帝圃，斜日尉佗鄉。", "疊巘分諸粵，重城截大荒。", "耕桑蠻聚落，烟火漢封疆。", "雲勢飄蓬島，天形壓夜郎。", "扁舟閑得侶，嘉樹遠成行。", "梅雨千林暮，春風百草香。", "人家浮浩淼，鳥道沒青蒼。", "爽塏吟魂健，虛明夏景凉。", "他年重回首，牢落愧甘棠。"]'),
('677bdffc-9eea-4f03-8710-24d9344ad616','天聖間入參大政復寄題二章  其一','陳堯佐','宋','宋诗','song-poetry','','[]','羅浮山下郡，樓閣枕滄溟。',24,'全唐诗/poet.song.4000.json','["羅浮山下郡，樓閣枕滄溟。", "誰得閑中意，清風野吏亭。"]'),
('dd840153-58a9-4f54-90cb-121e03c73840','天聖間入參大政復寄題二章  其二','陳堯佐','宋','宋诗','song-poetry','','[]','山好曾留句，城高復創亭。',24,'全唐诗/poet.song.4000.json','["山好曾留句，城高復創亭。", "登臨千萬境，誰與畫爲屏。"]'),
('e1a6cfda-9af6-426c-a8e3-d02ad2f4e905','鄭州浮波亭','陳堯佐','宋','宋诗','song-poetry','','[]','碧玉波光四面寒，虛空簷宇出林端。',32,'全唐诗/poet.song.4000.json','["碧玉波光四面寒，虛空簷宇出林端。", "塵埃未到交游絕，遶座扁舟與釣竿。"]'),
