('bf5a17d8-3689-4e09-a33c-cb437af3da1f','普濟院','陳堯咨','宋','宋诗','song-poetry','','[]','山遠峰峰碧，林疏葉葉紅。',24,'全唐诗/poet.song.4000.json','["山遠峰峰碧，林疏葉葉紅。", "憑闌對僧語，如在畫圖中。"]'),
('3fd85919-f25a-453a-ad6a-70c4c1c18256','施肩吾宅','陳堯咨','宋','宋诗','song-poetry','','[]','幽居正想滄霞客，夜久月寒珠露滴。',32,'全唐诗/poet.song.4000.json','["幽居正想滄霞客，夜久月寒珠露滴。", "千年獨鶴兩三聲，飛下巖前一株柏。"]'),
('16f62ee1-b989-4e63-ab57-153ef576b07d','題三桂亭','陳堯咨','宋','宋诗','song-poetry','','[]','不誇六印滿腰懸，二頃仍尋負郭田。',64,'全唐诗/poet.song.4000.json','["不誇六印滿腰懸，二頃仍尋負郭田。", "當日弟兄皆刷羽，如今鴻雁盡摩天。", "扶疏已問新栽柳，清淺猶尋舊漱泉。", "大尹今來還又去，夕陽旌旆復翩翩。"]'),
('17a6a2b1-35f4-48e7-8e6d-3e88d31df79a','草堂寺詩','陳堯咨','宋','宋诗','song-poetry','','[]','□□□跡□禪關，□殿清虛檜影間。',64,'全唐诗/poet.song.4000.json','["□□□跡□禪關，□殿清虛檜影間。", "客□□臨來此境，僧□興廢指前山。", "醉聞溪溜吟懷□，坐對嵐峰世慮閑。", "他日功成重遊賞，煙霞風物異塵寰。"]'),
('c68671bb-e369-4709-8b0e-cd131cd8ce54','華清宮','楊正倫','宋','宋诗','song-poetry','','[]','休罪明皇與貴妃，大都衰盛兩相隨。',32,'全唐诗/poet.song.4000.json','["休罪明皇與貴妃，大都衰盛兩相隨。", "惟憐一派溫泉水，不逐人心冷暖移。"]'),
('92d27359-1b57-41f9-9aeb-74096947fa98','聞高陽路警報','郭崇仁','宋','宋诗','song-poetry','','[]','上郡連烽火，河陽更羽書。',48,'全唐诗/poet.song.4000.json','["上郡連烽火，河陽更羽書。", "兵戈連歲擾，老病一身餘。", "警哨無安枕，憂危有報疏。", "名山猶未卜，何處好閒居。"]'),
('3a1eba1b-d886-417b-9f4e-c992246fb89c','第九十四多子塔前頌','釋義青','宋','宋诗','song-poetry','','[]','於道無所證，方通萬法路。',48,'全唐诗/poet.song.40000.json','["於道無所證，方通萬法路。", "或明或暗行，不慎亦不護。", "月來松色寒，雲去青山露。", "今古天台橋，幾人能得度。"]'),
('a52d9679-ecbf-4a0d-8a47-119d18103c3c','第九十五大陽玄旨頌','釋義青','宋','宋诗','song-poetry','','[]','輕輕人問玄中旨，便吐肝腸說與他。',32,'全唐诗/poet.song.40000.json','["輕輕人問玄中旨，便吐肝腸說與他。", "木人暗皺雙眉處，石女多言爭奈何。"]'),
('62dc31f8-bb58-4395-a880-2c002d01e9b5','第九十六德山上堂頌','釋義青','宋','宋诗','song-poetry','','[]','雙盲入暗路崎嶇，日落棲蘆暫得甦。',64,'全唐诗/poet.song.40000.json','["雙盲入暗路崎嶇，日落棲蘆暫得甦。", "爭似石人眠半夜，免教舜讓守休居。", "須知花綻非干木，無腳行時早觸途。", "昨朝風起長安道，元是崑崙進國圖。"]'),
('9746162b-ba4a-4d4b-b68b-2571e105b578','第九十七投子月圓頌','釋義青','宋','宋诗','song-poetry','','[]','圓缺曾伸問老翁，石龜銜子引清風。',32,'全唐诗/poet.song.40000.json','["圓缺曾伸問老翁，石龜銜子引清風。", "昨朝木馬潭中過，踏出金烏半夜紅。"]'),
('04d43286-d1b1-44a4-8caa-a7b33a327751','第九十八芭蕉拄杖頌','釋義青','宋','宋诗','song-poetry','','[]','有無今古兩重關，正眼禪人過者難。',32,'全唐诗/poet.song.40000.json','["有無今古兩重關，正眼禪人過者難。", "欲通大道長安路，莫聽崑崙敘往還。"]'),
('8d640063-7d11-4a86-b650-49b1e10d0e74','第九十九浮山繡毬頌','釋義青','宋','宋诗','song-poetry','','[]','月裏無根草，山前枯木花。',24,'全唐诗/poet.song.40000.json','["月裏無根草，山前枯木花。", "雁迴沙塞後，砧杵落誰家。"]'),
('b43f70f1-2b25-40dd-9514-b90ec6dfb838','第一百浮山骨堆頌','釋義青','宋','宋诗','song-poetry','','[]','嫩草疏斜徑，山泉带碧流。',24,'全唐诗/poet.song.40000.json','["嫩草疏斜徑，山泉带碧流。", "文曾要渭水，列士恥莊周。"]'),
('7bab8685-288a-44f7-9772-75d92dd8cdc4','五位頌  其一','釋義青','宋','宋诗','song-poetry','','[]','正中偏，星河橫轉月明前。',28,'全唐诗/poet.song.40000.json','["正中偏，星河橫轉月明前。", "彩氣夜變天未曉，隱隱俱彰暗裏圓。"]'),
