('03abe0e8-a482-4379-9a0c-ba8b2e65beb6','五位頌  其三','釋義青','宋','宋诗','song-poetry','','[]','正中來，火裏金鷄坐鳳臺。',28,'全唐诗/poet.song.40000.json','["正中來，火裏金鷄坐鳳臺。", "玄路倚空通脈上，披雲烏道出塵埃。"]'),
('1ee3e0b4-5e0e-4d18-a641-4d4079ccf6f0','五位頌  其四','釋義青','宋','宋诗','song-poetry','','[]','兼中至，雪刃籠身不回避。',28,'全唐诗/poet.song.40000.json','["兼中至，雪刃籠身不回避。", "天然猛將兩不傷，暗裏全施善周備。"]'),
('9e66c434-138e-4444-829d-ae7900ddedce','五位頌  其五','釋義青','宋','宋诗','song-poetry','','[]','兼中到，解走之人不觸道。',28,'全唐诗/poet.song.40000.json','["兼中到，解走之人不觸道。", "一般拈掇與君殊，不落是非方始妙。"]'),
('0e60665b-8e00-4d96-a421-451a1481a3b0','偶成','程顥','宋','宋诗','song-poetry','','["\u6625\u5929", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u54f2\u7406", "\u601d\u4e61", "\u5b8b\u8bd7"]','雲淡風輕近午天，望花隨柳過前川。',32,'全唐诗/poet.song.40000.json','["雲淡風輕近午天，望花隨柳過前川。", "旁人不識予心樂，將謂偷閑學少年。"]'),
('6042c74f-e158-4506-a1fc-0f5001cd6b7e','游鄠山詩十二首 白雲道中','程顥','宋','宋诗','song-poetry','','[]','吏身拘絆同疏屬，俗眼塵昏甚瞽矇。',32,'全唐诗/poet.song.40000.json','["吏身拘絆同疏屬，俗眼塵昏甚瞽矇。", "辜負終南好泉石，一年一度到山中。"]'),
('0333dca7-039b-492b-8f15-183c6ca818fa','游鄠山詩十二首 馬上偶成','程顥','宋','宋诗','song-poetry','','[]','身勞無補公家事，心冗空令學業衰。',32,'全唐诗/poet.song.40000.json','["身勞無補公家事，心冗空令學業衰。", "世路嶮巇功業遠，未能歸去不男兒。"]'),
('03019306-c18f-4b06-b1bf-e46fb0a0ce65','游鄠山詩十二首 遊紫閣山','程顥','宋','宋诗','song-poetry','','[]','仙掌遠相招，縈紆渡石橋。',48,'全唐诗/poet.song.40000.json','["仙掌遠相招，縈紆渡石橋。", "瞑雲生澗底，寒雨下山腰。", "樹色千層亂，天形一罅遙。", "吏紛難久駐，回首羡漁樵。"]'),
('39f657cd-960b-408c-adb4-4c55a0b36aa9','游鄠山詩十二首 獼猴','程顥','宋','宋诗','song-poetry','','[]','聞說獼猴性頗靈，相車來便滿山迎。',32,'全唐诗/poet.song.40000.json','["聞說獼猴性頗靈，相車來便滿山迎。", "鞭羸到此何曾見，始覺毛蟲更世情。"]'),
('0490a7c0-bb7f-40db-94e3-f9e63a626273','髙觀谷','程顥','宋','宋诗','song-poetry','','[]','轟雷疊鼓響前峰，來自彤雲翠藹中。',64,'全唐诗/poet.song.40000.json','["轟雷疊鼓響前峰，來自彤雲翠藹中。", "洞壑積陰成氣象，鬼神憑暗弄威風。", "噴崖雨露千尋濕，落石珠璣萬顆紅。", "縱有虬龍難駐足，還應不是旱時功。"]'),
('161ef3ff-d7cf-4eb6-ae45-139a34b554f3','草堂','程顥','宋','宋诗','song-poetry','','[]','參差臺殿綠雲中，四面篔簹一徑通。',32,'全唐诗/poet.song.40000.json','["參差臺殿綠雲中，四面篔簹一徑通。", "曾讀華陽真誥上，神仙居在碧琳宫。"]'),
('3e27f16d-ff92-437c-a77a-dae3d0e1b635','草堂 長嘯巖中得冰以石敲餐甚佳','程顥','宋','宋诗','song-poetry','','[]','車倦人煩渴思長，巖中冰片玉成方。',32,'全唐诗/poet.song.40000.json','["車倦人煩渴思長，巖中冰片玉成方。", "老仙笑我塵勞久，乞與雲膏洗俗腸。"]'),
('44f9a0df-61d4-412a-9e8e-3e51a278c8f1','草堂 游重雲','程顥','宋','宋诗','song-poetry','','[]','久厭塵籠萬慮昏，喜尋泉石暫清神。',32,'全唐诗/poet.song.40000.json','["久厭塵籠萬慮昏，喜尋泉石暫清神。", "目勞足倦深山裏，猶勝低睂對俗人。"]'),
('d6c0dcd0-fb77-4310-9688-ceb641cc676a','草堂 長嘯洞北回望大頂如列屏幛比到山前却不見蓋爲仙掌所蔽','程顥','宋','宋诗','song-poetry','','[]','行盡重雲幾曲山，回頭方見碧峰寒。',32,'全唐诗/poet.song.40000.json','["行盡重雲幾曲山，回頭方見碧峰寒。", "天將仙掌都遮斷，元恐塵中俗眼看。"]'),
('e781d0bb-29a3-4d60-8e67-7a1354b16af7','草堂 凌霄三峰','程顥','宋','宋诗','song-poetry','','[]','長嘯巖東古寺前，三峰相倚勢相連。',64,'全唐诗/poet.song.40000.json','["長嘯巖東古寺前，三峰相倚勢相連。", "偶逢雲静得見日，若有路通須近天。", "陰吹響雷生谷底，老松如箸見崖顛。", "結根不得居平地，猶與蓮花遠比肩。"]'),
('ebdbc4aa-4b97-40ed-9628-be3cbccaf617','草堂 雲際山','程顥','宋','宋诗','song-poetry','','[]','南藥東邊白閣西，登臨身共白雲齊。',32,'全唐诗/poet.song.40000.json','["南藥東邊白閣西，登臨身共白雲齊。", "上方頂上朝來望，陡覺羣峰四面低。"]'),
('14eb277b-8679-4ff9-9b9f-0f1e9056b82d','草堂 下山偶成','程顥','宋','宋诗','song-poetry','','[]','襟裾三日絕塵埃，欲上籃輿首重迴。',32,'全唐诗/poet.song.40000.json','["襟裾三日絕塵埃，欲上籃輿首重迴。", "不是吾儒本經濟，等閑爭肯出山來。"]'),
('05d216d4-ef71-40e7-a9f6-75c03da46d94','是遊也得小松黄楊各四本植於公署之西窗戲作五絕呈邑令張寺丞  其一','程顥','宋','宋诗','song-poetry','','[]','中春時節百花明，何必繁絃列管聲。',32,'全唐诗/poet.song.40000.json','["中春時節百花明，何必繁絃列管聲。", "借問近郊行樂地，潢溪山水照人清。"]'),
('69ca8a98-3735-468d-ae38-a5f7e5f99310','是遊也得小松黄楊各四本植於公署之西窗戲作五絕呈邑令張寺丞  其二','程顥','宋','宋诗','song-poetry','','[]','心閑不爲管絃樂，道勝豈因名利榮。',32,'全唐诗/poet.song.40000.json','["心閑不爲管絃樂，道勝豈因名利榮。", "莫謂冗官難自適，暇時還得肆游行。"]'),
('e6ae44aa-4f80-4601-af08-82e62691deae','是遊也得小松黄楊各四本植於公署之西窗戲作五絕呈邑令張寺丞  其三','程顥','宋','宋诗','song-poetry','','[]','功名不是關心事，富貴由來自有天。',32,'全唐诗/poet.song.40000.json','["功名不是關心事，富貴由來自有天。", "任是榷酤虧課利，不過抽得俸中錢。"]'),
('e08322e2-1e36-4d45-bedd-21f1d4ba9e25','是遊也得小松黄楊各四本植於公署之西窗戲作五絕呈邑令張寺丞  其四','程顥','宋','宋诗','song-poetry','','[]','有生得遇唐虞聖，爲政仍逢守令賢。',32,'全唐诗/poet.song.40000.json','["有生得遇唐虞聖，爲政仍逢守令賢。", "縱得無能閑主簿，嬉遊不負艶陽天。"]'),
('f3d17c3b-62d1-4a8d-b8a6-a2dfea6ebbf7','是遊也得小松黄楊各四本植於公署之西窗戲作五絕呈邑令張寺丞  其五','程顥','宋','宋诗','song-poetry','','[]','獄訟已聞冤滯雪，田農還喜土膏勻。',32,'全唐诗/poet.song.40000.json','["獄訟已聞冤滯雪，田農還喜土膏勻。", "只應野叟猶相笑，不與溪山作主人。"]'),
('d002ba9d-0066-49b1-8f0b-424bd954e6f1','春雪','程顥','宋','宋诗','song-poetry','','[]','二月將臨尾，羣陰久退潜。',288,'全唐诗/poet.song.40000.json','["二月將臨尾，羣陰久退潜。", "只知桃李艶，何復雪霜嫌。", "密霰仍先集，飄霙忽散霑。", "帯風成料峭，和雨作亷纖。", "江漢初彌望，珠璣亦間兼。", "片痕才著瓦，斜勢漸穿簾。", "鳥化遼城鶴，途鋪越女縑。", "落英時鬭舞，飛絮或同黏。", "直把瓊瑶比，誰疑鵠鷺撏。", "透肌錐共利，洒面刅爭銛。", "寒怯開闈賞，光凝伴月覘。", "價增樵市炭，興入酒家帘。", "駐足銀粧履，昂頭玉裹髯。", "如何欺煦律，重復困窮閻。", "薪乏經朝備，衣因恃暖拈。", "擷芳游女恨，憂歲老農占。", "惜竹頻敲葉，愁花旋覆苫。", "失權悲太皥，助虐有飛亷。", "驟降初疑勇，旋消亦訝謙。", "朔雲雖借便，水后可無厭。", "縱任陰靈巧，難令木氣殱。", "寒威徒自奮，春氣亦時添。", "積勢方平壠，澌流已墜簷。", "暗空猶沓沓，近地即佔佔。"]'),
('9d96c493-12e1-45bd-89fe-9eeec5c241e3','晚春','程顥','宋','宋诗','song-poetry','','[]','人生百年永，光景我逾半。',48,'全唐诗/poet.song.40000.json','["人生百年永，光景我逾半。", "中間幾悲歡，况復多聚散。", "青陽變晚春，弱條成老榦。", "不爲時節驚，把酒欲誰勸。"]'),
('e63bb749-d59f-4032-8af3-f64c46e0c526','桃花菊','程顥','宋','宋诗','song-poetry','','[]','仙人紺髪粉紅腮，近自武陵源上來。',64,'全唐诗/poet.song.40000.json','["仙人紺髪粉紅腮，近自武陵源上來。", "不比常花羞晚發，故將春色待秋開。", "存留金蘂天偏與，漏泄春香衆始猜。", "兼得佳名共堅節，曉霜還獨對樓臺。"]'),
('4b2504f2-3ea6-4bbc-a056-eb25c47da0fd','早寒','程顥','宋','宋诗','song-poetry','','[]','一夜威霜特地嚴，朝來寒氣入書簾。',64,'全唐诗/poet.song.40000.json','["一夜威霜特地嚴，朝來寒氣入書簾。", "乍須火暖親爐獸，初覺冰澌結硯蟾。", "敗葉卷風輕蔌蔌，遠峰經曉静尖尖。", "出門未要貂狐燠，且著輕裘次第添。"]'),
('36f0efca-d883-439b-bc7c-1748fca7ef2f','新晴野步  其一','程顥','宋','宋诗','song-poetry','','[]','青帝方成萬物春，如何滛雨害芳晨。',64,'全唐诗/poet.song.40000.json','["青帝方成萬物春，如何滛雨害芳晨。", "乞求共指雲間日，悔恨輕嫌陌上塵。", "消盡風威猶料峭，放開山色已嶙峋。", "燕遊莫道王孫樂，亦有羲皇更上人。"]'),
('23be0286-6626-4fcb-a38c-73f5a067a236','新晴野步  其二','程顥','宋','宋诗','song-poetry','','[]','陰曀消除六幕寛，嬉遊何事我心閑。',64,'全唐诗/poet.song.40000.json','["陰曀消除六幕寛，嬉遊何事我心閑。", "鳥聲人意融和候，草色花芳杳藹間。", "水底斷霞光出岸，雲頭斜日影銜山。", "緣情若論詩家興，却恐騷人合厚顔。"]'),
('c228ddc6-8505-4daa-abc7-21fd42124d05','西湖','程顥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','潩水橋邊鴨子陂，樓臺只在郡城西。',64,'全唐诗/poet.song.40000.json','["潩水橋邊鴨子陂，樓臺只在郡城西。", "煙波乍見心先快，島嶼將尋路欲迷。", "盡日無風横舴艋，有時經雨飲虹霓。", "如何咫尺塵埃地，能使遊人意不齊。"]'),
('ba8f6f7a-59f0-44d3-9b9d-cd3669c2d22e','環翠亭','程顥','宋','宋诗','song-poetry','','[]','城居不見萬山重，因起髙亭破遠空。',64,'全唐诗/poet.song.40000.json','["城居不見萬山重，因起髙亭破遠空。", "虚曠直疑天宇外，周旋如在畫屏中。", "凝嵐散藹層層出，削玉排青面面同。", "暫得登臨已忘去，四時佳致屬賢公。"]'),
('98942fef-46e7-410b-a6af-24eb31b29406','中秋月','程顥','宋','宋诗','song-poetry','','[]','雲静好風吹，清光溢四垂。',48,'全唐诗/poet.song.40000.json','["雲静好風吹，清光溢四垂。", "金行方盛日，陰魄正中時。", "彷彿窺瑶闕，分明露桂枝。", "遴英同醉賞，誰復歎官覉。"]'),
('07c9e14f-98eb-4acb-82f5-6e5a72a14fce','象戲','程顥','宋','宋诗','song-poetry','','[]','大都博奕皆戲劇，象戲翻能學用兵。',64,'全唐诗/poet.song.40000.json','["大都博奕皆戲劇，象戲翻能學用兵。", "車馬尚存周戰法，偏裨兼備漢官名。", "中權八面將軍重，河外尖斜步卒輕。", "却凭紋楸聊自笑，雄如劉項亦閑爭。"]'),
('69e0fc4c-caac-404a-b6f4-4c7c9ad6ba40','九日訪張子直承出看花戲書學舍五首  其一','程顥','宋','宋诗','song-poetry','','[]','平日邀相見，過門又不逢。',24,'全唐诗/poet.song.40000.json','["平日邀相見，過門又不逢。", "貪隨看花伴，應笑我龍鍾。"]'),
('45ec7e53-2ddb-4b53-834f-ef37b0403bd8','九日訪張子直承出看花戲書學舍五首  其二','程顥','宋','宋诗','song-poetry','','[]','須知春色醲於酒，醉得遊人意自狂。',32,'全唐诗/poet.song.40000.json','["須知春色醲於酒，醉得遊人意自狂。", "直使華顛老公子，看花爭入少年場。"]'),
('167279ee-aeea-4f91-a56b-8cae7eeb3713','九日訪張子直承出看花戲書學舍五首  其三','程顥','宋','宋诗','song-poetry','','[]','貪花自是少年事，沉酒定嫌醒者非。',32,'全唐诗/poet.song.40000.json','["貪花自是少年事，沉酒定嫌醒者非。", "顧我疏慵老山野，却騎歸馬背斜暉。"]'),
('b3e56572-0f68-41c4-a549-bc5632ac8f3d','九日訪張子直承出看花戲書學舍五首  其四','程顥','宋','宋诗','song-poetry','','[]','下馬問老僕，言公賞花去。',24,'全唐诗/poet.song.40000.json','["下馬問老僕，言公賞花去。", "只在近園中，業深不知處。"]'),
('4ef25505-4c57-4cba-9113-74291fde2c6f','九日訪張子直承出看花戲書學舍五首  其五','程顥','宋','宋诗','song-poetry','','[]','桃李飄零杏子青，滿城車馬響春霆。',32,'全唐诗/poet.song.40000.json','["桃李飄零杏子青，滿城車馬響春霆。", "就中得意張公子，十日花前醉不醒。"]'),
('6f5dbe6c-a741-444d-877e-289772512df4','贈王求甫鐵如意','程顥','宋','宋诗','song-poetry','','[]','妖言莫信傳張惡，虚氣休將碎唾壺。',32,'全唐诗/poet.song.40000.json','["妖言莫信傳張惡，虚氣休將碎唾壺。", "借問閑窗静狐背，何如爭勝擊珊瑚。"]'),
('bef70398-536e-49b0-b298-7001676a38e5','送吕晦叔赴河陽','程顥','宋','宋诗','song-poetry','','[]','曉日都門颭斾旌，晚風鐃吹入三城。',32,'全唐诗/poet.song.40000.json','["曉日都門颭斾旌，晚風鐃吹入三城。", "知公再爲蒼生起，不是尋常刺史行。"]'),
('744048c6-5999-4f00-a352-94db9c903b98','贈司馬君實','程顥','宋','宋诗','song-poetry','','[]','二龍閑卧洛波清，今日都門獨餞行。',32,'全唐诗/poet.song.40000.json','["二龍閑卧洛波清，今日都門獨餞行。", "願得賢人均出處，始知深意在蒼生。"]'),
('ad7c14f9-708f-4563-ba13-c15116040494','陪陸子履遊白石萬固','程顥','宋','宋诗','song-poetry','','[]','條山蒼蒼河流黄，中蒲形勢天下彊。',320,'全唐诗/poet.song.40000.json','["條山蒼蒼河流黄，中蒲形勢天下彊。", "帝得賢侯殿一方，四年不更慰民望。", "元豐戊午季春月，上心閔雨愁黎蒼。", "使車四出走羣望，我亦奉命來侯疆。", "情誠感格天意順，詔書才下雨已霶。", "病麥還青禾出土，野農鼓舞歌君王。", "故人相見不道舊，爲雨歡喜殊未央。", "聖主寛憂小臣樂，自可放蕩舒胸腸。", "白石萬固皆勝地，主人爲我攜壺觴。", "况逢佳日俗所尚，車馬未曉填康莊。", "扶提十里雜老幼，迤邐千騎明戈槍。", "初聽鳴鐃入青靄，漸見朱斾輝朝陽。", "遨頭自是謝康樂，後乘獨慚元漫郎。", "侯來雖知有賓客，衆喜更爲將豐穰。", "臨溪坐石遍巖谷，幽處往往聞絲簧。", "山光似迎好客動，日景定爲遊人長。", "乘髙望遠興不盡，戀戀不知歧路忙。", "人生汨没苦百態，得此樂事真難常。", "我辭佳境已惆悵，侯亦那得久此鄉。", "他時會合重相語，辜負泉石何能忘。"]'),
('a1566d4d-5cd6-4717-a896-538582d3f7ca','戲題','程顥','宋','宋诗','song-poetry','','[]','曾是去年賞春日，春光過了又逡巡。',32,'全唐诗/poet.song.40000.json','["曾是去年賞春日，春光過了又逡巡。", "却是去年春自去，我心依舊去年春。"]'),
('b8f83d18-a134-42a5-b277-f416c872e911','題淮南寺','程顥','宋','宋诗','song-poetry','','[]','南去北來休便休，白蘋吹盡楚江秋。',32,'全唐诗/poet.song.40000.json','["南去北來休便休，白蘋吹盡楚江秋。", "道人不是悲秋客，一任晚山相對愁。"]'),
('161b8b95-603d-44a4-8798-bc15ebed5c31','和家君早寒之什','程顥','宋','宋诗','song-poetry','','[]','滿地清霜結曉寒，平明飛霰洒柴關。',64,'全唐诗/poet.song.40000.json','["滿地清霜結曉寒，平明飛霰洒柴關。", "乍憑酒力温肌骨，陡覺風威著面顔。", "閭里相呼泥北戶，牛羊收牧下前山。", "急須趁日藏薪炭，凍後髙枝不易攀。"]'),
('7c5ddc29-0d58-4396-a69c-77bc0f8543e5','和詠草','程顥','宋','宋诗','song-poetry','','[]','漸覺東皇意思勻，陳根初動夜來新。',64,'全唐诗/poet.song.40000.json','["漸覺東皇意思勻，陳根初動夜來新。", "忽驚平地有輕綠，已蓋六街無舊塵。", "莫爲枯榮吟野草，且憐愁醉柅香輪。", "詩人空怨王孫遠，極目萋萋又一春。"]'),
('d55ae017-a5b0-4092-89c9-b49805d79872','和邵堯夫打乖吟二首  其一','程顥','宋','宋诗','song-poetry','','[]','打乖非是要安身，道大方能混世塵。',64,'全唐诗/poet.song.40000.json','["打乖非是要安身，道大方能混世塵。", "陋巷一生顔氏樂，清風千古伯夷貧。", "客求墨妙多攜卷，天爲詩豪剩借春。", "儘把笑談親俗子，德容猶足慰鄉人。"]'),
('0dee66c8-3e8f-4670-94da-e63c12626f5c','和邵堯夫打乖吟二首  其二','程顥','宋','宋诗','song-poetry','','[]','聖賢事業本經綸，肯爲巢由繼後塵。',64,'全唐诗/poet.song.40000.json','["聖賢事業本經綸，肯爲巢由繼後塵。", "三幣未回伊尹志，萬鍾難換子輿貧。", "且因經世藏千古，已占西軒度十春。", "時止時行皆有命，先生不是打乖人。"]'),
('e45e3f7d-e7fc-4c78-b905-647655ce8441','和堯夫首尾吟','程顥','宋','宋诗','song-poetry','','[]','先生非是愛吟詩，爲要形容至樂時。',64,'全唐诗/poet.song.40000.json','["先生非是愛吟詩，爲要形容至樂時。", "醉裏乾坤都寓物，閑來風月更輸誰。", "死生有命人何與，消長隨時我不悲。", "直到希夷無事處，先生非是愛吟詩。"]'),
('d4ae3346-1483-4799-a978-5c1cf07e46a4','和堯夫西街之什二首  其一','程顥','宋','宋诗','song-poetry','','[]','先生相與賞西街，小子親攜几杖來。',64,'全唐诗/poet.song.40000.json','["先生相與賞西街，小子親攜几杖來。", "行次毎容參劇論，坐隅還許侍餘杯。", "檻前流水心同樂，林外青山眼重開。", "時泰身閑難兩得，直須乘興數追陪。"]'),
('9ed73880-0aa4-4d8a-8f13-8c5a309a4c20','和堯夫西街之什二首  其二','程顥','宋','宋诗','song-poetry','','[]','先生髙蹈隱西街，風月猶牽賦詠才。',64,'全唐诗/poet.song.40000.json','["先生髙蹈隱西街，風月猶牽賦詠才。", "暫到鄰家賞池舘，便將佳句寫瓊瑰。", "壯圖已譲心先快，劇韻仍降字占挼。", "只有一條誇大甚，水邊曾未兩三杯。"]'),
('767738e6-0fe0-48bc-8461-bde8afd8c24a','遊月陂','程顥','宋','宋诗','song-poetry','','[]','月陂堤上四徘徊，北有中天百尺臺。',64,'全唐诗/poet.song.40000.json','["月陂堤上四徘徊，北有中天百尺臺。", "萬物已隨秋氣改，一鐏聊爲晚凉開。", "水心雲影閑相照，林下泉聲静自來。", "世事無端何足計，但逢佳日約重陪。"]'),
('6bdb08fe-223a-4b9d-84e8-a35528921447','秋日偶成二首  其一','程顥','宋','宋诗','song-poetry','','[]','寥寥天氣已髙秋，更倚凌虚百尺樓。',64,'全唐诗/poet.song.40000.json','["寥寥天氣已髙秋，更倚凌虚百尺樓。", "世上利名羣蠛蠓，古來興廢幾浮漚。", "退居陋巷顔回樂，不見長安李白愁。", "兩事到頭須有得，我心處處自優游。"]'),
('44624aaa-ab62-459d-b185-f6bec827bc1f','秋日偶成二首  其二','程顥','宋','宋诗','song-poetry','','["\u79cb\u5929", "\u4eba\u751f", "\u54f2\u7406"]','閑來無事不從容，睡覺東窗日已紅。',64,'全唐诗/poet.song.40000.json','["閑來無事不從容，睡覺東窗日已紅。", "萬物静觀皆自得，四時佳興與人同。", "道通天地有形外，思入風雲變態中。", "富貴不滛貧賤樂，男兒到此是豪雄。"]'),
('c6e68113-2a84-4576-a993-a61104b1f5e3','代少卿和王宣徽遊崇福宫','程顥','宋','宋诗','song-poetry','','[]','睿祖開真宇，祥光下紫微。',120,'全唐诗/poet.song.40000.json','["睿祖開真宇，祥光下紫微。", "威容凝粹穆，仙仗儼周圍。", "嗣聖嚴追奉，神遊遂此歸。", "冕旒臨秘殿，天日照西畿。", "朱鳯銜星蓋，清童護玉衣。", "鶴笙鳴遠吹，珠蘂弄晴暉。", "瑶草春常在，瓊霜曉未晞。", "木文靈像出，太一醴泉飛。", "醮夕思飊馭，香晨望絳闈。", "衰遲愧宫職，蕭洒自忘機。"]'),
('f7e26d3e-4f21-44fe-bd9e-2541e52be6aa','和王安之五首 小園','程顥','宋','宋诗','song-poetry','','[]','閒坊西曲奉常家，景物天然占一窳。',64,'全唐诗/poet.song.40000.json','["閒坊西曲奉常家，景物天然占一窳。", "恰似庾園基址小，全勝浥澗路途賖。", "知君陋巷心猶樂，比我僑居事已誇。", "且喜杖藜相過易，隔牆無用少游車。"]'),
('a8b4f4c9-2715-49c6-a350-ef1d27dc02ea','和王安之五首 野軒','程顥','宋','宋诗','song-poetry','','[]','誰憐大第多奇景，自愛貧家有古風。',32,'全唐诗/poet.song.40000.json','["誰憐大第多奇景，自愛貧家有古風。", "會向紅塵生野思，始知泉石在胸中。"]'),
('be066d53-be02-46c5-8bb6-df45e65022ec','和王安之五首 汙亭','程顥','宋','宋诗','song-poetry','','[]','強潔猶來真有爲，好髙安得是無心。',32,'全唐诗/poet.song.40000.json','["強潔猶來真有爲，好髙安得是無心。", "汙亭妙旨君須會，物我何争事莫侵。"]'),
('f33b0ace-cf05-42fc-9dd2-f428f3698c1e','和王安之五首 藥軒','程顥','宋','宋诗','song-poetry','','[]','嚢中數味應千種，砌下栽苗過百名。',32,'全唐诗/poet.song.40000.json','["嚢中數味應千種，砌下栽苗過百名。", "好是微風入庭户，清香交送滿檐楹。"]'),
('66750c0a-f40a-47a1-872b-084b1093981b','晚暉亭','程顥','宋','宋诗','song-poetry','','[]','亭下花光春正好，亭頭山色晚尤佳。',32,'全唐诗/poet.song.40000.json','["亭下花光春正好，亭頭山色晚尤佳。", "欲知剩占清風處，思順街東第一家。"]'),
('5156f505-7a1f-4e08-879f-f809986effc4','和花菴','程顥','宋','宋诗','song-poetry','','[]','得意即爲適，種花非貴多。',48,'全唐诗/poet.song.40000.json','["得意即爲適，種花非貴多。", "一區才丈席，滿目自雲蘿。", "静聽禽聲樂，閑招月色過。", "期公在康濟，終奈此情何。"]'),
('4f2a1aab-0060-4664-9620-09efa5853afb','子直示以新詩一軸偶爲四韻奉謝','程顥','宋','宋诗','song-poetry','','[]','治劇君能佚，居閑我更慵。',48,'全唐诗/poet.song.40000.json','["治劇君能佚，居閑我更慵。", "自惟降藻麗，不解斷舂容。", "寡和知高唱，深情見古風。", "静吟梁甫意，真似卧隆中。"]'),
('75e3d976-07cc-46ef-a009-1639df2872bd','和諸公梅臺','程顥','宋','宋诗','song-poetry','','[]','急須乘興賞春英，莫待空枝謾寄聲。',32,'全唐诗/poet.song.40000.json','["急須乘興賞春英，莫待空枝謾寄聲。", "淑景暖風前日事，淡雲微雨此時情。"]'),
('3a3da5c0-5efd-4e3f-96e5-cd7950a2e26d','後一日再和','程顥','宋','宋诗','song-poetry','','[]','常勸嬉遊須及辰，莫辭巾屨染埃塵。',32,'全唐诗/poet.song.40000.json','["常勸嬉遊須及辰，莫辭巾屨染埃塵。", "秪應風雨梅臺上，已減前時一半春。"]'),
('a42e2c05-5c89-4e9d-8a1c-5a4c652b3569','郊行即事','程顥','宋','宋诗','song-poetry','','["\u6e05\u660e\u8282", "\u6e05\u660e", "\u611f\u53f9", "\u4eba\u751f", "\u6625\u6e38", "\u73cd\u60dc"]','芳原綠野恣行時，春入遥山碧四圍。',64,'全唐诗/poet.song.40000.json','["芳原綠野恣行時，春入遥山碧四圍。", "興逐亂紅穿柳巷，困臨流水坐苔磯。", "莫辭盞酒十分醉，秪恐風花一片飛。", "况是清明好天氣，不妨游衍莫忘歸。"]'),
('a696ba83-b968-40ba-a893-2cc58dd0e35f','春日江上','程顥','宋','宋诗','song-poetry','','[]','新蒲嫩柳滿汀洲，春入漁舟一棹浮。',64,'全唐诗/poet.song.40000.json','["新蒲嫩柳滿汀洲，春入漁舟一棹浮。", "雲幕倒遮天外日，風帘輕颺竹間樓。", "望窮遠岫微茫見，興逐歸槎汗漫游。", "不畏蛟螭起波浪，却憐清泚向東流。"]'),
('b0045e63-73d2-4fa5-bec5-7e3f4f102135','下白徑嶺先寄孔周翰郎中','程顥','宋','宋诗','song-poetry','','[]','驟經微雨過芳郊，轉覺長河氣象豪。',64,'全唐诗/poet.song.40000.json','["驟經微雨過芳郊，轉覺長河氣象豪。", "歸騎已登吳坂峻，飛雲猶認華山髙。", "門前岐路通西國，城上樓臺壓巨濤。", "欲問甘棠舊風化，主人邀客醉香醪。"]'),
('608d2a58-e9cd-4c22-bfa2-de4a12a781fa','盆荷二首  其一','程顥','宋','宋诗','song-poetry','','[]','庭下竹青青，盆荷水面平。',48,'全唐诗/poet.song.40000.json','["庭下竹青青，盆荷水面平。", "誰言無遠趣，自覺有餘清。", "影倒假山翠，波光朝日明。", "漣漪尤綠淨，凉吹夜來生。"]'),
('dfb3408a-86d7-489d-bd3e-499e84a345c9','盆荷二首  其二','程顥','宋','宋诗','song-poetry','','[]','衡茅岑寂掩柴關，庭下蕭疏竹數竿。',64,'全唐诗/poet.song.40000.json','["衡茅岑寂掩柴關，庭下蕭疏竹數竿。", "狹地難容大池沼，淺盆聊作小波瀾。", "澄澄皓月供宵影，瑟瑟凉風助曉寒。", "不校蹄涔與滄海，未知清興有誰安。"]'),
('358a6547-c3d3-4a5f-acaa-9a1f9a1fbe07','陳公廙園修禊事席上賦','程顥','宋','宋诗','song-poetry','','[]','盛集蘭亭舊，風流洛社今。',48,'全唐诗/poet.song.40000.json','["盛集蘭亭舊，風流洛社今。", "坐中無俗客，水曲有清音。", "香篆來還去，花枝泛復沉。", "未須愁日暮，天際是輕陰。"]'),
('f8f61005-425e-4c52-9c88-61ac3449494c','酬韓持國資政湖上獨酌見贈','程顥','宋','宋诗','song-poetry','','[]','對花酌酒公能樂，飯糗羮藜我自貧。',32,'全唐诗/poet.song.40000.json','["對花酌酒公能樂，飯糗羮藜我自貧。", "若語至誠無內外，却應分别更迷真。"]'),
('ac3eb606-4dfe-4bdb-894f-d2ec6664629e','哭張子厚先生','程顥','宋','宋诗','song-poetry','','[]','歎息斯文約共修，如何夫子便長休。',64,'全唐诗/poet.song.40000.json','["歎息斯文約共修，如何夫子便長休。", "山東無復蒼生望，西土誰共後學求。", "千古聲名聯棣萼，二年零落去山丘。", "寢門慟哭知何限，豈獨交親念舊游。"]'),
('da5882d6-5117-4701-bf86-85062b3c1a24','夏','程顥','宋','宋诗','song-poetry','','[]','百葉盆榴照眼明，桐陰初密暑猶清。',32,'全唐诗/poet.song.40000.json','["百葉盆榴照眼明，桐陰初密暑猶清。", "深深重幕度香縷，寂寂高堂聞燕聲。"]'),
('489a0108-5e35-4abb-9360-87ab614e9616','秋','程顥','宋','宋诗','song-poetry','','[]','洗滌炎埃宿雨晴，井梧一葉報秋聲。',32,'全唐诗/poet.song.40000.json','["洗滌炎埃宿雨晴，井梧一葉報秋聲。", "氣從緹室葭莩起，風向白蘋洲渚生。"]'),
('b15e57e1-cb1e-4175-9251-b2c209dcb49d','睢陽五老圖','程顥','宋','宋诗','song-poetry','','[]','大道剛明孰肯閑，拳拳心志尚遺冠。',64,'全唐诗/poet.song.40000.json','["大道剛明孰肯閑，拳拳心志尚遺冠。", "飯蔬飲水時行樂，定禮刪詩國建桓。", "終身戀闕存忠厚，薄味供先表蹇寒。", "鴻鈞幸得循清運，餘烈憑人仔細看。"]'),
('e5c0b55f-a5f5-4653-94b2-1f513de1c361','句','程顥','宋','宋诗','song-poetry','','[]','中心如自固，外物豈能遷。',12,'全唐诗/poet.song.40000.json','["中心如自固，外物豈能遷。"]'),
('d6d2801d-429e-441a-892f-963e782fb346','謝客','羅善同','宋','宋诗','song-poetry','','[]','風爭漢雲歸碧洞，月高涼露返蒼巖。',32,'全唐诗/poet.song.40000.json','["風爭漢雲歸碧洞，月高涼露返蒼巖。", "乾坤萬里明如鏡，輕輦遙遙倩鶴驂。"]'),
('2c5ab29e-ce9c-4f06-a0ad-56a5ed805ea4','卧龍雪','沈遼','宋','宋诗','song-poetry','','[]','錯落卧龍雪，近春殊未消。',48,'全唐诗/poet.song.40000.json','["錯落卧龍雪，近春殊未消。", "庭前玉札碎，竹裏鈆華飄。", "陽氣在幽壤，輕寒生泬漻。", "城中清酪熟，歌吹上岧嶤。"]'),
('5d251504-ceb2-4550-afb7-d500c214b16d','寄陸九','沈遼','宋','宋诗','song-poetry','','[]','賀老湖邊春水生，野陽浮動北風輕。',64,'全唐诗/poet.song.40000.json','["賀老湖邊春水生，野陽浮動北風輕。", "天邊重鬭歌筦響，鑑裏綵舟金翠明。", "大抵盛時須著意，要知吾輩未忘情。", "君如彦道能懷帽，便逐輕帆作此行。"]'),
('3b783292-2179-479b-8b49-c4be7263a390','和穎叔西園春宴','沈遼','宋','宋诗','song-poetry','','[]','閑居喜遊覽，嘯詠待春風。',255,'全唐诗/poet.song.40000.json','["閑居喜遊覽，嘯詠待春風。", "春風來無逆，濳將羣卉通。", "卧龍形勝地，矢{羊高}鑑湖中。", "府寺壓山起，亭臺儼穹崇。", "幽翮弄新儔，夭葩散珍叢。", "弱柳不勝姸，修烟杳蒙蘢。", "太守樂邦人，縱觀迨時豐。", "天邊振簫瑟，縹渺大鼇宫。", "遊人競行樂，十里畫羅紅。", "金繡不誇富，隨珠巧玲瓏。", "眄睞鬭舟劇，歡呼金鼓雄。", "躊躇水中巧，公子射琱弓。", "神技窮怪變，舞衣事雍容。", "草樹日欣欣，笑語咸嗈嗈。", "念此駘蕩節，衆樂兹無窮。", "吾昔事冶遊，浚都盛朋從。", "邇來翻澹泊，白髪成衰翁。", "欲進一樽酒，坐來還無悰。", "追懷少年趣，那知化人功。", "慷慨芳樹下，日斜萬人空。", "喧呼趣歸馭，璧月生簾櫳。"]'),
('49590154-7261-46cc-ba58-41d95ee4e4dd','和穎叔蓬萊閣','沈遼','宋','宋诗','song-poetry','','[]','海上仙山豪，泛泛隨狂潮。',192,'全唐诗/poet.song.40000.json','["海上仙山豪，泛泛隨狂潮。", "仙人毒其危，禺强資巨鼇。", "澒洞絕世紛，於焉樂逍遙。", "長年誓不死，玉觀何岧嶤。", "麻姑朝按行，洪崖莫相招。", "宴勞酌瓊液，獻酬肯相饒。", "月裏振金珮，風前吹玉簫。", "至真遊樂地，世俗風波遙。", "我本丘壑人，居然厭煩囂。", "步此重閣峻，仙意何飄飄。", "下視照湖春，浩蕩生波濤。", "愛兹爲中峙，想可娛洪髙。", "蕭灑紫霞衣，淡泊顔氏瓢。", "聊樂白駒影，軒裳真𣙢牢。", "賀老久不作，吾方餌金膏。", "輕身化羽翼，把袂窮丹霄。"]'),
('64b65429-9c50-4bc0-90b3-4e657d3dccea','望海亭','沈遼','宋','宋诗','song-poetry','','[]','平昔懷壯觀，欲浮滄海遊。',144,'全唐诗/poet.song.40000.json','["平昔懷壯觀，欲浮滄海遊。", "乖暌未即去，歎恨成淹留。", "縱步越山頂，危亭停斗牛。", "顧視東北軒，烟雲莽浮浮。", "氣象凌萬有，心膽森相投。", "暫欣區霧明，三江如带流。", "信哉天地大，蕩蕩難爲侔。", "迤邐睨山川，微茫使人愁。", "春曉看晴旭，秋宵懸玉鈎。", "未遂逢海若，空然想蓬丘。", "老氏患有身，安得六翮修。", "終期赤松輩，敖蕩成蛟虬。"]'),
('b1e9bc9c-7c94-4e95-9110-8ddfad3ccef1','秦望閣','沈遼','宋','宋诗','song-poetry','','[]','秦王昔東狩，猖狂慕長生。',168,'全唐诗/poet.song.40000.json','["秦王昔東狩，猖狂慕長生。", "訾黄杳不下，空山獨含情。", "瞻彼萬仞勢，强兹千載名。", "居然作南屏，翠影臨重城。", "伊昔賢太守，樂此烟雲輕。", "憑髙結華構，顯敞資神明。", "後來宅此地，决訟休羣氓。", "仰止鎮靜姿，仁心繇是閎。", "東州七萬井，利病隨時平。", "百姓望太守，雲間引雙旌。", "政成宴賓從，籩豆陳前楹。", "上下此相樂，於焉歌太寧。", "眄想仲蔚隱，聿懷安石清。", "荒湛焉用戒，終想愧崢嶸。"]'),
('a5ea8f84-ea68-4afb-8a88-e6611d6a46e0','贈桃源大師還剡','沈遼','宋','宋诗','song-poetry','','[]','金庭昔相會，我髪才勝冠。',120,'全唐诗/poet.song.40000.json','["金庭昔相會，我髪才勝冠。", "長嘯望海嶠，志懷九霄丹。", "道人方少壯，談笑昇仙壇。", "一别支一載，流年劇飛翰。", "韋布早相誤，多病甘衰殘。", "道人自怡悅，形神愈堅完。", "訪我吳山陽，相顧生驚歎。", "使我負愧恥，終身謝仙官。", "猶欣被闇黮，得與世路寛。", "若逢羡門老，爲余假青鸞。"]'),
('7bc49203-bbc8-4111-993b-de512dc24763','送智印師還會稽','沈遼','宋','宋诗','song-poetry','','[]','窮居謝世事，浩蕩如孤雲。',168,'全唐诗/poet.song.40000.json','["窮居謝世事，浩蕩如孤雲。", "生計委夢幻，焉能履紛紛。", "上人遠來過，髙談紓所聞。", "天上曼陀華，吾知悅清芬。", "至理有神仙，會爲貝多文。", "法力浩無邊，諒能抗三軍。", "鼎新布金地，檀施咸訢訢。", "翩然揖歸袂，吾固殊其羣。", "浮杯渡天塹，歸路稽山垠。", "昨夜一尺雪，佳氣生鋤耘。", "擁毳可待飽，尚應事高薫。", "後會復何時，相望此江濆。", "吾已與心約，行當宅榆枌。", "他年白蓮會，何慚張隱名。"]'),
('701b1cd6-f083-4dcb-a1b2-536c434a1b2f','禪老閣','沈遼','宋','宋诗','song-poetry','','[]','少年尚淵默，偃仰事詩書。',96,'全唐诗/poet.song.40000.json','["少年尚淵默，偃仰事詩書。", "端然忘緼藉，乃欲尋榮途。", "一辱未知補，三獻何其愚。", "深中雅有趣，寧終渾泥塗。", "用物必傷已，誓將老江湖。", "在人既少與，於此固何誅。", "賞心不期侈，澹泊自有餘。", "儻逢安石輩，知余爲善謨。"]'),
('b81eedfa-fc7c-4f5a-8f84-f68b70950935','春日中和堂','沈遼','宋','宋诗','song-poetry','','[]','春風何處來，婉婉不暫停。',120,'全唐诗/poet.song.40000.json','["春風何處來，婉婉不暫停。", "芳林二三月，赤白鬭敷榮。", "我念造化始，有誰主其平。", "天地不相干，世人强經營。", "陽光肆燠沐，幽禽弄和聲。", "春風迎我笑，宛轉入軒楹。", "雖非少年客，感事豈忘情。", "拂拭久懸榻，開簾敞髙明。", "衰病無可樂，聊兹寄平生。", "彭殤付一夢，吾已能逃名。"]'),
('17af2f2f-6fa1-4d04-b51e-6a241f2f6116','寄題僧榮妙勝齋','沈遼','宋','宋诗','song-poetry','','[]','婉婉江記室，故廬在西陵。',144,'全唐诗/poet.song.40000.json','["婉婉江記室，故廬在西陵。", "疇昔文雅地，何年鐘梵興。", "越江下朝海，門前紺波騰。", "蒼茫夢筆事，誰似畫橋稱。", "世道久蒙昧，至人絕勾繩。", "名存誰有實，身往復奚憑。", "萬生着動靜，其初匪云應。", "紛然競其趣，自知遠真乘。", "上人學智者，髙談信能承。", "知以妙爲勝，新題敞相仍。", "色相不足誇，是境方清澄。", "行期授記誨，爲我比然燈。"]'),
('936cc3e5-9d8c-4143-a5ec-d4b4afaddb26','送師說兄弟西歸','沈遼','宋','宋诗','song-poetry','','[]','逍遙卧山館，久已謝勞生。',96,'全唐诗/poet.song.40000.json','["逍遙卧山館，久已謝勞生。", "春和不與較，安得駐君行。", "昔會殊可樂，今歸豈忘情。", "所樂去如掃，有情紛若縈。", "引領望河橋，雙舟鮮且輕。", "揚州看紅藥，雎邊弄朱櫻。", "頻羡君此遊，夢寐過吳城。", "誰知一感别，聊復亂吾清。"]'),
('a07a90ec-ed5e-4cee-a89b-5b4d661fd065','讀酈生傳','沈遼','宋','宋诗','song-poetry','','[]','秦人被塗炭，酈生自清狂。',144,'全唐诗/poet.song.40000.json','["秦人被塗炭，酈生自清狂。", "暴吏不得加，髙懷信旁洋。", "山東赤龍長，興嘯取功名。", "馮軾下全齊，其身先就烹。", "古人不輕死，何嘗貴其生。", "顧已有所造，二途皆一征。", "有誰憐是翁，欲以身狥榮。", "未卒杯酒樂，蒼茫禍來嬰。", "所懷奄不救，焉如監門清。", "乃知謬厝置，視世已皆輕。", "死者良可歎，世俗方營營。", "至仁吾所師，但欲窮山耕。"]'),
('73fa4ac8-f384-419a-92d9-535172578381','觀金沙花有感','沈遼','宋','宋诗','song-poetry','','[]','夭艷迎人意欲迷，不言正是怨深時。',32,'全唐诗/poet.song.40000.json','["夭艷迎人意欲迷，不言正是怨深時。", "愁腸百端不堪續，惆悵年年開向誰。"]'),
('63a3f6e3-2455-49bf-be67-9a65e1d59972','贈有道者','沈遼','宋','宋诗','song-poetry','','[]','昔吾知養生，始自皇人經。',144,'全唐诗/poet.song.40000.json','["昔吾知養生，始自皇人經。", "其說乃浩博，隱奥通神靈。", "錦囊固申行，夢寐嗟沉冥。", "十年不一開，未甘遂遺形。", "矯矯髙平生，真訣炳丹青。", "要妙不在多，一言如發硎。", "使人久滯念，霍如病已醒。", "豈徒固衰朽，且將延百齡。", "我雖欲亟試，未能廣娉婷。", "明年走浚上，要當宅重扃。", "信如君所說，誓將鄙心銘。", "爲報不易言，髙山柏亭亭。"]'),
('4ea08e4b-fa50-4487-ba4b-39382ab49f47','留題廣教安素堂','沈遼','宋','宋诗','song-poetry','','[]','佛舍靜不喧，求心知有趣。',120,'全唐诗/poet.song.40000.json','["佛舍靜不喧，求心知有趣。", "誰言幽人迹，寂寥爲善住。", "太師說法地，何爲號安素。", "安得此粗言，令人起驚悟。", "既不起滅定，宜已墮諸數。", "不說福德多，冥冥知正度。", "念復□饒益，能仁起兹護。", "獨示毉王功，豈爲有生故。", "伊音究法樂，清言對芳樹。", "何日敝廬歸，過汝窮朝暮。"]'),
('83fd7964-7ae8-4796-975f-b5dea5fef421','贈王伯虎','沈遼','宋','宋诗','song-poetry','','[]','盛暑劇焚燎，深林稱幽棲。',120,'全唐诗/poet.song.40000.json','["盛暑劇焚燎，深林稱幽棲。", "衰殘不勝事，遂得休天倪。", "重關人響絕，憫默與時違。", "慨念百年樂，誓將老鋤犁。", "吾子造府戟，勤拳苦攀躋。", "迺欲强訪我，清言相與稽。", "君方事軒冕，我乃樂山溪。", "所向適殊途，安得問軏輗。", "要我有所賦，將報錦與綈。", "病思何足云，有愧測海蠡。"]'),
('3e5f7321-b555-4160-a4f2-0c4025ab66d2','七月五日立秋初夜觀月','沈遼','宋','宋诗','song-poetry','','[]','酷暑殊未却，微風初夜清。',72,'全唐诗/poet.song.40000.json','["酷暑殊未却，微風初夜清。", "徘徊中庭步，復賞月華明。", "物色豈驟變，人情自先驚。", "長林最蕭灑，瑟瑟戰秋聲。", "野心獨怡懌，念此歲月征。", "聊持一樽酒，憑几坐南楹。"]'),
('adc36433-ac1c-46d7-9120-4e06ec42a814','七月十日天陰','沈遼','宋','宋诗','song-poetry','','[]','江海積陰地，浮雲朝莫生。',96,'全唐诗/poet.song.40000.json','["江海積陰地，浮雲朝莫生。", "秋來不爲雨，庭戶含孤清。", "南方八九月，殘暑尚未平。", "大火正西流，迺得逃炎蒸。", "衰柳弄金飇，幽蟬咽復鳴。", "漸欣泉石趣，已厭葛衣輕。", "夙昔抱幽志，何心守硜硜。", "已能閉諸外，無憂人事縈。"]'),
('af80edfc-61c2-4547-9a21-840b1ba3d5da','將去錢塘望烏峰有感','沈遼','宋','宋诗','song-poetry','','[]','海燕謝故巢，明年復來棲。',144,'全唐诗/poet.song.40000.json','["海燕謝故巢，明年復來棲。", "遊人去故里，飄飄困東西。", "三年豈云遠，往往遂乖睽。", "猶如水中木，那得有定稽。", "青山爲無聊，野水含悽悽。", "人生百年樂，中復失故蹊。", "悲歌夜半清，收涙不可啼。", "深愧社中翁，生死守一谿。", "無榮安得辱，萬事皆可齊。", "吾性樂幽閑，未遂親鋤犁。", "爲約平生遊，終不爲世迷。", "箕潁有夙心，老將守田畦。"]'),
('f2e32c86-8ca5-4d15-bdd3-f5bfb7cf8492','送榮叔歸蕭山','沈遼','宋','宋诗','song-poetry','','[]','疇昔來會稽，浮舟出江隄。',168,'全唐诗/poet.song.40000.json','["疇昔來會稽，浮舟出江隄。", "蒼茫望津道，隱隱辟招提。", "虚氣發峻嶺，疑有至人棲。", "龍象兹擁衛，羣木皆萋萋。", "吾家浮屠老，早歲離煩迷。", "持律破三業，悟道臻淵倪。", "法網覆衆生，一念絕町畦。", "戒刀割大葷，水陸無象犀。", "凡物有極勢，固難叙階梯。", "兀然被衣裓，誰能判金泥。", "六時宣法音，萬生荷提攜。", "愚人本無識，有識自難稽。", "如我解所說，安可議東西。", "稽首送歸馭，信美舊山蹊。"]'),
('ca19e60c-b53a-403d-907e-7a90bc311baa','留題榮師妙勝齋','沈遼','宋','宋诗','song-poetry','','[]','萬生托鈞播，美好皆因人。',48,'全唐诗/poet.song.40000.json','["萬生托鈞播，美好皆因人。", "公能以妙勝，有趣即爲真。", "儼雅翠山聳，參差芳草新。", "欲知閑客意，亦以勝吾身。"]'),
('73e2fd7a-9210-441b-876a-8a94e84f7ff2','寄昭慶闍黎','沈遼','宋','宋诗','song-poetry','','[]','二年客江漢，不知春與秋。',132,'全唐诗/poet.song.40000.json','["二年客江漢，不知春與秋。", "東來望吳越，歷記昔時遊。", "蕭山江水西，萬屋白雲迷。", "地勢既灑落，家家臨水隄。", "中有一大士，法與天台齊。", "至行通神明，多果無階梯。", "吾昔屢入室，遂能離筌蹄。", "誰言似金粟，真已謝荆溪。", "憫憫强冠带，悠悠恨乖暌。", "仍作趙魏行，何年造幽棲。", "臨風一問訊，深已愧提撕。"]'),
('defd930b-5e50-48bb-91e9-8395c0bd0bb1','過揚子望金山懷南屏師','沈遼','宋','宋诗','song-poetry','','[]','滄溟有餘力，揚子生狂瀾。',48,'全唐诗/poet.song.40000.json','["滄溟有餘力，揚子生狂瀾。", "素秋將西渡，竚立成盤桓。", "吾豈懷土人，苦厭世事艱。", "自念從此去，何時復丘樊。"]'),
('c6a49ba6-eaf1-426f-9842-d8e2ca467eec','觀蕉葉二首  其一','沈遼','宋','宋诗','song-poetry','','[]','春陰薄薄壓輕寒，朱檻無聊愁夢殘。',32,'全唐诗/poet.song.40000.json','["春陰薄薄壓輕寒，朱檻無聊愁夢殘。", "唯有庭蕉會人意，芳心欲展復微攢。"]'),
('39dd6dd1-5f13-4a84-ae8a-e0af46430bef','觀蕉葉二首  其二','沈遼','宋','宋诗','song-poetry','','[]','憶昔紅蕉狼籍時，玉人攜手淚沾衣。',32,'全唐诗/poet.song.40000.json','["憶昔紅蕉狼籍時，玉人攜手淚沾衣。", "今日芳心爲誰展，天邊怊悵未成歸。"]'),
('3e187576-573e-4ed5-aa52-8e5803745d7f','登澧陽樓','沈遼','宋','宋诗','song-poetry','','[]','眇眇江湘萬里平，夕陽明處楚山横。',64,'全唐诗/poet.song.40000.json','["眇眇江湘萬里平，夕陽明處楚山横。", "已知多病催生計，那爲青春感客情。", "牢落不如孤鶴羽，支離何慕古人名。", "追懷年少區區意，還似西軒一夢驚。"]'),
('6f9afbc9-0854-4233-acf5-6d376f9e2c95','殘花','沈遼','宋','宋诗','song-poetry','','[]','忽忽春已老，强行芳樹邊。',48,'全唐诗/poet.song.40000.json','["忽忽春已老，强行芳樹邊。", "不能驚白髪，何用惜流年。", "殘紅不可擷，復畏青條折。", "榮落終歲事，何心翻惙惙。"]'),
('8a40cd7d-9cc7-4dc5-8699-34f031f71957','寄才仲','沈遼','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','陶令在彭澤，放懷天壤間。',144,'全唐诗/poet.song.40000.json','["陶令在彭澤，放懷天壤間。", "横江三百里，往往向廬山。", "多尋簡寂醉，時訪遠公閑。", "不復顧吏迹，世人指爲頑。", "公子負文華，少年成青綸。", "風流不屑俗，爲邑得星灣。", "節節香爐峰，據案見蒼顔。", "何勞事舟楫，緩步可躋攀。", "形骸付物外，勿使人事關。", "巖壑髙世人，有誰偕往還。", "新篇定盈軸，佳句不可刪。", "南風儻乘寄，誠足慰衰孱。"]'),
('3318d473-476f-4917-98e3-9f33dc030b09','寄南屏師','沈遼','宋','宋诗','song-poetry','','[]','庭柳日衰落，已聽暮蟬吟。',96,'全唐诗/poet.song.40000.json','["庭柳日衰落，已聽暮蟬吟。", "吾州西郭外，誰感故人心。", "卧病觀元化，悠悠信難諶。", "不爲物所遷，固知幽趣深。", "情來念不淺，道喪理亦沉。", "相望五千里，江漢水涔涔。", "神遊不可到，短夢安能尋。", "不如東歸翼，華髪滿瑤簪。"]'),
('dd3ae0c5-0e09-4629-805c-f566b6c46c54','綠髪','沈遼','宋','宋诗','song-poetry','','[]','少年愛綠髪，櫛沐對春時。',48,'全唐诗/poet.song.40000.json','["少年愛綠髪，櫛沐對春時。", "多病久衰瘁，感事還成悲。", "昔人寧非我，我意顧何知。", "不須下照水，始識無生岐。"]'),
('d2ed2ede-05ec-47ee-91a7-1a97afb8d7ef','釣魚','沈遼','宋','宋诗','song-poetry','','[]','池上獨垂釣，日斜含夕陰。',48,'全唐诗/poet.song.40000.json','["池上獨垂釣，日斜含夕陰。", "游魚方適意，微我亦無心。", "投竿乃有獲，顧女猶顛擲。", "脫鈎捨之去，我與女偕適。"]'),
('9e9d239c-0293-483a-a7b1-5ebb488019b7','澧州水','沈遼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','火行厭袢溽，陰雨重爲沴。',120,'全唐诗/poet.song.40000.json','["火行厭袢溽，陰雨重爲沴。", "時序亦已僣，衰羸頓知敝。", "蒼茫洞庭上，五江劇奔逝。", "民阽爲魚憂，浮桴具生計。", "吾迺羈旅人，髙軒俯東勢。", "攜持顧未免，仁心安所濟。", "冒軼瓜瓠區，平原信容裔。", "池荷失清賞，流萍蕩階砌。", "咨嗟竹窗卧，凄風振衣袂。", "欲謀一觴樂，幸來豁蒙滯。"]'),
('1a31c855-543c-4c3c-b7fc-553831755262','重賦','沈遼','宋','宋诗','song-poetry','','[]','永念暑雨煩，居然蹈憂沴。',120,'全唐诗/poet.song.40000.json','["永念暑雨煩，居然蹈憂沴。", "寧謂生怨咨，甘爲小人敝。", "陰淫亦何患，臨觀大川逝。", "竹屋雖小疏，補苴豈無計。", "水性本就下，平川衍無勢。", "壅隘何不勝，湫底何由濟。", "河伯逢海若，足使誇洋裔。", "池魚肆涵泳，洋洋旁軒砌。", "流汗一已收，蕭騷撫輕袂。", "安得趣東歸，舟航應不滯。"]'),
('5d5f9c00-4c5c-4d67-beaa-4237653fb514','寄贈舒州徐處士','沈遼','宋','宋诗','song-poetry','','[]','昔愛灊川遊，青林覆幽石。',120,'全唐诗/poet.song.40000.json','["昔愛灊川遊，青林覆幽石。", "道人攜手行，蕭然名山客。", "誰知墮世路，譬如羈飛翮。", "林皋未脫去，紛紛頭欲白。", "輕負皇人經，猶懷稚川策。", "幸已棄韋带，遠謝功名迹。", "聊希閉關士，正苦身爲役。", "别來二千日，還丹應有獲。", "毋忘絳囊贈，使我昇仙籍。", "將酧金鐶脆，青綾三萬尺。"]'),
('2f526edb-3e85-45e9-9032-ef608e8eac92','寄贈伊先生','沈遼','宋','宋诗','song-poetry','','[]','在昔齊光禄，招余訪仙宫。',132,'全唐诗/poet.song.40000.json','["在昔齊光禄，招余訪仙宫。", "崇巖九疊峻，行望庵前松。", "下馬過星壇，超然挹孤風。", "華冠映紺髪，談笑想鴻濛。", "飲之青菁飯，喻以朝元功。", "顧余方羈束，焉能謝人中。", "闇黮七八歲，日月何匆匆。", "吾非久寐客，不煩一言攻。", "己知棄寵辱，安能爲世庸。", "還丹何時就，白雲弄秋空。", "相望江湖上，杳杳復蒙蒙。"]'),
('0caf9dcb-6d7b-4af5-9be0-67f6ec774810','贈長蘆福長老','沈遼','宋','宋诗','song-poetry','','[]','達摩西歸不記年，雪山消息更茫然。',32,'全唐诗/poet.song.40000.json','["達摩西歸不記年，雪山消息更茫然。", "行人不會真如事，唯愛長蘆含暮烟。"]'),
('264b1452-7472-4e9d-a5ec-04bbda329ba7','寄崇德大師','沈遼','宋','宋诗','song-poetry','','["\u592a\u6e56"]','滄波眇眇太湖邊，引領西風爲悵然。',32,'全唐诗/poet.song.40000.json','["滄波眇眇太湖邊，引領西風爲悵然。", "已會老師忘世事，阿蘭那行即真禪。"]'),
('31cbae38-d977-4fd5-8cf3-727071551250','贈夾山長老兼示石門蹇大博','沈遼','宋','宋诗','song-poetry','','[]','古佛不滅法，處處唯青山。',96,'全唐诗/poet.song.40000.json','["古佛不滅法，處處唯青山。", "如來大道場，多出荆湘間。", "吾聞夜山勝，欲往倦躋攀。", "一接老師語，已如陟孱顔。", "秋風孤猿嘯，絕壑古松殷。", "夜半天樂清，龍象稽首還。", "爲我告卓令，法樂元非艱。", "欲令沉痾愈，邂逅毉至閑。"]'),
('c9befc23-e8c1-43e7-8b6b-bd768ee4713c','西閣秋杪感懷','沈遼','宋','宋诗','song-poetry','','[]','秋入孤城萬木凋，荒山野水出林梢。',64,'全唐诗/poet.song.40000.json','["秋入孤城萬木凋，荒山野水出林梢。", "澧中夷落無烽火，湖上風雲有鬭蛟。", "經歲杜門人不識，終身謝事世何嘲。", "故廬寂寂烏峰下，誰爲迎霜葺草茅。"]'),
('2710cc30-27ed-4443-989a-81ee1174b367','屈平','沈遼','宋','宋诗','song-poetry','','[]','屈平已放逐，行吟成九歌。',72,'全唐诗/poet.song.40000.json','["屈平已放逐，行吟成九歌。", "孤心抱幽恨，君王將若何。", "才調固灑落，胡爲情慮多。", "哀哀撫長鋏，軋軋感女蘿。", "彼已不我待，吾將懷彼那。", "空令汨羅水，予客泣清波。"]'),
('78408015-23d1-4c20-a5ae-cdf48dde7171','雜詩  其一','沈遼','宋','宋诗','song-poetry','','[]','葱蒨竹林下，秋來多獨往。',48,'全唐诗/poet.song.40000.json','["葱蒨竹林下，秋來多獨往。", "豈無夕禽喧，固勝人語響。", "欲詠葛天歌，支離難自强。", "何如默默爲，中心亦怠賞。"]'),
('50402dee-be6a-40b1-9444-5c7e685d95b5','雜詩  其二','沈遼','宋','宋诗','song-poetry','','[]','夭娥屬客舞，樂府聲寂寥。',96,'全唐诗/poet.song.40000.json','["夭娥屬客舞，樂府聲寂寥。", "翹彦列中堂，于以娛終朝。", "誰言野人樂，孤坐自逍遙。", "青松有幽操，白石割圭刀。", "人生若朝露，哀樂迭相招。", "焉用金玉姿，甘被膏火銷。", "翛然卧林下，不繫市與朝。", "何必薄周孔，使我爲由巢。"]'),
('24f7efde-8594-4a11-a737-f31bfd694f54','雜詩  其三','沈遼','宋','宋诗','song-poetry','','[]','身世日泯泯，譬彼一毫輕。',72,'全唐诗/poet.song.40000.json','["身世日泯泯，譬彼一毫輕。", "胡爲餓首陽，不必造承明。", "達人不言命，恥向寵辱驚。", "不爲檻下虎，即作林中麖。", "憫憫欲夸俗，皎皎還爲名。", "卜筮雖小藝，逸哉嚴君平。"]'),
('53b10e03-11b7-4cbc-9b61-bbac47e6216b','雜詩  其四','沈遼','宋','宋诗','song-poetry','','[]','古人有精思，飄飄出天壤。',72,'全唐诗/poet.song.40000.json','["古人有精思，飄飄出天壤。", "遺形若屣履，寧復顧煩鞅。", "髙鳳會幽趣，迺貽漂麥讓。", "御寇好遊適，初聞內觀賞。", "希夷本人境，奚憚不可往。", "有說即忘言，指象真爲駔。"]'),
('88ee7f01-b7a8-41fe-a01f-33272804ef5c','雜詩  其五','沈遼','宋','宋诗','song-poetry','','[]','少小負不羈，長大好丘壑。',96,'全唐诗/poet.song.40000.json','["少小負不羈，長大好丘壑。", "天事與人爲，信哉何寥廓。", "乃知戛戛行，皆爲名所縛。", "寧爲瑣瑣人，有非利所攫。", "至行本無爲，俗論自美惡。", "强行或顛沛，終始豈億度。", "朱張信吾師，王貢不可作。", "咄咄轅門駒，毋以吾斟酌。"]'),
('d41ba842-72a7-4408-b223-2c3b279d163f','雜詩  其六','沈遼','宋','宋诗','song-poetry','','[]','達人體無爲，汎汎若野馬。',72,'全唐诗/poet.song.40000.json','["達人體無爲，汎汎若野馬。", "胡爲狂夫志，𥈭然小天下。", "知足自有餘，多謀始恨寡。", "可否必繫己，出處焉用假。", "大塊勞羣物，吾生信容冶。", "死生會如一，髙情迺能捨。"]'),
('9ac8febd-07eb-40a1-8755-c9aa9d02d5ba','贈磻翁龍尾硯','沈遼','宋','宋诗','song-poetry','','[]','龍尾山盤八十里，龍尾有潭下無底。',201,'全唐诗/poet.song.40000.json','["龍尾山盤八十里，龍尾有潭下無底。", "秋月亭亭潭氣黑，其中有石色如墨。", "山川秀氣散不爲，風雲頑不爲砂礫。", "融結至寶有物主，水上經營無處所，經年始獲不敢賈。", "我昔遊江南，有客遺我誇龍子。", "吾知龍能變化，是或不可制。", "追琢爲巨硯，大筆揮離騷。", "中圓體天形，外方作地象。", "精光熠熠角生浪，熟視乃有紺羅文。", "瑩潤無與比，玩愛何可論。", "我今樗散無所事，特贈華陽鴻筆麗藻人。", "吾聞蜀都多學士，寘諸文府爲戰具。", "君如窮經遂絕筆，請典大軸傳後嗣。"]'),
('112559c0-90ac-4751-b258-2afdb84699ae','春日行','沈遼','宋','宋诗','song-poetry','','[]','宫梅撲地白氈班，細柳結烟金縷繁。',96,'全唐诗/poet.song.40000.json','["宫梅撲地白氈班，細柳結烟金縷繁。", "春華年年來不已，人生七十半衰殘。", "少時豪放猶不敵，何况羈棲落荆蠻。", "囊中琵琶金鳳閑，古曲情深屬誰彈。", "病目矇矇對荒山，東風有意爲掩關。", "棄置萬事一夢還，江湖水生愁夜寒。"]'),
('87aed83d-ac0b-49d7-8823-18005d79281e','春霖','沈遼','宋','宋诗','song-poetry','','[]','春霖漫不已，楊柳一何衰。',72,'全唐诗/poet.song.40000.json','["春霖漫不已，楊柳一何衰。", "江國多晏寒，微晹來亦遲。", "豈不念向榮，惜逐秋風悲。", "植物固如此，勞生何可爲。", "誰將區中境，遙與青松期。", "匆匆從古然，滯念良可遺。"]'),
('0a19a371-7f32-45b3-ac53-6ba37b3510a5','養猿','沈遼','宋','宋诗','song-poetry','','[]','孤猿逸重巘，清嘯久不聞。',96,'全唐诗/poet.song.40000.json','["孤猿逸重巘，清嘯久不聞。", "中懷爲牢落，日跂吳山雲。", "宓子有深致，遠將清思分。", "蕭颯野人姿，慰我澧江濆。", "動靜得真性，超然離世紛。", "春華二月來，苑囿爭敷芬。", "誰言關閉趣，聊以樂朝曛。", "毋懷故山歸，吾將汝爲羣。"]'),
('148b6190-cc85-4c7e-8d3d-f222176b82ce','甲辰年五月十五日夜澧陽觀月','沈遼','宋','宋诗','song-poetry','','[]','少年悵不樂，明日何爲哉。',192,'全唐诗/poet.song.40000.json','["少年悵不樂，明日何爲哉。", "揚眉一遐賞，寂寂更傷懷。", "念昔吾州樂，泛舟湖上來。", "佳賓適所好，歡計成金罍。", "妖歌有送響，度曲清且哀。", "留連夕陽下，夜色起山隈。", "光明水晶域，素彩中天開。", "龍香弄微風，四顧絕纖埃。", "澄波照上下，倒影出瑤臺。", "紅燭漸向微，始知夜漏催。", "美人屢更衣，含笑玉山隤。", "歡樂殊未央，鼓枻中洲迴。", "人生無憂患，遇樂且銜杯。", "悵余失交臂，萬里來天涯。", "羈愁那無感，情慮長如灰。", "神遊忽自笑，安知顧形骸。"]'),
('ddedbe2e-11ce-4d77-b577-393c45d4adf1','陰溽','沈遼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','楚梅半已熟，苦雨含悽愴。',96,'全唐诗/poet.song.40000.json','["楚梅半已熟，苦雨含悽愴。", "不嫌茅屋疏，頓喜方池漲。", "洞庭納七澤，萬里相搖漾。", "凝陰有餘潤，霶霈劇浩蕩。", "古稱卑濕地，久痗累丁壯。", "况我憔悴人，那能保亡恙。", "蓮下雙鳬嬉，竹裏陰泉響。", "幸無世慮迫，聊且安俯仰。"]'),
('c4fed53d-c7fc-4ad4-beed-8df01f8f11c4','清晨','沈遼','宋','宋诗','song-poetry','','[]','清晨振衣起，起步芳池側。',72,'全唐诗/poet.song.40000.json','["清晨振衣起，起步芳池側。", "徘徊俯丹檻，倒影見欹魄。", "不識嵇中散，定非風塵格。", "長懷謝靈運，本自林泉客。", "吾衰厭世道，不以形爲役。", "顧非冕弁人，冕弁匪所適。"]'),
('938c7ea6-0833-4986-b8e0-a57d676a3221','稚子','沈遼','宋','宋诗','song-poetry','','[]','讀書北軒下，獨翫太古清。',108,'全唐诗/poet.song.40000.json','["讀書北軒下，獨翫太古清。", "稚子請我說，糟粕顧何明。", "念彼硜硜人，方起浩浩情。", "遺兹以蹈彼，於理或易平。", "深愧鄒魯生，章句誓成名。", "記問數寸間，孰知躬所行。", "爲人鬻所有，利如九河傾。", "中性或易遷，吾志將難攖。", "汎然美造化，庶使學躬耕。"]'),
('c413c910-e707-43e5-8f54-26e44713ade3','澧陽大水','沈遼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','澧陽地湫底，夏雨無時休。',120,'全唐诗/poet.song.40000.json','["澧陽地湫底，夏雨無時休。", "疏惡三尺城，民阽爲魚憂。", "竹屋易飄蕩，薄哉生生謀。", "羈人豈但免，飭隸資桴浮。", "洞庭信巨浸，畜洩浮荆州。", "無迺中江隘，千里壅其流。", "永懷吾州樂，宅土何夷猶。", "海隘不厭多，歲旱亦有收。", "胡爲此契濶，暴下安得瘳。", "嗟嗟南土人，狐貉守一丘。"]'),
('b89a20ca-9dc6-4308-a958-4e11158e27a3','崇山','沈遼','宋','宋诗','song-poetry','','[]','少小諷二典，已知崇山遙。',96,'全唐诗/poet.song.40000.json','["少小諷二典，已知崇山遙。", "朅來澧川溪，迺更識岧嶤。", "始詠皇國盛，土宇包前朝。", "荒徼撫民社，置官頒教條。", "頓驚羈旅迹，舟車任飄飄。", "中吳五千里，衝涉信已遼。", "使人重增念，鬱結自無聊。", "何當奮歸棹，江漢水迢迢。"]'),
('291fb86b-42bb-4891-8afb-44a45510447b','簫鼓曲','沈遼','宋','宋诗','song-poetry','','[]','樂不在歡合，悲不在生離。',72,'全唐诗/poet.song.40000.json','["樂不在歡合，悲不在生離。", "感此簫鼓曲，已堪華髪衰。", "月明大隄路，雨暗浙江西。", "狼籍一杯酒，凄凉千里期。", "誰言天涯恨，逸韻起相思。", "清角竟不返，悒然心不怡。"]'),
('dbb32c4a-92ee-4637-bca8-c1b89e5cd215','諷仕  其一','沈遼','宋','宋诗','song-poetry','','[]','仁治貴不殺，爲吏滋頑蔽。',96,'全唐诗/poet.song.40000.json','["仁治貴不殺，爲吏滋頑蔽。", "孰謂才不才，跂跂在髙位。", "詔策暴過惡，行建元侯旆。", "冗散坐姦贓，還來咨善地。", "世無三年黜，焉得終身廢。", "遂使貪猾人，昂昂罔知畏。", "政治明賞罰，於法不假易。", "吁嗟韓馮翊，胡爲子孫戒。"]'),
('198036a0-4050-4472-b829-0bb8b7a08930','諷仕  其二','沈遼','宋','宋诗','song-poetry','','[]','聖人不出世，斯民憂倒縣。',120,'全唐诗/poet.song.40000.json','["聖人不出世，斯民憂倒縣。", "仁心欲援手，寧以身爲先。", "仲尼貴用我，孟子推諸天。", "二聖有特立，何嘗持後前。", "後來迺昧已，惘惘爲利牽。", "紛挐竊古語，不顧內所愆。", "信如一丘貉，孰有然不然。", "苟伸刀割用，於世已爲賢。", "鼎鼐雜錡釡，誰知重烹煎。", "然提地史録，不如觀長川。"]'),
('dd74be82-fb79-4935-80a4-ab40ae3bd241','池上','沈遼','宋','宋诗','song-poetry','','[]','池上少人迹，多霖含微陽。',36,'全唐诗/poet.song.40000.json','["池上少人迹，多霖含微陽。", "幽禽有清弄，戲翼沙洲旁。", "顧余不知懼，知是機已忘。"]'),
('eb113e57-683c-411c-9085-11d048aeff00','贈大中鎮國長老','沈遼','宋','宋诗','song-poetry','','[]','昔從東南來，稅駕依金地。',120,'全唐诗/poet.song.40000.json','["昔從東南來，稅駕依金地。", "迎風步峻閣，始眺澧陽市。", "蒼茫烟霧下，一水縈如袂。", "夷落雜連峰，精廬遙相峙。", "宅土信羈客，杜門忽彌歲。", "風雲一蕭散，身世兩無累。", "懷歸悵有感，史遷念留滯。", "引脰企昔遊，野馬埋蒼翠。", "何時籃輿去，復將老師值。", "請掃巖下石，爲述空王偈。"]'),
('8047518a-1b53-47f8-b4dc-6e08d1fcbbb4','遊瑞巖','沈遼','宋','宋诗','song-poetry','','[]','已恨初年不學仙，老來何處更參禪。',32,'全唐诗/poet.song.40000.json','["已恨初年不學仙，老來何處更參禪。", "西風搖落歲事晚，卧對髙巖看落泉。"]'),
('c182fb35-45fe-4fdf-af93-482233a135db','天竺白雲堂','沈遼','宋','宋诗','song-poetry','','[]','四十餘年隨世緣，眼昏頭白更茫然。',32,'全唐诗/poet.song.40000.json','["四十餘年隨世緣，眼昏頭白更茫然。", "它時一念若不斷，來向此山開福田。"]'),
('0c5d4873-4a33-49e4-8221-5bc2ab9e9767','雪竇山','沈遼','宋','宋诗','song-poetry','','[]','世路衮衮何年休，青山白雲且淹留。',32,'全唐诗/poet.song.40000.json','["世路衮衮何年休，青山白雲且淹留。", "千尋飛雪下巖竇，落日洗耳前溪頭。"]'),
('a24fd79a-f11b-4026-9754-cadb60726713','龍潭','沈遼','宋','宋诗','song-poetry','','[]','潭中有龍不可見，但見瀑水從天來。',32,'全唐诗/poet.song.40000.json','["潭中有龍不可見，但見瀑水從天來。", "我欲垂鈎畏血指，却上北嶺聽奔雷。"]'),
('946d8c74-d3a1-4131-9807-2ed9bbd8a96c','金鵝方丈','沈遼','宋','宋诗','song-poetry','','[]','金鵝山勢髙崔崔，乘興已泛滄州迴。',32,'全唐诗/poet.song.40000.json','["金鵝山勢髙崔崔，乘興已泛滄州迴。", "計較百年能幾日，不知此地何時來。"]'),
('7fcac6fc-e1a8-4513-a7df-4f29270fcd68','漁浦躬師','沈遼','宋','宋诗','song-poetry','','[]','江東江西多舊遊，十載重來蓬鬢秋。',32,'全唐诗/poet.song.40000.json','["江東江西多舊遊，十載重來蓬鬢秋。", "多愧老師觀自在，慇懃渡口送歸舟。"]'),
('e54214e7-f462-448c-bf96-d04df05ee1e9','金山竇覺師','沈遼','宋','宋诗','song-poetry','','[]','不安甽畝强西遊，二月春風占渡頭。',32,'全唐诗/poet.song.40000.json','["不安甽畝强西遊，二月春風占渡頭。", "寄語道人莫相笑，歸時迎我到瓜洲。"]'),
('3d49fc2b-fdf6-4765-a1d3-4421c0bd19e2','西上','沈遼','宋','宋诗','song-poetry','','[]','一年爲客厭西東，白髪生來百事慵。',32,'全唐诗/poet.song.40000.json','["一年爲客厭西東，白髪生來百事慵。", "道路莫驚行李薄，初無盛意學終童。"]'),
('52c003eb-bc43-4299-a7b9-eec3fd5bfc6c','道旁','沈遼','宋','宋诗','song-poetry','','[]','道旁桃李鬭芳菲，歡意長隨斷夢歸。',32,'全唐诗/poet.song.40000.json','["道旁桃李鬭芳菲，歡意長隨斷夢歸。", "夢去夢來何可計，春風斜日鴈孤飛。"]'),
('926ffddf-b5fd-4e49-8b54-749c804b3882','暫來','沈遼','宋','宋诗','song-poetry','','[]','重入都城誰與鄰，暫來還去不知春。',32,'全唐诗/poet.song.40000.json','["重入都城誰與鄰，暫來還去不知春。", "繁華年少莫相笑，身是無爲閑道人。"]'),
('b25717e6-77a0-4617-aa67-6cf7157b75ac','東歸','沈遼','宋','宋诗','song-poetry','','[]','斷知無樂亦無憂，薄有田園滄海頭。',32,'全唐诗/poet.song.40000.json','["斷知無樂亦無憂，薄有田園滄海頭。", "得意已同毛義去，欣然載酒上東舟。"]'),
('dfc62c6f-5b42-4e53-b617-663c808c52cb','寄四明神智師','沈遼','宋','宋诗','song-poetry','','[]','甬水樓頭看盡山，南城寺裏扣禪關。',32,'全唐诗/poet.song.40000.json','["甬水樓頭看盡山，南城寺裏扣禪關。", "老師多事猶相記，千里馳書慰病孱。"]'),
('4593f360-3b32-4d32-a813-ad43e9ee3845','寄雅上人','沈遼','宋','宋诗','song-poetry','','[]','幽樂軒前春欲歸，紅葩綠萼鬭芳菲。',32,'全唐诗/poet.song.40000.json','["幽樂軒前春欲歸，紅葩綠萼鬭芳菲。", "一杯新酹邀誰飲，石首魚鮮赤蟹肥。"]'),
('9544494e-8be7-41a3-8086-0ab2ae6e0f90','題寄老軒','沈遼','宋','宋诗','song-poetry','','[]','道人寄老故山前，雪頂霜眉意嗒然。',32,'全唐诗/poet.song.40000.json','["道人寄老故山前，雪頂霜眉意嗒然。", "門外少年方作樂，誰家爲汝說因緣。"]'),
('cbc38b42-ebcb-4f26-8919-09b106f57b17','次韻酬郎祖德','沈遼','宋','宋诗','song-poetry','','[]','老去法光不足驚，嬰尋世事或能精。',32,'全唐诗/poet.song.40000.json','["老去法光不足驚，嬰尋世事或能精。", "眼花頭白終無用，卧看紗窗曉日明。"]'),
('824c9d84-32b4-454d-9102-cef1bfbf56eb','次韻酬明發華宗','沈遼','宋','宋诗','song-poetry','','[]','長卿倦遊欲東還，幸與諸公俱出關。',64,'全唐诗/poet.song.40000.json','["長卿倦遊欲東還，幸與諸公俱出關。", "世事轉頭都委夢，人生何計得長閑。", "殘花爛漫飄村塢，細雨亷纖隔碭山。", "誰寫熙寧十才子，老夫亦入畫圖間。"]'),
('9855f78c-d64e-48cb-a144-02705782c6e6','承示會稽大資政公思歸篇輙次元韻','沈遼','宋','宋诗','song-poetry','','[]','進退不辱古已稀，能如二疏蓋有數。',96,'全唐诗/poet.song.40000.json','["進退不辱古已稀，能如二疏蓋有數。", "中間已辭五鼎食，今年欲潔一身去。", "引身欲去强辭老，東部聊復頒寛詔。", "人間萬事如一夢，何人顛倒真可笑。", "紅梅夜發新春枝，黄堂晏坐賦思歸。", "已知無心更無礙，青山歷歷孤雲飛。"]'),
('f8968e92-932c-43b2-bf18-56677578a7c7','赴齋','沈遼','宋','宋诗','song-poetry','','[]','爾來世事久忘懷，十日長關九日齋。',32,'全唐诗/poet.song.40000.json','["爾來世事久忘懷，十日長關九日齋。", "白髪蒼顔見無相，不妨應供此間來。"]'),
('36035ddd-e4de-449d-9b93-d86725ade7f9','翻經臺','沈遼','宋','宋诗','song-poetry','','[]','不見康樂初翻經，崇臺百尺但有名。',32,'全唐诗/poet.song.40000.json','["不見康樂初翻經，崇臺百尺但有名。", "當時妙意遙可想，木葉落盡青山横。"]'),
('3e9891a5-0437-430f-82c7-5c869e58b1c6','和美叔澄心堂','沈遼','宋','宋诗','song-poetry','','[]','已悟無生杜世機，誰能操筆更題詩。',64,'全唐诗/poet.song.40000.json','["已悟無生杜世機，誰能操筆更題詩。", "平居赤軸粗有適，老去長齋不强持。", "炯炯色空都可計，紛紛多事豈煩知。", "有人欲識澄心要，但問君知我爲誰。"]'),
('5a4ecd97-3ac9-4272-b636-5977b3cbdc91','答文翁','沈遼','宋','宋诗','song-poetry','','[]','陶令初尋彭澤來，相如已構臨邛臺。',64,'全唐诗/poet.song.40000.json','["陶令初尋彭澤來，相如已構臨邛臺。", "正當銜杯行樂事，惠我鴻筆何爲哉。", "湖中多魚近易捕，石上老蕨拳未開。", "夫子不肯至我室，行駕畫舸遙相陪。"]'),
('42a3f9ed-b262-4364-8f7c-9cc6416b7740','奉陪穎叔賦鎖院牡丹','沈遼','宋','宋诗','song-poetry','','[]','昔年曾到洛城中，玉椀金盤深淺紅。',32,'全唐诗/poet.song.40000.json','["昔年曾到洛城中，玉椀金盤深淺紅。", "行上荆溪溪畔寺，愧將白髪對東風。"]'),
('84966add-55ca-4eb7-b67d-2949affb0aa0','顧浦觀潮','沈遼','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','放舟顧浦望江流，烟雨冥冥小麥秋。',32,'全唐诗/poet.song.40000.json','["放舟顧浦望江流，烟雨冥冥小麥秋。", "長憶故園遊觀樂，不知此地有潮頭。"]'),
('3f0635f9-c2c0-48ab-ab46-12c6ca52489e','崑山','沈遼','宋','宋诗','song-poetry','','[]','崑崙山在玉關西，此地還疑暗有嵠。',32,'全唐诗/poet.song.40000.json','["崑崙山在玉關西，此地還疑暗有嵠。", "玉石不分殊可惜，背臨斜日望虹霓。"]'),
('b2539d77-c8be-4c1f-a858-bff073e18dd7','題大中寺覺雲師壁','沈遼','宋','宋诗','song-poetry','','[]','老來情緒似秋烟，水畔林間不計年。',32,'全唐诗/poet.song.40000.json','["老來情緒似秋烟，水畔林間不計年。", "世事紛紛何可較，城西寺裏學參禪。"]'),
('a20a24c4-b1fa-4f77-976e-c739069a72a2','題廣嚴禪師房','沈遼','宋','宋诗','song-poetry','','[]','二十餘年談性空，不知强聒盡無功。',32,'全唐诗/poet.song.40000.json','["二十餘年談性空，不知强聒盡無功。", "愁來白髪如秋草，爲置浮生斷夢中。"]'),
('1a2a5efd-9253-476e-9ba2-9477094afdb3','西舍','沈遼','宋','宋诗','song-poetry','','[]','壯志已謝不復尋，無賴老境行見侵。',64,'全唐诗/poet.song.40000.json','["壯志已謝不復尋，無賴老境行見侵。", "已知筋力不自任，况復華髪如霜林。", "少年裁詩喜言老，誰知老大都無心。", "閑學維摩坐禪定，戶外唧唧鳴幽禽。"]'),
('82ca0452-fd3d-478d-a978-a460f1b35799','鄞江上作','沈遼','宋','宋诗','song-poetry','','[]','秋潮拍江余欲去，二年窮谷江之下。',64,'全唐诗/poet.song.40000.json','["秋潮拍江余欲去，二年窮谷江之下。", "疾目不矚西飛鴻，幽懷長寄斜陽樹。", "且余欲行去何之，白雲繚繞故山棲。", "蒼顔終不爲人役，不妨抱甕治田畦。"]'),
('a8cc5bcd-c7c7-40de-a260-72e2921ebf0d','湖亭懷子美','沈遼','宋','宋诗','song-poetry','','[]','秋來湖亭誰與樂，荷華半摧柳葉落。',64,'全唐诗/poet.song.40000.json','["秋來湖亭誰與樂，荷華半摧柳葉落。", "憶昔榜舟乘夜月，行觴數與君相酢。", "如今一西復一東，有如萍苴流水中。", "白頭無心治世故，何時勝處重相逢。"]'),
('37ce848a-283a-4105-ab6f-3db92296dbf9','龜兹舞','沈遼','宋','宋诗','song-poetry','','[]','龜兹舞，龜兹舞，始自漢時入樂府。',224,'全唐诗/poet.song.40000.json','["龜兹舞，龜兹舞，始自漢時入樂府。", "世上雖傳此樂名，不知此樂猶傳否。", "黄扉朱邸晝無事，美人親尋教坊譜。", "衣冠盡得畫圖看，樂器多因西域取。", "紅綠結裀坐後部，長笛短簫形製古。", "雞婁揩鼓舊所識，饒貝流蘇分白羽。", "玉顔二女髙髻花，孔雀羅衫金畫縷。", "紅靴玉带踏筵出，初驚翔鸞下玄圃。", "中有一人奏羯鼓，頭如山兮手如雨。", "其間曲調雜晉楚，歌詞至今傳晉語。", "須臾曲罷立前廡，歎息平生未嘗覩。", "清都閬苑昔有夢，寂寞如今在何所。", "我家家住江海涯，上國樂事殊未知。", "玉顔邀我索題詩，它時有夢與誰期。"]'),
('9ee5b90b-dfc5-4531-9d42-7b2735fcb1f4','寄文翁','沈遼','宋','宋诗','song-poetry','','[]','白兔觀邊仙路長，華林修竹到南莊。',64,'全唐诗/poet.song.40000.json','["白兔觀邊仙路長，華林修竹到南莊。", "比鄰雞犬易過屋，適意琴書動滿床。", "目斷鶺鴒分漢節，心隨鴻鴈極天潢。", "欲移畫舸遙相訪，正恐田家五月忙。"]'),
('26e0c4e8-f14c-4ef9-b4c4-2d7657d16e0d','答金山禪師','沈遼','宋','宋诗','song-poetry','','[]','遠公手札遠相招，陶令懷歸正鬱陶。',32,'全唐诗/poet.song.40000.json','["遠公手札遠相招，陶令懷歸正鬱陶。", "遙想宴堂長夏靜，坐臨江水看風濤。"]'),
('3abd73f5-8248-40c9-9610-76dc6df1312a','春晚偶題','沈遼','宋','宋诗','song-poetry','','[]','幸有陶公五株柳，不戀河陽千樹花。',32,'全唐诗/poet.song.40000.json','["幸有陶公五株柳，不戀河陽千樹花。", "數日東風吹欲盡，小軒寂寂日西斜。"]'),
('01f8f505-efdf-47ca-8f67-649a23908106','次韻奉酬文翁','沈遼','宋','宋诗','song-poetry','','[]','昔人幽操有至樂，吾豈含華企沖漠。',192,'全唐诗/poet.song.40000.json','["昔人幽操有至樂，吾豈含華企沖漠。", "已知勞生委夢幻，不問萬事紛紛作。", "四十年來春復秋，但見花開更花落。", "最愛長夏適我懷，新竹森森初解籜。", "修林喬木結青蔭，下蔽文窗與朱箔。", "已將形骸付物外，何必髙下窮崖壑。", "老去詩書强遮眼，爾來悉已懸髙閣。", "多病不賴世人知，吾亦於人無厚薄。", "陽狂長鄙向子平，絃歌偶似陶淵明。", "無事長甘數斗粟，終不苟就五鼎烹。", "南莊夫子謝聲名，誇我田家蠶且耕。", "誰知此意正相合，寂寥應笑魯諸生。"]'),
('675ddc9a-d964-4102-ab83-0ce57561b66a','奉酬舜文即次元韻','沈遼','宋','宋诗','song-poetry','','[]','我生無庸如斷絡，已分老死填溝壑。',208,'全唐诗/poet.song.40000.json','["我生無庸如斷絡，已分老死填溝壑。", "不能掉舌强附會，何暇論經更穿鑿。", "萊蕪甑敝欲生塵，玉川婢粗常赤脚。", "世間要塗不易驟，身外名韁誰可縛。", "本無道義輕王公，亦不悲傷念流落。", "水鄉夏半不厭熱，繞舍新篁尚含籜。", "訟庭鈎距非吾事，吏案煩苛都可却。", "農民漸使安甽畝，和氣終須蠲疹瘼。", "子羽不肯過我室，懸榻何妨卧西閣。", "年來多病亦廢飲，牆下度泥委杯酌。", "舊學迂疏不適時，譬如石田何可穫。", "欲捕大鵬逐嶺嶠，終不勞心事弋繳。", "行當歸掃烏峰下，試鍊金鼎長生藥。"]'),
('6c9c1754-0cfc-4108-8b11-7f62ff476dfc','張公洞下','沈遼','宋','宋诗','song-poetry','','[]','道人升天久不迴，至今洞門向北開。',192,'全唐诗/poet.song.40000.json','["道人升天久不迴，至今洞門向北開。", "當時仙仗人不識，白雲繚繞山間來。", "闖然初望燒香臺，百步九折多蒼苔。", "仙官委蛇劍佩肅，霓旌羽蓋光漼漼。", "鶴馭欲下風作媒，雪猿白鳳勢欲頹。", "嵌巖石乳誰敢飲，洞下風水聲如雷。", "龍車遙遙斷消息，數百年來化爲石。", "六朝人物丘墓壞，白骨盡爲泥土蝕。", "吾昔已煉九華丹，欣尋二洞窮幽寂。", "稚川方求句漏令，長史亦賴旌陽力。", "手種青精期可擇，未能脫去空羈靮。", "籃輿往來不憚勤，搔首山前髪斑白。"]'),
('8b729408-09a7-4a3c-aa68-f36e8685f766','題楊師壁','沈遼','宋','宋诗','song-poetry','','[]','年來病倦厭尋山，且寄青泠白水間。',32,'全唐诗/poet.song.40000.json','["年來病倦厭尋山，且寄青泠白水間。", "最愛楊師舊茅舍，頻來借榻伴髙閑。"]'),
('b4140055-ad6d-4413-820a-26926dd2d3e1','奉和敦義張公洞','沈遼','宋','宋诗','song-poetry','','[]','誰識此間非洞天，白雲輪囷石斕斑。',64,'全唐诗/poet.song.40000.json','["誰識此間非洞天，白雲輪囷石斕斑。", "松篁蔽空世務隔，日月不動仙家閑。", "金堂玉室不可測，霓旌羽蓋終當還。", "蛟龍沉淵馬空住，會與楊許來追攀。"]'),
('0c652b46-a0d3-492a-81d5-a2aa364b137c','將行寄蔣三','沈遼','宋','宋诗','song-poetry','','[]','春風迎我到荆谿，行看秋成憶故畦。',32,'全唐诗/poet.song.40000.json','["春風迎我到荆谿，行看秋成憶故畦。", "乘興去來何可恨，爲君引領隔湖西。"]'),
('77e7f776-d345-48e6-a4c1-584347ff8a57','招靜之','沈遼','宋','宋诗','song-poetry','','[]','浙西夫子蚤相陪，解印新從海上來。',32,'全唐诗/poet.song.40000.json','["浙西夫子蚤相陪，解印新從海上來。", "借得谿邊五畝宅，與君共酌任公臺。"]'),
('e8acd09d-cde6-4259-bbdd-602fbb7d421a','陽羨浮翠亭','沈遼','宋','宋诗','song-poetry','','[]','江南山川若奔鹿，下照江流翠相矚。',160,'全唐诗/poet.song.40000.json','["江南山川若奔鹿，下照江流翠相矚。", "朝望長干暮石牌，山頭年年春草綠。", "我昔長愛江南遊，當時少年今白頭。", "人生匆匆寄幻事，六朝得喪惟荒丘。", "陽羨本自江南州，水邊孤烟千古愁。", "沙禽關關夜相呼，稻粱自足知何求。", "我生已如不繋舟，投老爲誰計沉浮。", "腰間墨綬亦偶爾，此地欣與心相投。", "行歸三吳卜幽隱，不復更到枚回洲。", "漁父丈人莫相笑，解带於此聊遲留。"]'),
('fbe959eb-a2d8-4fbb-8c1e-8101a4593321','昭君操','沈遼','宋','宋诗','song-poetry','','[]','王昭君，漢宮女。',202,'全唐诗/poet.song.40000.json','["王昭君，漢宮女。", "漢宮女，嫁配虜。", "生如桃李花，皖皖託朝露。", "春風一摧折，零落在泥土。", "君王委心事匈奴，不知匈奴在何處。", "黄門扶我上車去，遙望漢宫隔烟霧。", "十年簾下學畫眉，不知還爲蛾眉誤。", "當時恩怨或易忘，今日悲愁那可訴。", "夢中往往作歌舞，滿目異類誰與語。", "但見驚風吹塵沙，豈識春還復秋暮。", "山林强鬼向夜哭，夜夜氊車宿荒戍。", "胡人從來不照鏡，但見白髪垂霜縷。", "念知此意終不傳，獨自援琴彈作譜。", "彈作譜，寄與漢宮人，一曲未終淚如雨。"]'),
('cab5bd42-f59a-4139-8957-79f890623e5f','酬思誠見贈','沈遼','宋','宋诗','song-poetry','','[]','都下相逢意氣歡，翩翩清興到江干。',64,'全唐诗/poet.song.40000.json','["都下相逢意氣歡，翩翩清興到江干。", "壯心已謝馳千里，薄禄猶慚繫一官。", "閑比水雲隨所適，朽如溝木不勝蟠。", "欣然於此重相會，一讀新篇九起歎。"]'),
('e02c03d1-020a-4b6b-8a45-336382741cf9','寄慶復允中','沈遼','宋','宋诗','song-poetry','','[]','木葉飄蕭已半殷，試臨髙處望君山。',64,'全唐诗/poet.song.40000.json','["木葉飄蕭已半殷，試臨髙處望君山。", "野田繚繞來時路，畫舸逍遙數日閑。", "坐想故人應見憶，如今秃髪不勝斑。", "兩州相望無千里，莫惜新篇斷往還。"]'),
('854c144e-3b31-4dc0-aec8-66391638aebe','喪表姑輓詞  其一','沈遼','宋','宋诗','song-poetry','','[]','不盡華髪養，奄聞朝露傷。',48,'全唐诗/poet.song.40000.json','["不盡華髪養，奄聞朝露傷。", "人雖恨長夜，生已在西方。", "靈輤過空坂，羅繻空北堂。", "欲知簫史處，松柏正凌霜。"]'),
('6f9bb5b0-3123-4346-97ed-d5c445f1d511','喪表姑輓詞  其二','沈遼','宋','宋诗','song-poetry','','[]','憶昔祖姑前，曾觀八法妍。',48,'全唐诗/poet.song.40000.json','["憶昔祖姑前，曾觀八法妍。", "常嗟道韞在，終愧右軍傳。", "幻化已委世，清明當作仙。", "松門一長慟，丹旐上新阡。"]'),
('1fa1acaa-50c8-437a-ac0a-f18e21105b5a','初聞鶴唳','沈遼','宋','宋诗','song-poetry','','[]','海天寥寥禾黍秋，人籟已息烟霧收。',32,'全唐诗/poet.song.40000.json','["海天寥寥禾黍秋，人籟已息烟霧收。", "數聲鶴唳草堂靜，何苦更向咸陽游。"]'),
('0b21feb6-7edb-40c4-92ae-24fcab9efd71','和毅公賦謝仙','沈遼','宋','宋诗','song-poetry','','[]','常愛金泉謝自然，題詩多在蘂珠篇。',64,'全唐诗/poet.song.40000.json','["常愛金泉謝自然，題詩多在蘂珠篇。", "玄洲靈草自有種，西郭故人還作仙。", "飛馭飄搖誰可想，斷雲流散世空憐。", "錦江何處無由到，乞與齊諧異日傳。"]'),
('f57361c3-7c6a-4866-8217-27a8972abffa','和李正甫喜雨','沈遼','宋','宋诗','song-poetry','','[]','朝來靈雨下巖阿，秋氣歡聲到處多。',64,'全唐诗/poet.song.40000.json','["朝來靈雨下巖阿，秋氣歡聲到處多。", "頓起西疇千頃稻，斬新南浦萬重波。", "乍欣勝意閑尋賞，晚得髙吟更作魔。", "憔瘁病夫毛骨爽，匡床坐聽四明歌。"]'),
('0a09b3ed-f063-4e47-b25b-4bda45a4caa1','和李泰叔','沈遼','宋','宋诗','song-poetry','','[]','一身已與世相違，寧假虚名竹帛垂。',64,'全唐诗/poet.song.40000.json','["一身已與世相違，寧假虚名竹帛垂。", "老去讀書聊自遣，病多飲藥倚支持。", "長因斜日增離恨，却有秋風慰所思。", "屢辱髙吟不即報，使來多值欲眠時。"]'),
('8860eb79-79c0-4a4b-8358-70c2e648e7df','和清順','沈遼','宋','宋诗','song-poetry','','[]','世事咄咄非余知，常愛天籟林中吹。',80,'全唐诗/poet.song.40000.json','["世事咄咄非余知，常愛天籟林中吹。", "子雲老來亦嗜酒，秦女屢典釵頭螭。", "不忮不求自得趣，不知梅萼生南枝。", "昨日偶尋北山去，清曠正直窮冬時。", "道人相惱更題詩，信道匡鼎解人頤。"]'),
('7565e293-5901-4530-b6c2-42014a1beab7','龍居觀泉','沈遼','宋','宋诗','song-poetry','','[]','泉聲泠泠山間落，山下有田朝夕作。',96,'全唐诗/poet.song.40000.json','["泉聲泠泠山間落，山下有田朝夕作。", "東涇西瀆久已涸，夜來暴雨溪聲惡。", "我欲浮舟到西郭，山前灘瀨石鑿鑿。", "坐看横流出林薄，欲行未行翻不樂。", "朝市權利方相搏，民聲愁嘆入溝壑。", "不如曲几安寂寞，我享趙子清都樂。"]'),
('cc55e538-778d-4a46-b677-d9ba187fc07e','贈清道','沈遼','宋','宋诗','song-poetry','','[]','少年好書老彌篤，牙籖錦囊數百軸。',240,'全唐诗/poet.song.40000.json','["少年好書老彌篤，牙籖錦囊數百軸。", "江左墨妙世不矚，有唐諸公粗可錄。", "諸公草法無可稱，中葉始有張顛名。", "張顛下筆有神會，其妙不似點畫成。", "後來沙門有藏真，措意瀟灑尤更精。", "當時二子最名盛，至今學者皆伏膺。", "本朝蘇公名弟兄，汝南蒲陽亦有聲。", "比來諸公已老死，其餘卑俗類可憎。", "我昔乘興遊都城，列子示我新素屏。", "始知無擇得此道，長沙道人今復生。", "歸來窮巷掩柴荆，惠然相訪得忘形。", "贈我數行豈無意，勢如九河注滄溟。", "中間龍蜃降沒升，歡伏不暇獨可驚。", "自欲何能謝言情，欲贈金玉還愧輕。", "慇懃之揖喜不勝，使我驅霧老眼明。"]'),
('0a446d6d-49fd-4082-934d-293c00440161','贈覺師','沈遼','宋','宋诗','song-poetry','','[]','我昔乘興遊荆溪，數訪道人谿水西。',64,'全唐诗/poet.song.40000.json','["我昔乘興遊荆溪，數訪道人谿水西。", "道人飄然捨我去，有如白雲謝汙泥。", "我來雲間亦未久，惠然相顧攜枯藜。", "時人莫將老相識，解空第一須菩提。"]'),
('65f647f3-0ed3-4934-b19b-6ad47720b77a','酬楊髙士','沈遼','宋','宋诗','song-poetry','','[]','秋來當砌看金錢，不爲流年悵白顛。',64,'全唐诗/poet.song.40000.json','["秋來當砌看金錢，不爲流年悵白顛。", "已向滄洲逢九日，更欣髙士貺新篇。", "牛山誰見沾衣客，籬下空懷採菊賢。", "遙望白衣猶未至，不妨細雨竹窗前。"]'),
('01ee5e19-2715-45bf-b7e6-dbed2d140ff8','池陽  其一','沈遼','宋','宋诗','song-poetry','','[]','池南柳色未全黄，池北萱芽尚带霜。',32,'全唐诗/poet.song.40000.json','["池南柳色未全黄，池北萱芽尚带霜。", "老去尋春不嫌早，春深留與少年郎。"]'),
('b99c8204-c266-4c09-95ec-0cb04845b5bb','池陽  其二','沈遼','宋','宋诗','song-poetry','','[]','水南殘鐘水北清，浮雲斷處玉鈎明。',32,'全唐诗/poet.song.40000.json','["水南殘鐘水北清，浮雲斷處玉鈎明。", "持杯欲飲還看帽，十里春江如鏡平。"]'),
('804a6213-b5a3-4ed5-a22a-23b9a8d08420','池陽  其三','沈遼','宋','宋诗','song-poetry','','[]','寒烟寂寂鏁清谿，圓月亭亭上曲堤。',32,'全唐诗/poet.song.40000.json','["寒烟寂寂鏁清谿，圓月亭亭上曲堤。", "小杜風情遙可想，閑調絲竹舞金泥。"]'),
('4711484e-9d3c-4d51-b8ab-51d7063fb644','林平  其一','沈遼','宋','宋诗','song-poetry','','[]','林平勝處向東紆，水轉山迴畫不如。',32,'全唐诗/poet.song.40000.json','["林平勝處向東紆，水轉山迴畫不如。", "或息或勞都可樂，白雲深處五浮圖。"]'),
('a31d4eae-c798-468c-ae64-4f883b06addb','林平  其二','沈遼','宋','宋诗','song-poetry','','[]','河邊柳眼澹烟浮，臘破春歸一歲休。',32,'全唐诗/poet.song.40000.json','["河邊柳眼澹烟浮，臘破春歸一歲休。", "不復平時羈旅恨，離明還泊北城頭。"]'),
('64bd73ad-31c9-4db9-8fb1-62d7c929c4d7','西齋','沈遼','宋','宋诗','song-poetry','','[]','東齋清曠西齋靜，上下往來唯一徑。',32,'全唐诗/poet.song.40000.json','["東齋清曠西齋靜，上下往來唯一徑。", "幸有方床不得眠，行休已有陶潜興。"]'),
('0d03efc0-ace1-403d-9dc9-6e767542bdb7','雲間','沈遼','宋','宋诗','song-poetry','','[]','野田茫茫秋水清，生盡蒲蔍無人耕。',32,'全唐诗/poet.song.40000.json','["野田茫茫秋水清，生盡蒲蔍無人耕。", "不知三吳地力壯，老鶴空向烟中鳴。"]'),
('f4cb2b56-459c-46d7-8af4-e3346754b32e','陸機雲碑','沈遼','宋','宋诗','song-poetry','','[]','朝日欲出已復西，人間興廢那可知。',32,'全唐诗/poet.song.40000.json','["朝日欲出已復西，人間興廢那可知。", "崑山陵谷久已變，水旁唯有將軍碑。"]'),
('b02dd532-c2bd-49f4-affd-c9fc89f8419c','和宋平叔莫子謠','沈遼','宋','宋诗','song-poetry','','[]','南方氣候多不叙，茫茫萬生亦殊趣。',136,'全唐诗/poet.song.40000.json','["南方氣候多不叙，茫茫萬生亦殊趣。", "人性雖或異所宜，莫不知愛膚與肌。", "時方盛夏困多旱，髙堂方喜遂我私。", "有蟲名爲物甚小，樸樸無狀安能爲。", "諸公所賦雖甚美，盛道嘴吻良見欺。", "虎豹齒牙利如兵，我尚不畏矧此微，微物曾不如蚊虻。", "天生有命各有情，何用譏侮起紛爭。", "我心坦然如日月，我若呶呶我當罰。"]'),
('ec61ff31-55b2-4788-9884-574781c1ca20','過水心寺訪芝上人','沈遼','宋','宋诗','song-poetry','','[]','行年四十髪已斑，似夢非夢寄人間。',32,'全唐诗/poet.song.40000.json','["行年四十髪已斑，似夢非夢寄人間。", "數日秋風稍强健，閑尋戒律過南山。"]'),
('7811bb89-fded-4767-a1e4-7da0bfcdc1e1','泰叔召食鱠','沈遼','宋','宋诗','song-poetry','','[]','酷暑隆隆不可活，聞有玉鱗纖手割。',32,'全唐诗/poet.song.40000.json','["酷暑隆隆不可活，聞有玉鱗纖手割。", "不得相從飽便腹，空聽髙吟何灑落。"]'),
('09930a2b-9cc4-482d-9c46-01c8dad63358','泰叔求桂漿','沈遼','宋','宋诗','song-poetry','','[]','越人遠寄桂花漿，敝屋欣聞破鼻香。',32,'全唐诗/poet.song.40000.json','["越人遠寄桂花漿，敝屋欣聞破鼻香。", "遽遣小奴分送客，夜來已敗不堪嘗。"]'),
('d7f046ee-9d62-41db-94ae-971d0d39683b','次韻和宋平叔','沈遼','宋','宋诗','song-poetry','','[]','憶昔銜杯折梅處，孤山寺前千丈塘。',64,'全唐诗/poet.song.40000.json','["憶昔銜杯折梅處，孤山寺前千丈塘。", "横遮青林鬭殘雪，暗入紅袖留清香。", "往遊都城雖屢賞，縱有素艷終殊芳。", "莫辭遶林行百匝，更嚼嫩蕊薰愁腸。"]'),
('0c9a357d-5299-4be4-ae31-683035d08bd8','自懷','沈遼','宋','宋诗','song-poetry','','[]','十月北風流舶迴，官曹無事人吏稀。',64,'全唐诗/poet.song.40000.json','["十月北風流舶迴，官曹無事人吏稀。", "欲沽斗酒自爲樂，囊無一錢還典衣。", "平生懶性不預事，終老閑暇誰謂非。", "筋骨衰殘苦畏冷，更移方榻對斜暉。"]'),
('3dc01524-62c8-4df5-a3ac-9e9bdc7009eb','次韻和李正甫','沈遼','宋','宋诗','song-poetry','','[]','故國重尋梅柳春，自憐頭上二毛新。',64,'全唐诗/poet.song.40000.json','["故國重尋梅柳春，自憐頭上二毛新。", "已知憫默安無位，寧免低昂爲有身。", "前日少年都自夢，比來賤仕始憂貧。", "多慚幕府文章客，都爲風光作主人。"]'),
('0cd6a9dc-55a7-4455-a757-95b8387c492d','白鷺','沈遼','宋','宋诗','song-poetry','','[]','清江濯濯生菰蒲，一雙白鷺雪不如。',32,'全唐诗/poet.song.40000.json','["清江濯濯生菰蒲，一雙白鷺雪不如。", "輕烟細雨不肯去，潮來正有浮陽魚。"]'),
('ca90b396-cd8b-4dbf-8c9c-83344f3af47b','戲贈伯泓供備','沈遼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','公子好樂惟好琴，初傳一曲費千金。',64,'全唐诗/poet.song.40000.json','["公子好樂惟好琴，初傳一曲費千金。", "其聲微妙出世外，若聽無聞古與今。", "烏孫琵琶止四絃，濮上箜篌人不傳。", "西湖圓月籠修烟，一杯綠酒爲陶然。"]'),
('6476c243-0ad0-4e17-9318-c3874cc17737','題徑山二首  其一','沈遼','宋','宋诗','song-poetry','','[]','昔日道師開法筵，老人化龍去山前。',64,'全唐诗/poet.song.40000.json','["昔日道師開法筵，老人化龍去山前。", "至今勝迹冠西境，髙第相傳爲敬田。", "平生自得物外趣，爾來更薄區中緣。", "終隨老師學善住，行種芝草休天年。"]'),
('b7b5053f-899a-4937-a08b-f05a90bc5190','題徑山二首  其二','沈遼','宋','宋诗','song-poetry','','[]','五峰相望勢如掌，中有紺園閟龍象。',64,'全唐诗/poet.song.40000.json','["五峰相望勢如掌，中有紺園閟龍象。", "坦愛曲道兩盤迴，不知身出浮雲上。", "浮雲悠悠覆朝市，朝市小人鼎中沸。", "暫來欣得避世愁，奈我未老先白頭。"]'),
('a24aae02-96ec-491a-8296-f2396b5c83a0','和李子儀即元韻','沈遼','宋','宋诗','song-poetry','','[]','胡人泛舶萬里來，頭上㲲市纒作堆。',64,'全唐诗/poet.song.40000.json','["胡人泛舶萬里來，頭上㲲市纒作堆。", "建武賮琛終罷獻，元和亭榭不求材。", "君王方講羽干舞，太守何妨樂聖杯。", "筦庫賤生固多幸，天邊長見利篷開。"]'),
('0409de0f-ad61-4808-a871-81941a4dd039','和張寶臣即元韻','沈遼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','始余倦遊念還家，一身泛然寄天涯。',384,'全唐诗/poet.song.40000.json','["始余倦遊念還家，一身泛然寄天涯。", "頭上白髪日益加，朱顔不駐爐中砂。", "飄飄逸氣凌紫霞，猶著黄綬趨泥沙。", "烈日漫憑烏帽遮，窮巷歸來夕烟斜。", "閉門正欲謝喧譁，何憚屋室多庳窊。", "楊柳欲落鳴饑鴉，八月秋風想乘槎。", "市中有金誰攫挐，自欲歸耕老菑畬。", "嗜好已背梨與樝，那復開口增詉詉。", "眼昏白晝生黑花，老悲獨向兒女夸。", "枯轍不能活鱨魦，騏驥垂耳伏鹽車。", "一官欣得飽魚蝦，頓首致謁辭當衙。", "愚拙不遇何復嗟，川陸舊遊殊不遐。", "才渡揚子已聞蛙，吳女蓬鬢多髦髿。", "西湖信美謝若耶，松竹夾道繁根芽。", "勢利屈曲如盤蝸，衛青變化乃龍蛇。", "深閨召客舞雙髽，撫手相勸競呀呀。", "西崦老師自煮茶，太守陳樂奏渝巴。", "湖水洗面去塵痂，故山白浪留文沙。", "田裏小兒放猪猳，爲樂往往鳴簫笳。", "亦有狐兔堪施罝，令人指手徒爲挪。", "賤職馳使告及瓜，聿來甬東絕紛華。", "箝口不復露頰牙，聯曹相係瓊與葭。", "上官庇覆不汝瑕，優游重見林中葩。", "四時風露換物華，新詩迭致思無邪。"]'),
('31b8b9f3-fde0-4bcf-a880-c8eaa51658de','和李正甫','沈遼','宋','宋诗','song-poetry','','[]','山川旱氣赤如虹，大海半涸驚魚龍。',128,'全唐诗/poet.song.40000.json','["山川旱氣赤如虹，大海半涸驚魚龍。", "行人渴死道不通，時見飛鳶墜長空。", "日輪軋軋未背昃，獨坐髙堂酌瓊液。", "下視萬屋生白烟，不復平日瞻青山。", "閉目欲想瑤池瀕，欲往萬里增黄塵。", "長憶仙人李太白，若乘鯨魚應腐鱗。", "晚餐一盤薦黑黍，出鐺已敗色如土。", "忽得諸篇排硬言，伏讀未終汗如雨。"]'),
('e7200577-7f31-4ad5-8963-92b74e100700','和李泰叔見菊有感','沈遼','宋','宋诗','song-poetry','','[]','雨露蕭條歲景催，庭前黄菊未全開。',64,'全唐诗/poet.song.40000.json','["雨露蕭條歲景催，庭前黄菊未全開。", "揚雄嗜酒寧爲樂，杜甫愁吟亦薄材。", "故國欲歸行解綬，滄洲無路可浮杯。", "新亭秋興君知否，潮信方隨月色迴。"]'),
('c94a2e58-3a52-412c-98a7-7513fd1ebef4','酬海公即次元韻','沈遼','宋','宋诗','song-poetry','','[]','早遊諸方見佛祖，若能開口便相許。',96,'全唐诗/poet.song.40000.json','["早遊諸方見佛祖，若能開口便相許。", "長愛當時王老師，不開粗言反細語。", "大道逍遙本不遐，青天萬里孤鴻舉。", "比來多病卧環堵，低頭不茹亦不吐。", "上座何爲相示來，龍駒豈煩伯樂顧。", "更須歸去造丈室，擎拳便是諸魔路。"]'),
('04760f1d-4fcf-4796-a5cd-c316a0b687a8','方池','沈遼','宋','宋诗','song-poetry','','[]','森森古木蔭方池，池上秋來一夕知。',32,'全唐诗/poet.song.40000.json','["森森古木蔭方池，池上秋來一夕知。", "墜葉沉波青徹底，倚欄無事看魚嬉。"]'),
('3c0bc3c6-ec81-4fec-b573-09ddb27c1ffc','題上天竺','沈遼','宋','宋诗','song-poetry','','[]','平生未省人間樂，老去惟求世外閑。',32,'全唐诗/poet.song.40000.json','["平生未省人間樂，老去惟求世外閑。", "它日終當斷家事，籃輿蓬舸訪名山。"]'),
('fc1dc8f8-3a29-4a5a-887b-73a2facd70b5','走筆奉酬正夫即次元韻','沈遼','宋','宋诗','song-poetry','','[]','樂府古有行路難，但悲白髪憐朱顔。',272,'全唐诗/poet.song.40000.json','["樂府古有行路難，但悲白髪憐朱顔。", "時命多向賢才慳，詰屈不平萬世間。", "壯心欲馳步輒跚，試出鋒穎官已瘝。", "中心忽忽惓且煩，不如歸去江海閑。", "要懸大刀數撫鐶，何陋九夷與八蠻。", "自顧鄙性疏且頑，誰能隨時事黠姦。", "從來多病筋力孱，正當落魄卧深山。", "敝廬數椽粗可跧，安居里巷鎖重關。", "終日無人踐茅菅，冠带不修衣袂黫。", "髙歌一曲舞雲鬟，比鄰有酒時見頒。", "春風秋月與我閑，夜靜佩玉鳴珊珊。", "髙人逸士或往還，蓬舟自訪來前灣。", "行歌紅藥與香蘭，已憎俗物近塵寰。", "一身蕭然念早鰥，髭鬚憔悴半已斑。", "誰能更問秃與鬝，旦聽溪水聲潺潺。", "强來爲吏腰少彎，幸讀君詩錦繡篇。", "相望鬱鬱何可刪，君豈久居五兩綸。"]'),
('37b51aff-56b0-488a-be57-ea0305bd029e','聞杜鵑','沈遼','宋','宋诗','song-poetry','','[]','杜鵑花發春山明，杜鵑鳥啼行人驚。',96,'全唐诗/poet.song.40000.json','["杜鵑花發春山明，杜鵑鳥啼行人驚。", "世上有誰能忘情，一身離家作遠行。", "爲名受辱爲法攖，爲利被奪爲官爭。", "憂愁嗟蹙向誰說，那忽聽此斷腸聲。", "吾家家住在泉亭，烟水相望數月程。", "呼兒酤酒多酌客，聊用相慰如平生。"]'),
('70d8b7bc-f8a1-40cd-8085-e599f8f74a7e','次酬韻李正甫對雪','沈遼','宋','宋诗','song-poetry','','[]','苦寒冽冽日夜增，朔風軒軒勢相凌。',240,'全唐诗/poet.song.40000.json','["苦寒冽冽日夜增，朔風軒軒勢相凌。", "遙山頑碧空崚嶒，髙堂閑坐擁敝繒。", "欲釂一杯意已仍，浩歌黄竹但伏膺。", "愁雲漫漫方四騰，海氣上薄初不勝。", "雪霰雜下風作稜，漸著弱柳頭鬅鬙。", "半積軒砌發幽層，枯樹兀兀愁饑鷹。", "紛然不已失溝塍，一飲一斗心易矜。", "試步薄冰猶戰兢，圓圭方璧降復登。", "憶昔前年正嚴凝，攝事大蜡清晨興。", "平生看雪實未曾，健僕駿馬半醉乘。", "或前或後望交朋，不辨明河與玉澠。", "烈火萬炬氣不蒸，被面惟有凍與冰。", "歸來心目如水澄，喜看道旁刳作燈。", "豐年爲瑞古有稱，凍死何暇談鄒滕。", "欲邀君飲恨不能，相酬莫問準與繩。"]'),
('acd765f0-c5cf-46b5-a266-65abd986249a','行田舍','沈遼','宋','宋诗','song-poetry','','[]','輕烟微雨滿金塘，天氣清明看下秧。',32,'全唐诗/poet.song.40000.json','["輕烟微雨滿金塘，天氣清明看下秧。", "筋骨已衰難自力，田家次第賜壺漿。"]'),
('10efa96c-46df-45b3-8b00-9411dede7b31','題宸奎閣','沈遼','宋','宋诗','song-poetry','','[]','至和天仙臨御久，能通祖印空諸友。',64,'全唐诗/poet.song.40000.json','["至和天仙臨御久，能通祖印空諸友。", "化成殿上召禪師，親宣玉偈傳金口。", "鄮山山上建華閣，宸翰光芒燦星斗。", "江湖小臣稽首觀，永爲兹山傳不朽。"]'),
('526b13cd-bb74-483c-85a6-7bb5028adb47','次韻酬公夫二首  其一','沈遼','宋','宋诗','song-poetry','','[]','野性孱疏寄浩然，不邀虚譽借人延。',64,'全唐诗/poet.song.40000.json','["野性孱疏寄浩然，不邀虚譽借人延。", "賤官牽率終非意，故國歸休粗有田。", "平昔是非猶可計，後來去就孰爲賢。", "西軒一夢無餘事，不似南柯與世傳。"]'),
('edb00de1-d264-4e8b-9ec9-a53bc264949f','次韻酬公夫二首  其二','沈遼','宋','宋诗','song-poetry','','[]','海舶不來官事閑，朝雲夕雨看西山。',64,'全唐诗/poet.song.40000.json','["海舶不來官事閑，朝雲夕雨看西山。", "强從委吏心雖易，欲避宵人勢亦難。", "卧探古書聊自適，醉攀庭柯幸怡顔。", "因尋舊友清歡意，猶有榴裙數處斑。"]'),
('2dcf9d4d-bad2-4af0-9c34-4d887ac6670c','次韻酬李泰叔','沈遼','宋','宋诗','song-poetry','','[]','歲寒倚遍甬東樓，喜上江邊一葉舟。',64,'全唐诗/poet.song.40000.json','["歲寒倚遍甬東樓，喜上江邊一葉舟。", "流轉生涯常壁立，飄蕭官况信雲浮。", "欲逢故舊開青眼，先得詩章說白頭。", "縱有一樽聊可飲，正當相對論窮愁。"]'),
('eea6f344-8595-4fbf-9419-2820a371f2ab','召邵彦瞻','沈遼','宋','宋诗','song-poetry','','[]','青嶂疊疊西南馳，上下佛宮筋力疲。',32,'全唐诗/poet.song.40000.json','["青嶂疊疊西南馳，上下佛宮筋力疲。", "一樽欲與魯山醉，悵望車馬來何遲。"]'),
('a5d290c2-303d-4dff-9c56-add19d185c15','題垂雲亭','沈遼','宋','宋诗','song-poetry','','[]','老師有意出人間，便學垂雲也未閑。',32,'全唐诗/poet.song.40000.json','["老師有意出人間，便學垂雲也未閑。", "带雨有時歸北嶺，隨風依舊過南山。"]'),
('0948ad3b-9f77-4904-a74b-3c9525ec1387','次韻酬鄭榮緒','沈遼','宋','宋诗','song-poetry','','[]','長夏苦袢暑，何適可開眼。',180,'全唐诗/poet.song.40000.json','["長夏苦袢暑，何適可開眼。", "爲約山間行，遠訪金仙館。", "時當歲旱凶，人跡尚猶罕。", "况復有遊客，來結青雲伴。", "古松臨水瀕，我意秋可款。", "悵羨彼中人，一去不復返。", "髙深步巘崿，我道方坦坦。", "山僧多故人，不復怪敖誕。", "延我火齊柈，酌我流霞醆。", "少小不預事，老大更慵懶。", "巖花爲誰擷，藕絲悶獨綰。", "爾來復多雨，昨夜重湖滿。", "欲榜一舟歸，舟敝不可揀。", "世事久忘懷，吾言固無間。", "無樂亦無憂，亮非斗筲算。"]'),
('82aaf6cc-db25-4054-b673-bbcdff1d0144','夜坐有感','沈遼','宋','宋诗','song-poetry','','[]','齋閣夜不寐，耿耿對華燭。',96,'全唐诗/poet.song.40000.json','["齋閣夜不寐，耿耿對華燭。", "眼病懶讀書，投老亦忘欲。", "華寵非我願，終不蹈迫辱。", "五畝窮巷居，薄有數斗粟。", "歸來解衣袂，何爲愧仰屋。", "天晴步明月，雨暗一棋局。", "四夷正耀兵，百姓食不足。", "爲謝支離疏，吾方外羈束。"]'),
('1ac9e050-3665-4989-8afd-095ebb25ddfe','新作小屏','沈遼','宋','宋诗','song-poetry','','[]','少年喜讀書，偃仰在方床。',144,'全唐诗/poet.song.40000.json','["少年喜讀書，偃仰在方床。", "不知晝日勞，常愛秋夜長。", "炯炯戶牖明，翳翳燈燭光。", "我樂自有趣，驊騮步康莊。", "道學貴深思，千古浩無方。", "投機踐聖域，所戒怠且狂。", "常鄙小人儒，不能志軒昂。", "蹈襲已陳語，何爲浪皇皇。", "爾來四十歲，鬢髪已如霜。", "回首念疇昔，此意殊未忘。", "曲屏倚方枕，可以寄彷徉。", "誨言示稚子，朝夕當此强。"]'),
('bc83c39d-e683-4385-b962-65911666d3c3','開窗','沈遼','宋','宋诗','song-poetry','','[]','齋居病紆鬱，况復當梅霖。',48,'全唐诗/poet.song.40000.json','["齋居病紆鬱，况復當梅霖。", "鑿開小窗明，坐對佳樹陰。", "翠微映書帙，凉氣生衣襟。", "豈惟豁心目，聊可發幽吟。"]'),
('6196f86b-72f8-4d5d-8833-3613b59b6a54','和穎叔沖寂觀','沈遼','宋','宋诗','song-poetry','','[]','疇昔學輕舉，衰齡恨未逢。',144,'全唐诗/poet.song.40000.json','["疇昔學輕舉，衰齡恨未逢。", "慇懃尋福地，邂逅聽山鐘。", "陵阜規模古，烟霞氣象濃。", "滆湖開左派，勾曲聳西峰。", "宮殿瞻黄皓，風期想赤松。", "區中誠久厭，物外或能容。", "落日窺三島，陰雲隔九重。", "蛟淵無往害，兔井識遺蹤。", "遐企旌陽隱，旁鄰函里封。", "翹心冥有感，稽首敢忘恭。", "幽士期相訪，扁舟志未從。", "拳拳望仙境，尼父歎猶龍。"]'),
('7a4ebc22-1e30-41d7-8a02-05de99f4b912','奉陪穎叔賦吐綬鳥','沈遼','宋','宋诗','song-poetry','','[]','佛舍有珍羽，垂頷袐文綬。',96,'全唐诗/poet.song.40000.json','["佛舍有珍羽，垂頷袐文綬。", "對客輒復吐，粲粲如絺繡。", "其吐豈適然，乃在喜懼間。", "已吐亦復收，倉卒一瞬還。", "綠玉聳角毛，褐羽殊斕斑。", "方其振舞時，意氣艶且閑。", "吾欲語阿師，不如放深山。", "稻粱使自得，不復勞深關。"]'),
('874335e2-f512-4520-ba30-d42a33f9344f','奉陪穎叔和覺師','沈遼','宋','宋诗','song-poetry','','[]','疇昔欲求法，初參溈印禪。',48,'全唐诗/poet.song.40000.json','["疇昔欲求法，初參溈印禪。", "已知物外趣，頓謝區中緣。", "不學蘭那行，終歸兜率天。", "即心如有證，何暇問方圓。"]'),
('9694ef82-0108-4eff-9e14-ea0daf4195a3','復和  其一','沈遼','宋','宋诗','song-poetry','','[]','老師善言法，何者名爲禪。',48,'全唐诗/poet.song.40000.json','["老師善言法，何者名爲禪。", "不復著言句，應當離事緣。", "挹水何有用，攀雲誰望天。", "欲知證心要，爲我示偏圓。"]'),
('32bfaaf0-9c2a-4292-8b20-33a06fbac9cb','復和  其二','沈遼','宋','宋诗','song-poetry','','[]','耆窟清談妙，少林方坐禪。',48,'全唐诗/poet.song.40000.json','["耆窟清談妙，少林方坐禪。", "於世誠大事，投機非小緣。", "休公祗彈指，□老呼蒼天。", "子能分半座，爲畫相光圓。"]'),
('dd24954f-8d38-4645-9e12-7e8e860d08ef','惠聚上方','沈遼','宋','宋诗','song-poetry','','[]','卧病甬東久，偶尋吳會遊。',96,'全唐诗/poet.song.40000.json','["卧病甬東久，偶尋吳會遊。", "不知陶令意，乃與身爲讐。", "恤隱豈不美，更恐增人愁。", "黽勉有餘暇，强來訪林丘。", "此地多山石，鳥道與雲浮。", "松筠鬱回合，四顧皆良疇。", "僕本山野人，聊此謝羈愁。", "從容日已夕，歸意良悠悠。"]'),
('1cd4a830-7121-4ebf-a480-f8d40c5c185b','善權閲軒巖','沈遼','宋','宋诗','song-poetry','','[]','古寺寄林丘，清泉髙下流。',48,'全唐诗/poet.song.40000.json','["古寺寄林丘，清泉髙下流。", "山僧空自老，巖石不知秋。", "龍去潭水白，猿吟楓樹幽。", "軒前一楸局，誰與汝忘憂。"]'),
('cd13b453-da56-44bb-b701-99e38cdce35d','次韻和允中送覺師','沈遼','宋','宋诗','song-poetry','','[]','心在白雲居，逍遙誰復如。',48,'全唐诗/poet.song.40000.json','["心在白雲居，逍遙誰復如。", "從來機事少，終與俗情疏。", "師已脫敝屣，吾方還故廬。", "他年若相見，應更老渠渠。"]'),
('7370e667-df7f-43dc-8f57-c351ed24980d','戲呈慶復乞畫','沈遼','宋','宋诗','song-poetry','','[]','鷙鳥寧有種，詩書多不傳。',120,'全唐诗/poet.song.40000.json','["鷙鳥寧有種，詩書多不傳。", "豈期猛厲氣，專美鷹與鸇。", "有客畫鴉鶻，古紙含秋烟。", "羽毛被玄甲，爪角森戈鋋。", "想見太公望，桓桓統中權。", "何如鄞中尉，側目誰敢前。", "吾方病拘鬱，逍遙溪水邊。", "賞此神駿物，霜風相孤騫。", "從公乞妙墨，小齋伴衰孱。", "何以報雅况，作詩致拳拳。"]'),
('965f3509-fbd7-410c-ab0e-6bd03b02375e','秋早登住閣','沈遼','宋','宋诗','song-poetry','','[]','病夫倦拘鬱，遐賞寄重閣。',144,'全唐诗/poet.song.40000.json','["病夫倦拘鬱，遐賞寄重閣。", "大火欲西流，髙林已搖落。", "海旁土氣淺，風雨易回薄。", "數日多狂飇，餘暑亦濳卻。", "千山在天際，清氣遙可託。", "平生樂烟霞，幽步誰與約。", "緬懷機雲輩，襟靈信夷廓。", "草草蹈危機，千載尚可啄。", "吾知非世用，白首甘寂寞。", "攝令亦偶然，何能求民瘼。", "勾釘盡誅斂，下筆良多怍。", "不如陳太丘，行歸老丘壑。"]'),
('90064849-78ed-47e7-986d-be63cb60aa5b','雲間','沈遼','宋','宋诗','song-poetry','','[]','蠟屐去陽羨，乘桴望雲間。',48,'全唐诗/poet.song.40000.json','["蠟屐去陽羨，乘桴望雲間。", "腰垂陶令印，意在莊生環。", "斯民久困敝，何用惠孤瘝。", "於心儻有愧，拂衣歸故山。"]'),
('83a38c8c-2aef-4220-8048-9eaaed7150de','奉送景升西上','沈遼','宋','宋诗','song-poetry','','[]','京口楊夫子，知名三十秋。',96,'全唐诗/poet.song.40000.json','["京口楊夫子，知名三十秋。", "青衫尚爲邑，相見松江頭。", "傾蓋曾未久，歡若平生遊。", "適當及瓜代，浩然治西舟。", "薦章滿公車，行想拜恩休。", "萬里起跬步，青雲眇難儔。", "余方歸東路，於此悵夷猶。", "行觴莫辭醉，分袂雲間樓。"]'),
('6f459306-2fae-4567-9639-a5755e805c39','奉和宋平叔','沈遼','宋','宋诗','song-poetry','','[]','海角厭多雨，乍晴山更嘉。',48,'全唐诗/poet.song.40000.json','["海角厭多雨，乍晴山更嘉。", "梅林半黄熟，柳带剩夭斜。", "忽忽久不懌，悠悠誰可涯。", "世如有夫子，終不歎匏瓜。"]'),
('f51cfbd0-2386-4133-8ede-3eeafc852d2b','題上天竺天仙閣','沈遼','宋','宋诗','song-poetry','','[]','久厭朝市冗，粗能忘蓋纒。',72,'全唐诗/poet.song.40000.json','["久厭朝市冗，粗能忘蓋纒。", "頭依梵唄地，行結西方緣。", "山前種香稻，山下流清泉。", "此地既岑寂，此心良泰然。", "法師清淨觀，招我修初禪。", "斯言倘不踐，何路休餘年。"]'),
('794dd038-e259-4a70-ae57-7812986cb5b6','次韻酬泰叔','沈遼','宋','宋诗','song-poetry','','[]','志士有不遇，繇來多感傷。',288,'全唐诗/poet.song.40000.json','["志士有不遇，繇來多感傷。", "末途長憫默，往事委冥茫。", "偃蹇乾坤外，推移日月長。", "初心寄林壑，何事襲軒裳。", "才地慚前輩，文華笑老蒼。", "討論聊自適，仕進亦惟惶。", "直欲馳千里，寧誰出一鄉。", "典謨窺禹契，教化識軒唐。", "不信時難駕，焉知命弗將。", "士雖殊用舍，吾豈托炎凉。", "寶劍埋霜鏑，明珠稱夜光。", "三公猶可去，一命孰難忘。", "壯節深無累，髙歌詠更鏘。", "振衣辭旦望，逸跡寄朱張。", "管庫心何愧，江湖幸退藏。", "朝辭汴師日，夜渡淛河霜。", "故國尋仙路，當年結客場。", "二毛雖老醜，一醉迺尋常。", "花圃風生席，雲齋月滿床。", "清歌憐落落，髙論接琅琅。", "誰謂羈遊地，還陪君子觴。", "衆推朋好厚，不間弟兄行。", "斟酌南堂夜，逍遙甬水陽。", "長篇荷髙意，他日結離腸。"]'),
('08026325-d49f-4092-a0c0-3d5b8727d525','庭柏','沈遼','宋','宋诗','song-poetry','','[]','鬱鬱庭下柏，何年移此栽。',48,'全唐诗/poet.song.40000.json','["鬱鬱庭下柏，何年移此栽。", "雖然失地性，本自凌雲材。", "不復鸞鳳集，空餘鳥雀來。", "誰爲許長史，拔宅去塵埃。"]'),
('10486dfd-a8f8-4088-a71a-d9bc4daaf49a','竹軒','沈遼','宋','宋诗','song-poetry','','[]','古人愛修竹，瀟灑臨幽軒。',48,'全唐诗/poet.song.40000.json','["古人愛修竹，瀟灑臨幽軒。", "勁節有髙致，清聲無俗喧。", "春日鬭鏁碎，秋風撼琅玕。", "誰知渭川富，千畝可懸冠。"]'),
('101e7f35-3208-40a7-a374-b8932b7bebad','黄鸝一聲','沈遼','宋','宋诗','song-poetry','','[]','陰陰三四木，官舍悄無鄰。',48,'全唐诗/poet.song.40000.json','["陰陰三四木，官舍悄無鄰。", "何處黄鸝囀，來驚白髪新。", "浪隨殊俗過，可負舊山春。", "自笑親香火，看經作鈍人。"]'),
('fdde94e1-cce5-4f8f-a2b1-16acffed45a0','舟行','沈遼','宋','宋诗','song-poetry','','[]','我舟莫行疾，我家日已遠。',48,'全唐诗/poet.song.40000.json','["我舟莫行疾，我家日已遠。", "行遲終不到，不到何由返。", "吳楚千萬里，江山道回轉。", "白頭多傷感，方寸不勝亂。"]'),
('ddc43be6-7c25-422d-a666-2514322ea154','道中','沈遼','宋','宋诗','song-poetry','','[]','昔我離家時，月生正如鈎。',96,'全唐诗/poet.song.40000.json','["昔我離家時，月生正如鈎。", "行行載見月，已在天南頭。", "我身豈當然，吏議不可酬。", "下手亦何愧，搖尾終無求。", "默默就孤征，悽悽懷百憂。", "吳山望不盡，已泛楚江流。", "木落知歲寒，客子多悲愁。", "一慟一斗血，安能望松楸。"]'),
('e19c21c6-126a-44f8-946f-a71fe40596ce','九龍洞','沈遼','宋','宋诗','song-poetry','','[]','洞中石乳色如霜，欲煮刀圭未得方。',32,'全唐诗/poet.song.40000.json','["洞中石乳色如霜，欲煮刀圭未得方。", "嘆息此生來已晚，更將殘命笑嵇康。"]'),
('49a63154-f08d-4908-acc4-84c88ab7df3a','西津','沈遼','宋','宋诗','song-poetry','','[]','山後山前到已頻，更尋殘雪過西津。',32,'全唐诗/poet.song.40000.json','["山後山前到已頻，更尋殘雪過西津。", "愚溪愁客今何在，應有猿猱解笑人。"]'),
('930d7e6c-9689-4f5d-abf8-3db5e00851aa','讀書','沈遼','宋','宋诗','song-poetry','','[]','病骨愔愔百不如，不應投老更看書。',32,'全唐诗/poet.song.40000.json','["病骨愔愔百不如，不應投老更看書。", "古今得喪今方辨，且向斜陽弄蠧魚。"]'),
('02b166a9-6a35-4d14-aafa-725001353d16','愚溪','沈遼','宋','宋诗','song-poetry','','[]','愚溪水中多圓石，水邊竹樹山如壁。',32,'全唐诗/poet.song.40000.json','["愚溪水中多圓石，水邊竹樹山如壁。", "夫子幽棲十二年，至今使人長嘆息。"]'),
('371bb0a8-d236-4411-9255-43f8c9bda522','雜詩  其一','沈遼','宋','宋诗','song-poetry','','[]','白雲非我役，出沒在山間。',48,'全唐诗/poet.song.40000.json','["白雲非我役，出沒在山間。", "我亦何所事，籃輿自往還。", "不知樂與否，聊爾寄衰孱。", "早恨冠冕誤，空令鬢毛斑。"]'),
('5d699b5f-f988-4a04-82fd-21b30a4c1683','雜詩  其二','沈遼','宋','宋诗','song-poetry','','[]','我昧明哲戒，置身在天涯。',48,'全唐诗/poet.song.40000.json','["我昧明哲戒，置身在天涯。", "憫憫常畏人，豈異池中蛙。", "吳山千萬里，夢寐不到家。", "永懷故山樂，輕舟棹烟霞。"]'),
('86e8d943-dd55-4429-829d-0cb141edbe5b','雜詩  其三','沈遼','宋','宋诗','song-poetry','','[]','屈平作天問，委骳窮不悔。',48,'全唐诗/poet.song.40000.json','["屈平作天問，委骳窮不悔。", "寥寥千載還，柳子强復對。", "二子誠多材，無乃振憔悴。", "區區亦何爲，吾方游物外。"]'),
('4d96dc17-87e1-493e-9ac3-e5b6b167bd56','雜詩  其四','沈遼','宋','宋诗','song-poetry','','[]','巨蛇老且蛻，不如蟬脫飛。',72,'全唐诗/poet.song.40000.json','["巨蛇老且蛻，不如蟬脫飛。", "茫然寄坱圠，生死亦一歸。", "達人觀元化，其言玄且微。", "生死有不類，於是知者稀。", "秋池夜觀月，方與水相輝。", "聊爾乘物化，指象終爲非。"]'),
('98119eb1-4dce-4daa-9487-72478a887887','詒隱者二首  其一','沈遼','宋','宋诗','song-poetry','','[]','汝勿輕王侯，王侯非汝曹。',48,'全唐诗/poet.song.40000.json','["汝勿輕王侯，王侯非汝曹。", "地勢有輕重，太山與鴻毛。", "鼓腹一歡笑，不知鐘鼓豪。", "我樂彼不預，山林且陶陶。"]'),
('e2e39b9e-12a2-41a8-b3fb-66f6029fdd99','詒隱者二首  其二','沈遼','宋','宋诗','song-poetry','','[]','訪我維摩室，不值香積飰。',48,'全唐诗/poet.song.40000.json','["訪我維摩室，不值香積飰。", "開囊出黄粟，爲汝林中爨。", "軟語少稽留，青蔬亦易辦。", "勿言方外趣，我汝真如幻。"]'),
('6a7e526f-9088-4cd5-abcf-b980f1064593','善飲','沈遼','宋','宋诗','song-poetry','','[]','誰道淵明不善飲，亦知太白愛題詩。',32,'全唐诗/poet.song.40000.json','["誰道淵明不善飲，亦知太白愛題詩。", "浪醉浪吟成底事，不如髙卧過當時。"]'),
('1b70eb8f-4a1c-4265-967c-48a0146c0dd0','夷山','沈遼','宋','宋诗','song-poetry','','[]','夷山邈無際，落日多青烟。',48,'全唐诗/poet.song.40000.json','["夷山邈無際，落日多青烟。", "渺渺寄愁恨，吾知從古然。", "逝者既已矣，後來誰可言。", "達生亦有意，吾歸將灌園。"]'),
('3747ab88-01e5-42f8-9d44-c7388a375311','晉室','沈遼','宋','宋诗','song-poetry','','[]','晉室昔中圯，正人多戮死。',72,'全唐诗/poet.song.40000.json','["晉室昔中圯，正人多戮死。", "加害寧無辭，惟其不徇己。", "朝室有難置，山林或能已。", "誰云清議在，美玉不全燬。", "曠達余所嘉，數欲玩遺史。", "撫卷輒增感，終夕那復理。"]'),
('30bd3d37-e9bd-4a93-8963-39af5e143f8e','東嶺','沈遼','宋','宋诗','song-poetry','','[]','東嶺寄吾廬，西崦多屐齒。',84,'全唐诗/poet.song.40000.json','["東嶺寄吾廬，西崦多屐齒。", "何爲不憚陟，下視湘川水。", "此水不湧激，朝暮流未已。", "烟雲媚幽趣，落日更清泚。", "徙倚有髙木，獨往每自喜。", "山猿助我嘯，幽鳥司我跂。", "山僧忽吾怪，使汝識善逝。"]'),
('9bf73aca-e895-4c78-b458-825dafc319d6','水車','沈遼','宋','宋诗','song-poetry','','[]','黄葉渡頭春水生，江中水車上下鳴。',32,'全唐诗/poet.song.40000.json','["黄葉渡頭春水生，江中水車上下鳴。", "誰道田間得機事，不如抱甕可忘情。"]'),
('97e688ed-0785-4e78-83c1-72377e02c950','召楚興禪師','沈遼','宋','宋诗','song-poetry','','[]','匡床我示維摩疾，持鉢師來舍衛城。',32,'全唐诗/poet.song.40000.json','["匡床我示維摩疾，持鉢師來舍衛城。", "與汝欲分香積飯，不妨作戯說浮生。"]'),
('92f08e04-7d78-4e8c-bcd8-eee07659e36e','春日二絕  其一','沈遼','宋','宋诗','song-poetry','','[]','壁下茶鐺久不黔，更無白眼與人嫌。',32,'全唐诗/poet.song.40000.json','["壁下茶鐺久不黔，更無白眼與人嫌。", "春來老困還多睡，時有狂風入破簾。"]'),
('f3da39d6-3f95-40e9-aece-ecf2d97b0893','春日二絕  其二','沈遼','宋','宋诗','song-poetry','','[]','寂寂山間誰與言，悶搔短髪向香烟。',32,'全唐诗/poet.song.40000.json','["寂寂山間誰與言，悶搔短髪向香烟。", "死灰朽木君知否，不似胡人面壁禪。"]'),
('0f97b096-ce69-4f9e-90c7-9cf5f41afaff','楊花','沈遼','宋','宋诗','song-poetry','','[]','島夷三月不知春，唯有楊花似故人。',32,'全唐诗/poet.song.40000.json','["島夷三月不知春，唯有楊花似故人。", "老大相逢何可語，滿頭白髪不勝嚬。"]'),
('67110058-cb31-419a-8e30-6816850cb923','樂神','沈遼','宋','宋诗','song-poetry','','[]','夷人事神正自醵，山頭水邊與神樂。',64,'全唐诗/poet.song.40000.json','["夷人事神正自醵，山頭水邊與神樂。", "大巫龐衣手搖鐸，羣兒伐鼓更鳴角。", "青山歷歷神欲歸，湘水灕灕日脚西。", "小大酣歌向山棲，神羮滿盎均汝釐。"]'),
('f4c2e01b-7097-4f4b-89e6-ab341a62a69e','山上','沈遼','宋','宋诗','song-poetry','','[]','山上桃花紅欲燒，山間病老苦無聊。',70,'全唐诗/poet.song.40000.json','["山上桃花紅欲燒，山間病老苦無聊。", "古人有時亦好飲，已醉復醒真似勞。", "誰能忘情學枯木，不如隱几看猿猱。", "攀援上下豈無意，新林落日風{風噪}{風噪}。"]'),
('6416d406-136f-427d-b235-81d80cef1124','李華','沈遼','宋','宋诗','song-poetry','','[]','山僧種李華，華白誰肯折。',48,'全唐诗/poet.song.40000.json','["山僧種李華，華白誰肯折。", "春風欲去時，庭前紛如雪。", "綠葉始有芽，繁香且未歇。", "鬱陶何可道，空庭步明月。"]'),
('fa2cc32b-42da-433a-b469-0b3906e4dafd','日落','沈遼','宋','宋诗','song-poetry','','[]','日落沙頭山已昏，饑烏投暝下前村。',32,'全唐诗/poet.song.40000.json','["日落沙頭山已昏，饑烏投暝下前村。", "誰云野客無多事，步出林間自掩門。"]'),
('803fe7ff-e28b-41b4-bbb0-1a2d4f88d79d','黄鸝','沈遼','宋','宋诗','song-poetry','','[]','黄鸝何處來，啼我夷即下。',48,'全唐诗/poet.song.40000.json','["黄鸝何處來，啼我夷即下。", "綠葉掩窮陬，春容已衰謝。", "百年如轉轂，悲歡正相駕。", "感事一傷懷，吾年四十化。"]'),
('78d80068-999e-4722-a8be-d11dffef86c0','春林','沈遼','宋','宋诗','song-poetry','','[]','春林日已繁，隔我遙山青。',48,'全唐诗/poet.song.40000.json','["春林日已繁，隔我遙山青。", "下簾成幽卧，野鳥鳴嚶嚶。", "鳥鳴有時息，春林亦衰寂。", "生物自環轉，何心翻戚戚。"]'),
('63a93676-856a-4bc8-9c81-66b7cab88a24','散郎亭','沈遼','宋','宋诗','song-poetry','','[]','法華寺上散郎亭，老樹蒼崕如有情。',32,'全唐诗/poet.song.40000.json','["法華寺上散郎亭，老樹蒼崕如有情。", "歡戚已隨時事去，代間秪有古人名。"]'),
('1b150cf7-32d3-4a86-b253-c7c7684e87e1','棗花寒','沈遼','宋','宋诗','song-poetry','','[]','山禽哺雛半欲摶，坐想葛帔臨風湍。',32,'全唐诗/poet.song.40000.json','["山禽哺雛半欲摶，坐想葛帔臨風湍。", "數日陰霖復未暢，不知更作棗花寒。"]'),
('0df32a6c-5328-432b-a7fc-4dc2c2ccae3b','讀書','沈遼','宋','宋诗','song-poetry','','[]','讀書十車老已忘，人生得意須少壯。',64,'全唐诗/poet.song.40000.json','["讀書十車老已忘，人生得意須少壯。", "白髪漸多筋力衰，誰爲流年更惆悵。", "自寄蠻夷朋舊稀，更將黄卷卧斜暉。", "古來枉直何足道，昨日皦皦今還非。"]'),
('d00e0e93-6b1f-4488-b753-702cca285ad5','觀大水望朝陽巖','沈遼','宋','宋诗','song-poetry','','[]','前日巖間欲結廬，下眺江水百步餘。',64,'全唐诗/poet.song.40000.json','["前日巖間欲結廬，下眺江水百步餘。", "春水濺濺出乳竇，青山白石半洿塗。", "不到津頭已三月，誰知江水漲天墟。", "遙望横流不敢濟，巖口已有人罾魚。"]'),
('0c2dad2c-f557-4645-b835-c3c00da4aa37','滄洲亭懷古','沈遼','宋','宋诗','song-poetry','','[]','瀟水悠悠天際來，夾江古木抱山回。',64,'全唐诗/poet.song.40000.json','["瀟水悠悠天際來，夾江古木抱山回。", "柵中人物不滿把，日晏市散多蒼苔。", "九疑巉天古雲埋，遙想帝子龍車迴。", "心衰目極何可望，九歌寂寂令人哀。"]'),
('89ae2959-fc02-415d-8cf1-e786336ad765','奉送伯才都官代歸','沈遼','宋','宋诗','song-poetry','','[]','前日使君佩銅魚，雅望已合升華塗。',64,'全唐诗/poet.song.40000.json','["前日使君佩銅魚，雅望已合升華塗。", "一遭黯黮誠非辜，人爲歎憤我若無。", "夷州已非人所居，况復筦庫治贏餘。", "幸及瓜時笑還都，襟懷落落真丈夫。"]'),
('9cc6e528-1974-42e0-86e6-26a706164696','次韻答陳生問禪','沈遼','宋','宋诗','song-poetry','','[]','從來多事笑歸宗，我已無心豈有通。',64,'全唐诗/poet.song.40000.json','["從來多事笑歸宗，我已無心豈有通。", "達士猶能知夢夢，世人何用更空空。", "江頭冷落三秋月，山半支離一病翁。", "不到古今能與否，林間拭目看來鴻。"]'),
('6cf61623-eefd-43b8-af05-d843ae57f1e3','出瀟江泊蒲洲','沈遼','宋','宋诗','song-poetry','','[]','汎汎瀟江水，天生西北流。',48,'全唐诗/poet.song.40000.json','["汎汎瀟江水，天生西北流。", "蒼烟開蛋市，曉日下蒲洲。", "清曠適幽步，方洋如昔游。", "何爲沙上鳥，相避小山頭。"]'),
('8ceb0d2b-7906-45be-a989-6d4165f4ef93','水車','沈遼','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山田遶山脚，江水何可作。',96,'全唐诗/poet.song.40000.json','["山田遶山脚，江水何可作。", "車輪十丈圍，飛湍半天落。", "雁翅插修筦，隨流得深酌。", "升降豈無勢，長江怒相薄。", "有如萬夫力，讙呼傾衆壑。", "曾不捨晝夜，美源終未涸。", "人間有機事，由來生巧惡。", "善彼漢陰老，忘懷抱純朴。"]'),
('f55e747e-82f7-44ab-8670-96c92eb0a7e5','復作過商翁墓  其一','沈遼','宋','宋诗','song-poetry','','[]','當年不佩封侯印，後世誰尋墮淚碑。',64,'全唐诗/poet.song.40000.json','["當年不佩封侯印，後世誰尋墮淚碑。", "定遠將軍豈夸勇，關南常侍最能詩。", "故人不解傳遺事，五嶺猶能識信旗。", "墓下寂寥無鼓角，秋風獨向白楊悲。"]'),
('c3b2da49-a174-4c40-9267-238f5951a2ce','復作過商翁墓  其二','沈遼','宋','宋诗','song-poetry','','[]','平生氣業許誰知，官制應崇九尺碑。',64,'全唐诗/poet.song.40000.json','["平生氣業許誰知，官制應崇九尺碑。", "已爲朝廷恢遠略，不應江漢獨無詩。", "交牙石鎖先偏陣，野燒光開後隊旗。", "老婦尫殘誰主奠，從來伯道使人悲。"]'),
('f141e05a-8276-4b36-8e3a-c5a2b6a6a8b4','復作過商翁墓  其三','沈遼','宋','宋诗','song-poetry','','[]','同預楊公國士知，延陵應得我題碑。',64,'全唐诗/poet.song.40000.json','["同預楊公國士知，延陵應得我題碑。", "人間已悟黄粱夢，泉下誰尋古劍詩。", "邕管已聞圖像祭，廣源無復納降旗。", "水禽山鳥無人意，獨解飛鳴不解悲。"]'),
('ee4aad2b-1b30-4f88-a643-15cf4b19a29f','復作過商翁墓  其四','沈遼','宋','宋诗','song-poetry','','[]','蒼頭已作歸來曲，不信全生庾氏碑。',64,'全唐诗/poet.song.40000.json','["蒼頭已作歸來曲，不信全生庾氏碑。", "疑有史官爭立傳，終無嗣子與聞詩。", "後房已閉千金妓，私廟空收五采旗。", "聞說詔書優贈典，孤魂應結九泉悲。"]'),
('e7216476-c531-42f9-bf99-814952abed15','庭下菊','沈遼','宋','宋诗','song-poetry','','[]','夷天九月尾，秋氣殊未肅。',72,'全唐诗/poet.song.40000.json','["夷天九月尾，秋氣殊未肅。", "病士蒙葛衣，正如庭下菊。", "憶昔移菊初，夏暑方煩溽。", "瘴山旱無雨，憔悴兹不足。", "安得望茅茨，竊自譬松竹。", "神仙久視藥，孤根寄窮谷。"]'),
('75563d91-601b-443f-b3de-e983c54bc893','鈷鉧潭','沈遼','宋','宋诗','song-poetry','','[]','余讀子厚書，始聞鈷鉧潭。',120,'全唐诗/poet.song.40000.json','["余讀子厚書，始聞鈷鉧潭。", "榜舟西江下，振步愚溪南。", "髙下凌山阿，松篁蔽秋嵐。", "土人識其地，古木森楩楠。", "水深日波瀾，此理亦易探。", "古木爲鈷鉧，土音正相參。", "所記或不然，信書殊未甘。", "此公廢已久，山水窮年耽。", "造化毫楮間，浮實微相錟。", "幽心有默識，西歸助清談。"]'),
('a0879b10-7941-4dd2-b778-5bfbad22acab','寄題聱隅塚亭','沈遼','宋','宋诗','song-poetry','','[]','不識聱隅生，斯人亦豪怪。',96,'全唐诗/poet.song.40000.json','["不識聱隅生，斯人亦豪怪。", "挾書海上來，軒昂軼前輩。", "何爲老窮阨，獨與當時背。", "寵禄出一時，此書終不廢。", "客死江都館，骸骨埋荒穢。", "幸會田使君，開塋北門外。", "浮屠清曠地，馬鬣森松檜。", "百年一抔土，誰當論窮泰。"]'),
('04179590-bb9d-469a-becd-81f120261280','龍興觀','沈遼','宋','宋诗','song-poetry','','[]','山林搖落江水寒，松下古觀生秋蘭。',74,'全唐诗/poet.song.40000.json','["山林搖落江水寒，松下古觀生秋蘭。", "白日無人午夜靜，玉皇殿上朝仙官，但聞金環玉佩鳴珊珊。", "麻姑女子不下壇，有誰乞得延齡丹。", "人生不如爲善好，草頭曉露空潸潸。"]'),
('02d426f0-2e5d-464a-9a60-d7a093582f26','還湘南集','沈遼','宋','宋诗','song-poetry','','[]','蚤識陶公父子名，未知李老思尤清。',32,'全唐诗/poet.song.40000.json','["蚤識陶公父子名，未知李老思尤清。", "後來無復能文客，瀟水湘山空月明。"]'),
('b9c193c4-1453-4653-86c6-5df239c6f3fe','過李氏澹塘别墅','沈遼','宋','宋诗','song-poetry','','[]','淵明昔已愛吾廬，我亦悁悁憶故居。',32,'全唐诗/poet.song.40000.json','["淵明昔已愛吾廬，我亦悁悁憶故居。", "君有東臯千束稻，山前更望澹塘湖。"]'),
('d9d571d7-b809-4c33-b93e-7d6defe3aaf6','答林夫五頌次元韻  其一','沈遼','宋','宋诗','song-poetry','','[]','無心難與有心期，欲說無心已自癡。',32,'全唐诗/poet.song.40000.json','["無心難與有心期，欲說無心已自癡。", "會得金剛本來性，此人與我合先知。"]'),
('516dc690-9e2d-4fa2-bbd4-5106736e1daa','答林夫五頌次元韻  其二','沈遼','宋','宋诗','song-poetry','','[]','白髪生來何可驚，不求雜食豈須耕。',32,'全唐诗/poet.song.40000.json','["白髪生來何可驚，不求雜食豈須耕。", "山間一榻無餘事，但看山花枯復榮。"]'),
('35b8972b-d21c-4acb-82e6-95fa6c406a2e','答林夫五頌次元韻  其三','沈遼','宋','宋诗','song-poetry','','[]','海水浩蕩烟蒼茫，我欲求渡無舟航。',32,'全唐诗/poet.song.40000.json','["海水浩蕩烟蒼茫，我欲求渡無舟航。", "東西路迷何苦渡，楞伽山下秋風涼。"]'),
('5e3a134d-5d7f-49d7-bd84-060ef7da69f0','答林夫五頌次元韻  其四','沈遼','宋','宋诗','song-poetry','','[]','世間明闇一毫端，爲底忙時不肯閑。',32,'全唐诗/poet.song.40000.json','["世間明闇一毫端，爲底忙時不肯閑。", "水盛草深牛不動，始知緣業有多般。"]'),
('0634672e-6d8d-472d-954a-4c8db656437d','答林夫五頌次元韻  其五','沈遼','宋','宋诗','song-poetry','','[]','阿彌陀佛一爐香，欲道知時已是狂。',32,'全唐诗/poet.song.40000.json','["阿彌陀佛一爐香，欲道知時已是狂。", "若得醫師除我病，何煩筋力更求方。"]'),
('c1f686e4-2723-449f-b664-1664a7326c82','有感','沈遼','宋','宋诗','song-poetry','','[]','我身如斷蓬，我性如孤鶴。',72,'全唐诗/poet.song.40000.json','["我身如斷蓬，我性如孤鶴。", "飄搖寄林野，不復人間樂。", "豈如雞與犬，朱門肆依託。", "雖沐稻粱恩，安能遠嫌薄。", "理或不在我，幽懷放寥廓。", "人生能幾時，百年共搖落。"]'),
('15014cfe-8d60-453b-bcd3-67d0fdbac686','贈飲客','沈遼','宋','宋诗','song-poetry','','[]','鄙性不嗜飲，不知酒中樂。',96,'全唐诗/poet.song.40000.json','["鄙性不嗜飲，不知酒中樂。", "古人能閉關，此興應可度。", "形骸委物外，寵利安能薄。", "何爲攘臂人，喧卑同燕雀。", "朝揮百神王，夕引羣憂涸。", "疇昔二三公，逃死向杯杓。", "我樂不在是，陶然造沖漠。", "子當劇醉時，相訪南山脚。"]'),
('5c780065-51ba-4ae0-9ad9-4c1933d023d6','雪後','沈遼','宋','宋诗','song-poetry','','[]','瀟川夜飛雪，草舍朝成冰。',48,'全唐诗/poet.song.40000.json','["瀟川夜飛雪，草舍朝成冰。", "微陽始下燭，南山浩如蒸。", "林木散孚甲，烏鳥營巢橧。", "物化不可戚，深挹南天僧。"]'),
('bee9250f-66ef-4f3b-937d-d83181483942','次韻酬陳生求書','沈遼','宋','宋诗','song-poetry','','[]','老朽何心託市朝，正當鼓腹詠軒堯。',64,'全唐诗/poet.song.40000.json','["老朽何心託市朝，正當鼓腹詠軒堯。", "由來方外希夷樂，漸與人間路徑遙。", "澤畔應無漁父問，松間時聽葛天謠。", "髯君莫及兒童伎，留取褚中翡翠翹。"]'),
('099dfd71-53b9-48af-8078-abc180e7940d','贈廣祐上人','沈遼','宋','宋诗','song-poetry','','[]','不入四明路，侵尋已十年。',48,'全唐诗/poet.song.40000.json','["不入四明路，侵尋已十年。", "葛藤論往事，蟬蛻想蒼烟。", "松下數株石，巖前千丈泉。", "何爲不肯往，芒屩更參禪。"]'),
('8fdd30ff-0ad8-49f2-9aba-26f4d883a2d7','奉送馬令歸長沙','沈遼','宋','宋诗','song-poetry','','[]','腰間新佩臨桂章，歸著綵衣拜髙堂。',64,'全唐诗/poet.song.40000.json','["腰間新佩臨桂章，歸著綵衣拜髙堂。", "鴻雁知時自翔翥，驊騮得路方騰驤。", "正煩絃歌治疲俗，仰看干羽來降王。", "憔悴山間老遷客，不能相送出瀟湘。"]'),
('be845dc0-002c-4928-bf6b-56009548a146','奉贈玉笥王尊師','沈遼','宋','宋诗','song-poetry','','[]','玉笥羽人不絕食，鬢毛清潤顔色赤。',96,'全唐诗/poet.song.40000.json','["玉笥羽人不絕食，鬢毛清潤顔色赤。", "中黄仙翁傳妙經，十年功成人不識。", "身如孤雲行無迹，欲上九疑望南極。", "岣嶁不見神禹碑，瀟湘真得浮丘伯。", "城南濯足江水碧，逍遙城中混名德。", "東巖西穴已爛遊，共過廬陽尋簡寂。"]'),
('d5701096-bea3-4b42-8126-a18372d0c50c','仙居閣','沈遼','宋','宋诗','song-poetry','','[]','鶴馭已歸三十春，至今重閣無纖塵。',64,'全唐诗/poet.song.40000.json','["鶴馭已歸三十春，至今重閣無纖塵。", "蟠桃誰知天上事，白骨不駐城中人。", "門外江流似平昔，林間鳥雀空悲辛。", "當時留侯强辟穀，黄石老翁悟終身。"]'),
('867f8a74-0ca6-4f76-aef8-78753307a74f','寄題譚氏需亭','沈遼','宋','宋诗','song-poetry','','[]','譚子作需亭，佳客同宴樂。',216,'全唐诗/poet.song.40000.json','["譚子作需亭，佳客同宴樂。", "宴樂乃餘事，文華相博約。", "散帙列經史，所游盡通博。", "揮毫斷新義，諸生困穿鑿。", "中厨具烹飪，髙懷肆杯杓。", "遙想大論時，紛紛麈毛落。", "春風豁幽鬱，秋日延林薄。", "人生樂名教，安在甘寂寞。", "相期一窮達，豈止爲脾臄。", "窮達乃在天，得時即鳴躍。", "在昔鄭司農，處身固窮索。", "饗客頗豐侈，水陸薦金錯。", "其後李北海，髙材冠臺閣。", "摛文示時彦，萬金資一酌。", "遺風不在是，斯名豈苟作。", "泥沙何足道，正當爲善謔。", "子雲老嗜酒，行當躡芒屫。", "爲君說難字，猶能中一喙。"]'),
('77004eda-117b-43f3-927e-2196b5b6c2e0','望浯臺示無競','沈遼','宋','宋诗','song-poetry','','[]','每愛瀟江西北流，水邊幽石强爲留。',32,'全唐诗/poet.song.40000.json','["每愛瀟江西北流，水邊幽石强爲留。", "歸時欲借浯臺望，何處陂陁可繫舟。"]'),
('913f89b1-8c1b-4f16-9843-a90c2a9c9abb','太平上方','沈遼','宋','宋诗','song-poetry','','[]','山上白雲淡無情，不如山前利與名。',32,'全唐诗/poet.song.40000.json','["山上白雲淡無情，不如山前利與名。", "水西落日何時盡，二十一萬鐘磬鳴。"]'),
('4b0b42b4-2be6-4fcd-829a-35516a217bb3','送唐道士遊南岳','沈遼','宋','宋诗','song-poetry','','[]','瀟湘一片雲，翩翩上南岳。',48,'全唐诗/poet.song.40000.json','["瀟湘一片雲，翩翩上南岳。", "不依澗底石，欲引瑤臺鶴。", "乘風出崕嶠，带月縈林薄。", "若會洪崕生，爲求金鼎藥。"]'),
('b68457a3-54bb-434a-8843-cd820ada0c8b','贈張明之','沈遼','宋','宋诗','song-poetry','','[]','文雅張夫子，飄然東嶺居。',48,'全唐诗/poet.song.40000.json','["文雅張夫子，飄然東嶺居。", "不隨人毁譽，獨與道盈虚。", "歡笑一棋局，湛沈萬卷書。", "三年流竄客，相見止如初。"]'),
('4f7267af-27f8-455f-bc4b-011ea7896e74','唁下第','沈遼','宋','宋诗','song-poetry','','[]','時去亦可惜，浩然若滄溟。',48,'全唐诗/poet.song.40000.json','["時去亦可惜，浩然若滄溟。", "平生窮古學，老大困新經。", "君抱松竹操，余無龜筮靈。", "相看故眼在，惟有遙山青。"]'),
('f1fd68c0-5e8d-49e6-81be-650244afce6a','朱趙二使者示問','沈遼','宋','宋诗','song-poetry','','[]','古木巃嵸山徑斜，不知使者出山窊。',32,'全唐诗/poet.song.40000.json','["古木巃嵸山徑斜，不知使者出山窊。", "羈禽野獸遙相避，亦有人尋顔闔家。"]'),
('85d80b93-04a9-4ee1-a45a-4d2af7a33b63','零陵觀大水','沈遼','宋','宋诗','song-poetry','','[]','春雨淫不已，江水一夕漲。',144,'全唐诗/poet.song.40000.json','["春雨淫不已，江水一夕漲。", "初聞漸其柵，離明已三丈。", "老弱走山去，浮沉困丁壯。", "髙樓半欲沒，木杪維舟舫。", "睢阜已懷襄，那能辨閭巷。", "升髙瞰其下，犬牙縈疊嶂。", "始知地形隘，何由保無恙。", "湘川浩東下，其勢不相讓。", "安得驅山澤，移徙就空曠。", "市井安且平，黎民獲生養。", "羣流亦適性，千里肆夷漾。", "斯懷知未遂，蓬茆獨怊悵。"]'),
('e706980b-3607-44e5-8794-628e296a09e1','謝履道天麻','沈遼','宋','宋诗','song-poetry','','[]','仙客餌赤箭，其根乃天麻。',96,'全唐诗/poet.song.40000.json','["仙客餌赤箭，其根乃天麻。", "延年不復老，飛身混烟霞。", "文升蚤得道，山下多靈芽。", "世士所購求，金玉如泥沙。", "吾昔負羸疾，衰齡畏風邪。", "筋骨困連卷，跳偏竟何嗟。", "履道知我欲，囊封寄山家。", "呼奴爲煮食，惜已鬢毛華。"]'),
('d8bf25f1-767c-473f-996b-ede05d0401dd','奉簡莘叟','沈遼','宋','宋诗','song-poetry','','[]','紅葉飄蕭秋後山，相望止在一嵠間。',64,'全唐诗/poet.song.40000.json','["紅葉飄蕭秋後山，相望止在一嵠間。", "老夫無用方安命，夫子何爲蚤閉關。", "世事不隨歌吹樂，此身略與水雲閑。", "經年不見寧相外，安在區區事往還。"]'),
('04cc539a-f709-42a2-ad7d-08c0c7209dfb','次韻博古贈王道人','沈遼','宋','宋诗','song-poetry','','[]','調笑同方朔，機微似幸靈。',48,'全唐诗/poet.song.40000.json','["調笑同方朔，機微似幸靈。", "囊中萬金藥，機上九仙經。", "虛靜孤猿噪，支離病鶴形。", "子雲稱隱德，於此識沉冥。"]'),
('ed5eb5ce-6542-4b79-bc8c-e82344707873','戯贈莘叟明之','沈遼','宋','宋诗','song-poetry','','[]','仲子絕不出，留侯數相顧。',48,'全唐诗/poet.song.40000.json','["仲子絕不出，留侯數相顧。", "二客雖不同，所知均一趣。", "仲子屏世故，翛然掩蓬戶。", "留侯喜奕棋，清歡寄玄悟。"]'),
('61f19233-a4da-46d4-8c62-329de20dbb05','奉贈王道人','沈遼','宋','宋诗','song-poetry','','[]','身世飄搖如斷雲，此生不復世間塵。',32,'全唐诗/poet.song.40000.json','["身世飄搖如斷雲，此生不復世間塵。", "能言得喪歸諸命，維有東坡王道人。"]'),
('d16561b6-c7d7-4dca-8fc9-093fdfb3967e','平生','沈遼','宋','宋诗','song-poetry','','[]','平生愛閑今幸閑，投老愛山今住山。',32,'全唐诗/poet.song.40000.json','["平生愛閑今幸閑，投老愛山今住山。", "不復區區同眩事，正當渺渺出人間。"]'),
('d2925dbf-9960-43d2-9908-9128fa28418d','將行泊瀟江','沈遼','宋','宋诗','song-poetry','','[]','憫憫久同巢幕燕，翩翩今作北歸鴻。',32,'全唐诗/poet.song.40000.json','["憫憫久同巢幕燕，翩翩今作北歸鴻。", "湘山瀟水愁無度，更泊孤舟夜雨中。"]'),
('6ee3f842-fdb8-4c57-8ec9-b0dcdc1530f3','宿浯溪','沈遼','宋','宋诗','song-poetry','','[]','孤蓬衝雨出湘西，欲向崕間寄一棲。',32,'全唐诗/poet.song.40000.json','["孤蓬衝雨出湘西，欲向崕間寄一棲。", "天外月華如有意，故來相伴宿浯谿。"]'),
('86444476-d26e-446b-adf1-48b265cb9d89','謝蔚宗木棉','沈遼','宋','宋诗','song-poetry','','[]','嶠南地熟氣如烟，木華蒙茸散爲綿。',64,'全唐诗/poet.song.40000.json','["嶠南地熟氣如烟，木華蒙茸散爲綿。", "使君作紬遠相寄，表似夷錦紅欲燃。", "病士榻上殘青氊，山中苦寒多破穿。", "使君相贈何可言，困來不妨伸脚眠。"]'),
('b98bab72-dff1-4134-af3b-41c573976a1c','嬋娟亭','沈遼','宋','宋诗','song-poetry','','[]','天邊新月一絃生，堂上美人肢體輕。',32,'全唐诗/poet.song.40000.json','["天邊新月一絃生，堂上美人肢體輕。", "何似君家庭下竹，孤風髙節照人清。"]'),
('d15b724c-d320-4052-a603-b23f46a4b5ea','静照庵','沈遼','宋','宋诗','song-poetry','','[]','擾擾百年何可爲，正應静處得忘機。',32,'全唐诗/poet.song.40000.json','["擾擾百年何可爲，正應静處得忘機。", "心猿不動無餘境，照見人間是與非。"]'),
('3e6e1cc8-0c7c-4b6c-82f4-0a8c06658a99','石燕坡','沈遼','宋','宋诗','song-poetry','','[]','祁陽縣南石燕坡，驟雨乾時燕子多。',32,'全唐诗/poet.song.40000.json','["祁陽縣南石燕坡，驟雨乾時燕子多。", "行李蕭疏常畏雨，誰能駐馬待滂沱。"]'),
('021fc881-705b-44bd-8417-c827695453ed','峽山寺','沈遼','宋','宋诗','song-poetry','','[]','峽山山下古招提，叢木猶藏半泐碑。',32,'全唐诗/poet.song.40000.json','["峽山山下古招提，叢木猶藏半泐碑。", "正自會昌多難後，至今龍象繞山悲。"]'),
('7c338128-aba9-4bb3-9228-9370ec3cda1f','白水','沈遼','宋','宋诗','song-poetry','','[]','九江水色白如雪，流水瀟湘尚未渾。',32,'全唐诗/poet.song.40000.json','["九江水色白如雪，流水瀟湘尚未渾。", "落日墟頭人已散，獨留烟樹送黄昏。"]'),
('1eb7e70e-b7fa-47d3-9eaf-6925b310ed02','題文殊寺  其一','沈遼','宋','宋诗','song-poetry','','[]','二公誅茆今幾年，至今山下一爐烟。',32,'全唐诗/poet.song.40000.json','["二公誅茆今幾年，至今山下一爐烟。", "駐舟薄致伊蒲饌，欲結諸公寂静緣。"]'),
('5b3d4035-da91-4b93-a2f2-512df43d9f91','題文殊寺  其二','沈遼','宋','宋诗','song-poetry','','[]','月落山時魚鼓鳴，華堂不動夜來燈。',32,'全唐诗/poet.song.40000.json','["月落山時魚鼓鳴，華堂不動夜來燈。", "人間擾擾方多事，誰似爐間白髪僧。"]'),
('5fecef56-a080-4f6e-b4b3-8b4058576a11','雪後','沈遼','宋','宋诗','song-poetry','','[]','朝來風雪滿湘山，頓失羣峰上下間。',32,'全唐诗/poet.song.40000.json','["朝來風雪滿湘山，頓失羣峰上下間。", "風定雪休歸舫穩，江流不動碧潺潺。"]'),
('007eca0a-beab-46fd-be25-4090480d4134','南臺禪師云得蔚宗書報老夫入山','沈遼','宋','宋诗','song-poetry','','[]','支持病骨上南臺，一眺雲林眼暫開。',32,'全唐诗/poet.song.40000.json','["支持病骨上南臺，一眺雲林眼暫開。", "不道雲長更繞舌，已將名姓入山來。"]'),
('d910a972-e411-491b-aaa3-ca45a9731bbc','君山','沈遼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我來洞庭上，延首望君山。',48,'全唐诗/poet.song.40000.json','["我來洞庭上，延首望君山。", "君山不可見，止在狂波間。", "風休水亦息，烟嵐露空碧。", "何煩問法意，開口成塵迹。"]'),
('948a36b8-50dd-4067-92bb-554bea38d105','洞庭山雪','沈遼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭春雪曉霏霏，一陣風來半已晞。',32,'全唐诗/poet.song.40000.json','["洞庭春雪曉霏霏，一陣風來半已晞。", "唯有山陰吹不盡，田塍片段衲僧衣。"]'),
('be553855-7a72-4a13-aecb-adb6e409d50e','次韻奉贈巴陵上官令','沈遼','宋','宋诗','song-poetry','','[]','古人善治身，擺落在塵土。',120,'全唐诗/poet.song.40000.json','["古人善治身，擺落在塵土。", "明哲所自任，不爲小人侮。", "嗟我一何愚，逍遙寄天宇。", "長嫌柳下汙，有意莊生堵。", "微官被黯黮，遠放瀟湘浦。", "閉關絕世故，况復揮談麈。", "蒙恩許北下，始接諸公武。", "若得一丸藥，頓發三年瞽。", "巴陵遇言游，髙文璨瑤圃。", "泠泠挹清風，使人懷玉斧。"]'),
('1a1861f8-82e3-4632-83d2-8dd70088dc29','奉贈上官令','沈遼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭春水静，楚山氣雄勁。',48,'全唐诗/poet.song.40000.json','["洞庭春水静，楚山氣雄勁。", "欲言世上清，不敵巴陵令。", "山深多猿嘯，水涸縱鱗泳。", "牛刀有餘閑，盡入安仁詠。"]'),
('1e31e492-bbed-420e-ace0-58327c5f7c47','重示','沈遼','宋','宋诗','song-poetry','','[]','不識南宗與北宗，欲齊得喪已非通。',64,'全唐诗/poet.song.40000.json','["不識南宗與北宗，欲齊得喪已非通。", "若將直指生爲夢，便可偏知色是空。", "莫爲嚴周馳誕說，欲輕摩詰作衰翁。", "古人言句真芻狗，天外秋來有信鴻。"]'),
('937c4f53-da8d-4dc0-9322-1fd43d0674e9','代諸生送黄鎮判官','沈遼','宋','宋诗','song-poetry','','[]','瀟湘秋水漲山阿，小駐歸舟綠玉波。',64,'全唐诗/poet.song.40000.json','["瀟湘秋水漲山阿，小駐歸舟綠玉波。", "翰苑主人青眼在，湘南使者薦書多。", "庭中紫詔迎綸綍，道上黄花醉叵羅。", "賤客十年京國夢，恨無羽翼從鳴珂。"]'),
('16eade34-40f3-4066-8204-6e17a116efbc','贈送盧總赴調','沈遼','宋','宋诗','song-poetry','','[]','山東盧翁舊儒者，少年久客都城下。',368,'全唐诗/poet.song.40000.json','["山東盧翁舊儒者，少年久客都城下。", "先朝數因春官薦，投袂攀鞍學弓馬。", "大黄六鈞猿臂挽，武庫官箭長分靶。", "横門較藝在第一，武士賈勇來相迓。", "天子臨觀虎豹羣，弓滿不苦何由化。", "固知窮達不在我，乞得參軍何足吒。", "晚除一尉來荆域，白髪婆娑誰復識。", "部中夷落寄戎政，上下六年無盜賊。", "使者垂庥太守惜，地薄器寒無勢力。", "平生介直恥自媒，一紙薦書終不得。", "中間安南大將出，嘗願奮身借一戟。", "翻蒙羽檄督軍糧，靈渠首運三千石。", "小官繇使當自効，解衣操舟上灘磧。", "同行嘲笑何自苦，殊勝陶公閑運甓。", "功勞涓埃何足道，甫得臨湘升斗食。", "髙堂老母終天年，屏居古寺甘窮寂。", "從來畏慎不干人，糲食布衣殘喘息。", "春秋祀事亦粗給，妻子不爲饑寒逼。", "三年終喪壯心在，矍鑠安能忌吏役。", "古劍不折終不埋，老馬豈甘長伏櫪。", "却持手板謁公府，斗擻青衫塵土迹。", "我知盧公意可憐，世人□家輕相測。", "何如市井輕薄兒，朝來指白暮爲黑。"]'),
('0a38f609-226d-4d51-b995-ea54283c63c2','古興十六首  其一','沈遼','宋','宋诗','song-poetry','','[]','朝亦看踰山，暮亦看踰山。',48,'全唐诗/poet.song.40000.json','["朝亦看踰山，暮亦看踰山。", "芳華春樹外，古澹白雲閑。", "絕頂有池水，昔年棲玉顔。", "妙靈想不駐，緬慕何由攀。"]'),
('e50bb614-5e80-44ca-b979-0ba688c1e3a1','古興十六首  其二','沈遼','宋','宋诗','song-poetry','','[]','春草日已枯，山中少人迹。',48,'全唐诗/poet.song.40000.json','["春草日已枯，山中少人迹。", "草間秋蛩鳴，遙知歲寒逼。", "人生何可恃，金丹須努力。", "流景終不回，永歎尚何益。"]'),
('cb354a03-9c5c-475d-8f0e-79093150e110','古興十六首  其三','沈遼','宋','宋诗','song-poetry','','[]','我不歎白髪，安得新少年。',48,'全唐诗/poet.song.40000.json','["我不歎白髪，安得新少年。", "往者不失勢，後來豈能賢。", "世間亦多士，倚伏良有緣。", "寄語夸奪子，古人已皆然。"]'),
('5eb99414-21ce-49f4-a70d-59f5ec16cf58','古興十六首  其四','沈遼','宋','宋诗','song-poetry','','[]','修道須陰功，留侯亦何爲。',48,'全唐诗/poet.song.40000.json','["修道須陰功，留侯亦何爲。", "區區欲報怨，方爲帝王師。", "辟穀學赤松，强爲女子飴。", "黄石更殉葬，空令後人疑。"]'),
('e580d96d-1d59-40ca-b0d7-6a19833fc1b0','古興十六首  其五','沈遼','宋','宋诗','song-poetry','','[]','皖皖何氏女，不食終不饑。',48,'全唐诗/poet.song.40000.json','["皖皖何氏女，不食終不饑。", "普公南遷日，金鏡識仙衣。", "清冷少言語，時時露天機。", "冥數有時盡，玉棺有餘輝。"]'),
('6cb745ec-3aa2-4d03-98ae-e3b37d262e2b','古興十六首  其六','沈遼','宋','宋诗','song-poetry','','[]','古人喜功名，冒死立奇節。',48,'全唐诗/poet.song.40000.json','["古人喜功名，冒死立奇節。", "嗟我亦何弱，翰墨老蒙拙。", "富貴難苟求，恥隨世汩沒。", "千年柏庭下，不負金光骨。"]'),
('56728945-8781-4fd0-8e50-66d539e55d29','古興十六首  其七','沈遼','宋','宋诗','song-poetry','','[]','不識揚子雲，清峭想玄鶴。',48,'全唐诗/poet.song.40000.json','["不識揚子雲，清峭想玄鶴。", "後世欲論文，斯人不可作。", "死生固有命，一眚爲投閣。", "相去已千年，空山甘寂寞。"]'),
('2dff32b7-0d62-4e1e-896b-a6038b2c84d1','古興十六首  其八','沈遼','宋','宋诗','song-poetry','','[]','黄葉日已落，西飇易驚衰。',48,'全唐诗/poet.song.40000.json','["黄葉日已落，西飇易驚衰。", "憶昔陽春下，芳華弄葳蕤。", "四序不代運，生物皆凌夷。", "匆匆蓋常理，晚暮令人悲。"]'),
('fd0f1c17-4a78-42b5-8501-aa4445136f72','古興十六首  其九','沈遼','宋','宋诗','song-poetry','','[]','百草皆有種，風土不可移。',72,'全唐诗/poet.song.40000.json','["百草皆有種，風土不可移。", "甘辛與美惡，所得自適宜。", "東家鮐背翁，前日迺嬰兒。", "耄倪寄百年，誰可强扶持。", "芳華有不實，不實未足悲。", "神仙不死藥，多採南山芝。"]'),
('6187e385-5ecd-47a8-ab30-051a30348ee4','古興十六首  其一○','沈遼','宋','宋诗','song-poetry','','[]','天外青青山，重雲忽蒙翳。',48,'全唐诗/poet.song.40000.json','["天外青青山，重雲忽蒙翳。", "青山終不移，明目未可睨。", "秋風方憀慄，冥雨何時霽。", "不見希夷翁，欲學窮年睡。"]'),
('1e3e5a85-bea2-422c-8fcf-6f0ec0b33ac1','古興十六首  其一一','沈遼','宋','宋诗','song-poetry','','[]','夜半山氣冷，始知秋序深。',96,'全唐诗/poet.song.40000.json','["夜半山氣冷，始知秋序深。", "開軒望明月，西嶺莽涔涔。", "人籟久已息，繁然蟪蛄吟。", "緬懷故丘鶴，清唳有餘音。", "遙與白雲期，豈憚冰雪侵。", "人情與物象，邂逅愜幽心。", "夜漏漸已長，清風入松林。", "逍遙掩蓬戶，微涼生衣襟。"]'),
('51ff1692-0136-4c85-8364-ebdf717b7a78','古興十六首  其一二','沈遼','宋','宋诗','song-poetry','','[]','瀟湘望秋月，清曠無風埃。',48,'全唐诗/poet.song.40000.json','["瀟湘望秋月，清曠無風埃。", "誰知故園影，亦向裔夷來。", "水際衰老翁，練衣獨徘徊。", "頫仰方自適，爲誰指玄胎。"]'),
('45b58395-5ce9-4af0-aa27-0e80dd991b5d','古興十六首  其一三','沈遼','宋','宋诗','song-poetry','','[]','落葉何足歎，歳暮皆枯枝。',48,'全唐诗/poet.song.40000.json','["落葉何足歎，歳暮皆枯枝。", "白髪不可摘，我老誰不知。", "榮瘁乃常理，日月濳推移。", "莊生强欲下，祗能解人頤。"]'),
('cc9175b6-52f4-4c46-81f4-286c80ce477c','古興十六首  其一四','沈遼','宋','宋诗','song-poetry','','[]','我意不自適，何爲浪多憂。',48,'全唐诗/poet.song.40000.json','["我意不自適，何爲浪多憂。", "艸舍亦無事，浩如水中舟。", "陵谷尚或遷，百年爲誰侜。", "不作亦不止，生肇知吾優。"]'),
('4a19c286-1bfe-4d62-a222-5c5e01ac1de3','古興十六首  其一五','沈遼','宋','宋诗','song-poetry','','[]','前日春已歸，殘花尚赤白。',72,'全唐诗/poet.song.40000.json','["前日春已歸，殘花尚赤白。", "秋來初未頃，園林亦早索。", "桃實久已空，黄柑年可摘。", "唯有半折松，青青獨如昔。", "少年勿歎息，明年復春色。", "莫疑衰老翁，住世方爲客。"]'),
('5f82705e-096e-45e6-9b8e-4651af80ed52','古興十六首  其一六','沈遼','宋','宋诗','song-poetry','','[]','疇昔一夢還，强憂亦强喜。',48,'全唐诗/poet.song.40000.json','["疇昔一夢還，强憂亦强喜。", "殘息若少延，視今諒亦爾。", "何爲有得失，寧非爲物使。", "長哂王濳夫，區區論天咫。"]'),
('093e9ee3-f3ad-4cb0-b580-2b97e4d84a5e','渡西','沈遼','宋','宋诗','song-poetry','','[]','百家渡西日已落，青山上下猿鳥樂。',64,'全唐诗/poet.song.40000.json','["百家渡西日已落，青山上下猿鳥樂。", "欲因新月望吳雲，遙看北斗掛南岳。", "一夢愔愔已十秋，古人不死終未休。", "草舍蕭條誰與語，清香吹過白蘋洲。"]'),
('add56788-b3bd-421a-ad41-bcb782c56025','次韻酬楚興三頌  其一','沈遼','宋','宋诗','song-poetry','','[]','莫欺隱几維摩老，不爲文殊不設齋。',32,'全唐诗/poet.song.40000.json','["莫欺隱几維摩老，不爲文殊不設齋。", "寂寂青山何所有，霜風落葉滿空堦。"]'),
('ed7c8fad-c8a7-4505-a33a-d96bfeef08df','次韻酬楚興三頌  其二','沈遼','宋','宋诗','song-poetry','','[]','給孤長者尋常有，應供如來不易逢。',32,'全唐诗/poet.song.40000.json','["給孤長者尋常有，應供如來不易逢。", "二施本無差别理，莫論庭柏與庭松。"]'),
('6c320875-eacb-4b99-a3ec-5de60bd40c4c','次韻酬楚興三頌  其三','沈遼','宋','宋诗','song-poetry','','[]','已住世間如影響，不牽法相論偏圓。',32,'全唐诗/poet.song.40000.json','["已住世間如影響，不牽法相論偏圓。", "山邊茆屋隨緣業，不是當時忍辱仙。"]'),
('6c7aed6f-1a71-4596-be0a-43fdaf241b16','寄金山禪師','沈遼','宋','宋诗','song-poetry','','[]','秋來清血灑瀟湘，遙望東流带夕陽。',32,'全唐诗/poet.song.40000.json','["秋來清血灑瀟湘，遙望東流带夕陽。", "爲過金山沾法力，便隨潮水入錢塘。"]'),
('a8dc1d5c-9185-44a9-9010-105e99076653','九日','沈遼','宋','宋诗','song-poetry','','[]','去年九日始離家，行到江南見菊花。',32,'全唐诗/poet.song.40000.json','["去年九日始離家，行到江南見菊花。", "今日裔夷逢節物，獨將白髪換年華。"]'),
('457135fa-35bf-49fb-9454-ca7ce98bc876','送畢公綽','沈遼','宋','宋诗','song-poetry','','[]','畢子治車馬，游學去成均。',96,'全唐诗/poet.song.40000.json','["畢子治車馬，游學去成均。", "成均首善地，俊乂方軿臻。", "爲儒當讀書，術業藏諸身。", "羣居久昧是，終亦爲塗人。", "通塞雖有時，操修貴道真。", "求益當擇友，好德必有鄰。", "吾爲投裔客，其言何足珍。", "行矣當自慎，思慰髙堂親。"]'),
('8a997b1d-9382-46ca-a600-c11668275680','火星巖','沈遼','宋','宋诗','song-poetry','','[]','火星巖下石崚嶒，殿閣相望止一僧。',32,'全唐诗/poet.song.40000.json','["火星巖下石崚嶒，殿閣相望止一僧。", "莫問人間興廢事，門前流水几前燈。"]'),
('bdc7f52e-89f7-4756-89ac-b01439de1e1f','白髪','沈遼','宋','宋诗','song-poetry','','[]','山頭甘實半已黄，領上白髪日更長。',64,'全唐诗/poet.song.40000.json','["山頭甘實半已黄，領上白髪日更長。", "青雲合散寄孤岫，世事悲歡空夕陽。", "我欲乘風學御寇，泠然有意尋滄浪。", "滄浪無人誰與適，青山路遠烟茫茫。"]');
